const pendingActions = new Set();
function actionKey(action, id) { return `${action}:${id || "global"}`; }
function setGlobalLoading(active, message = "Processando...") {
  let el = document.getElementById('globalLoadingOverlay');
  if (!el) {
    el = document.createElement('div');
    el.id = 'globalLoadingOverlay';
    el.className = 'global-loading-overlay';
    el.setAttribute('role','status');
    el.innerHTML = `<div class="global-loading-card"><div class="spinner" aria-hidden="true"></div><strong data-loading-title>Aguarde</strong><p data-loading-message>Estamos processando sua requisição...</p></div>`;
    document.body.appendChild(el);
  }
  const msg = el.querySelector('[data-loading-message]');
  if (msg) msg.textContent = message || 'Aguarde, estamos processando sua requisição...';
  el.classList.toggle('is-active', !!active);
  el.setAttribute('aria-hidden', active ? 'false' : 'true');
}
function setButtonLoading(button, active, label) {
  if (!button) return;
  if (active) {
    if (!button.dataset.originalLabel) button.dataset.originalLabel = button.innerHTML;
    button.disabled = true;
    button.setAttribute('aria-busy','true');
    button.innerHTML = `<span class="spinner spinner-inline" aria-hidden="true"></span> ${esc(label || 'Processando...')}`;
  } else {
    button.disabled = false;
    button.removeAttribute('aria-busy');
    if (button.dataset.originalLabel) button.innerHTML = button.dataset.originalLabel;
    delete button.dataset.originalLabel;
  }
}
async function withLoading(label, fn, options = {}) {
  const key = actionKey(options.action || label, options.id);
  if (pendingActions.has(key)) { toast?.('Ação já em andamento.','warn'); return options.duplicateValue; }
  pendingActions.add(key);
  setButtonLoading(options.button, true, options.buttonText || options.buttonLabel || label);
  setGlobalLoading(true, label || 'Processando...');
  try { return await fn(); }
  catch (error) { toast?.(sanitizePublicError?.(error) || error?.message || 'Não foi possível concluir a ação.','error'); throw error; }
  finally { setButtonLoading(options.button, false); pendingActions.delete(key); setGlobalLoading(false); }
}
window.ValoraLoading={setGlobalLoading,withLoading,setButtonLoading,pendingActions,actionKey};

