function getLimitStatus(companyId){const c=companyById(companyId),limits=getEffectiveCompanyLimits(c),usage=getCompanyUsage(companyId),map={maxActiveSurveys:'activeSurveys',maxResponsesMonth:'responsesMonth',maxManagers:'managers',maxEmployees:'employees',maxEmailsMonth:'emailsMonth'};return Object.entries(limits).map(([k,limit])=>{const used=Number(usage[map[k]]||0),pct=limit<0?0:Math.round(used/Math.max(1,limit)*100);return {key:k,used,limit,percent:pct,status:limit>=0&&used>=limit?'excedido':limit>0&&used/limit>=.8?'atenção':'ok'};});}
function canCreateSurveyBySubscription(company){return ['trial','active','overdue'].includes(getSubscriptionStatus(company));}
function canSendInvitesBySubscription(company){return ['trial','active'].includes(getSubscriptionStatus(company));}
function canUseReportsBySubscription(company){return ['trial','active','overdue','suspended'].includes(getSubscriptionStatus(company));}
function canUseWhiteLabel(company){return ['trial','active'].includes(getSubscriptionStatus(company));}

