function assertSurveyShareableInProduction(survey){const form=formById(survey?.formId);const company=companyById(survey?.companyId||survey?.organizationId);const status=String(survey?.status||'').toLowerCase();if(!survey||isBlockedInProduction(survey)||isBlockedInProduction(form)||isBlockedInProduction(company)||survey?.deleted||survey?.archived||survey?.revoked||survey?.removed||['archived','deleted','removed'].includes(status)||!['active','published','open'].includes(status)||!form||form.id!==survey.formId){throw Object.assign(new Error(productionDemoShareMessage()),{code:'demo_survey_blocked'});}return {form,company};}
