let actions={};
let formHandlers={};
let globalHandlersRegistered=false;
function safeAction(name,handler){
  if(typeof handler==='function')return handler;
  return function missingActionHandler(){
    console.error(`[Valora Pulse] Action handler ausente: ${name}`);
    toast(`Ação indisponível: ${name}`,'error');
    return false;
  };
}
function getFunctionIfDefined(name){
  try{
    const root=typeof globalThis!=='undefined'?globalThis:(typeof window!=='undefined'?window:{});
    const fn=root?.[name]||window?.[name];
    return typeof fn==='function'?fn:null;
  }catch(_){return null;}
}
function missingAction(actionName){
  console.warn(`[Valora Pulse] Ação não registrada: ${actionName}`);
  toast('Esta ação ainda não está disponível neste ambiente.','warn');
}
function missingFormHandler(formName){
  console.warn(`[Valora Pulse] Formulário não registrado: ${formName}`);
  toast('Este formulário ainda não está disponível.','warn');
}
function handleDocumentClick(e){
  const el=e.target.closest('[data-action]'); if(!el)return;
  const actionName=el.dataset.action;
  const action=actions[actionName];
  e.preventDefault();
  if(typeof action!=='function')return missingAction(actionName);
  return run(`a ação “${actionName}”`,action,el,e);
}
function handleDocumentChange(e){
  const el=e.target.closest('[data-change]');if(!el)return;
  const change=changes[el.dataset.change];if(change)run(`a alteração “${el.dataset.change}”`,change,el,e);
}
function handleDocumentInput(e){
  const el=e.target.closest('[data-input]');if(!el)return;
  const change=inputs[el.dataset.input];if(change)run(`a edição “${el.dataset.input}”`,change,el,e);
}
function handleDocumentSubmit(e){
  const form=e.target.closest('form[data-form]');if(!form)return;
  e.preventDefault();
  const formName=form.dataset.form;
  const handler=formHandlers[formName];
  if(typeof handler!=='function')return missingFormHandler(formName);
  return run(`o envio de “${formName}”`,handler,form,e);
}
function handleDocumentKeydown(e){
  if(e.key==='Escape'){
    if($('#confirmLayer')?.classList.contains('open'))closeConfirm();
    else if($('#modalLayer')?.classList.contains('open'))closeModal();
    else toggleBot(false);
  }
}
function registerGlobalHandlers(){
  if(globalHandlersRegistered)return;
  document.addEventListener('click',handleDocumentClick);
  document.addEventListener('change',handleDocumentChange);
  document.addEventListener('input',handleDocumentInput);
  document.addEventListener('submit',handleDocumentSubmit);
  document.addEventListener('keydown',handleDocumentKeydown);
  globalHandlersRegistered=true;
}
function bootstrapApp(){
  try{
    actions=createActions();
    formHandlers=createFormHandlers();
    registerGlobalHandlers();
    run('a inicialização',init);
  }catch(error){
    recordPublicBootError(error,'bootstrapApp');
    releasePublicUi('bootstrap_error');
    if(isPublicRoute(currentRoute,routeParamsFromLocation())||!currentUserSafe()){
      try{renderHomeFallback();}catch(_){renderHome();}
      return;
    }
    renderFatalAdminError(error);
  }
}
function renderHomeFallback(){return renderHome();}
function renderFatalAdminError(error){const app=$('#app');if(app)app.innerHTML=`<section class="empty-state error-state"><h3>Não foi possível iniciar a área administrativa</h3><p>${esc(error?.message||'Falha de inicialização')}</p><button class="btn btn-secondary" data-action="reloadApp">Atualizar</button></section>`;}

function legacyTraceEnabled(){return window.ValoraConfig?.observability?.legacyTraceEnabled===true;}
function safeRun(label,category,action,fn,options={}){
  try{
    if(legacyTraceEnabled())window.ValoraLogger?.debug({category,action,message:`Iniciando: ${label}`,metadata:options.metadata,user:currentUser?.()});
    const result=fn();
    if(legacyTraceEnabled())window.ValoraLogger?.info({category,action,message:`Concluído: ${label}`,metadata:options.metadata,user:currentUser?.()});
    return result;
  }catch(err){
    window.ValoraLogger?.error({category,action,message:`Erro em: ${label}`,error:err,metadata:options.metadata,user:currentUser?.()});
    handleError(label,err);
    return options.fallback;
  }
}
async function safeRunAsync(label,category,action,fn,options={}){
  try{
    if(legacyTraceEnabled())window.ValoraLogger?.debug({category,action,message:`Iniciando: ${label}`,metadata:options.metadata,user:currentUser?.()});
    const result=await fn();
    if(legacyTraceEnabled())window.ValoraLogger?.info({category,action,message:`Concluído: ${label}`,metadata:options.metadata,user:currentUser?.()});
    return result;
  }catch(err){
    window.ValoraLogger?.error({category,action,message:`Erro em: ${label}`,error:err,metadata:options.metadata,user:currentUser?.()});
    handleError(label,err);
    return options.fallback;
  }
}
function run(label,fn,...args){return safeRun(label,'system','legacy_run',()=>{const result=fn(...args);if(result&&typeof result.then==='function') result.catch(err=>handleError(label,err));return result;});}
let isHandlingError=false;let isSavingAudit=false;
function callableBusinessCode(err){return String(err?.details?.code||err?.code||err?.rawCode||'').replace(/^functions\//,'');}
function handleError(label,err){
  const businessCode=callableBusinessCode(err);
  if(businessCode==='form_linked_to_active_surveys'){const details=err?.details||{};if(details.formId||details.id)return openLinkedFormSurveysModal(details.formId||details.id,details);return;}
  if(isHandlingError){console.warn('[Valora Pulse] erro suprimido para evitar loop',label,err?.message||err);return;}
  isHandlingError=true;setTimeout(()=>{isHandlingError=false;},1000);
  if(window.ValoraConfig?.observability?.consoleEnabled===true)console.error(`[Valora Pulse] ${label}`,err);
  try{window.ValoraLogger?.error({category:'system',action:'frontend_error',message:`Não foi possível concluir ${label}.`,error:err,route:currentRoute,user:currentUser?.()});}catch(_){ }
  if(label==='a inicialização')renderFatalStartupError(err);
  toast(`Não foi possível concluir ${label}. ${err?.message||err}`,'error');
  try{window.ValoraLogs?.logServerEvent?.({level:'error',category:'system',action:'frontend_error_handled',message:String(label),metadata:{error:String(err?.message||err)}});}catch(_){ }
}
function renderFatalStartupError(error){
  const app=document.getElementById('app');
  if(!app)return;
  const isLocalMode=['localhost','127.0.0.1',''].includes(location.hostname)||APP_CONFIG.STORAGE_MODE==='local';
  const resetButton=isLocalMode?'<button class="btn btn-secondary" id="startupResetBtn" type="button">Recriar base local</button>':'';
  app.innerHTML=`<section class="section"><div class="container"><div class="card startup-error"><span class="badge danger">Falha na inicialização</span><h1>Não foi possível carregar o Valora Pulse™</h1><p>Atualize a página. Se o problema continuar, contate o suporte.</p><div class="confirm-actions"><button class="btn btn-primary" id="startupRetryBtn" type="button">Tentar novamente</button>${resetButton}</div>${isLocalMode?'<pre class="debug-box"></pre>':''}</div></div></section>`;
  const debug=app.querySelector('.debug-box');
  if(debug)debug.textContent=error?.stack||error?.message||String(error);
  app.querySelector('#startupRetryBtn')?.addEventListener('click',()=>location.reload());
  app.querySelector('#startupResetBtn')?.addEventListener('click',()=>{try{localStorage.removeItem(STORE_KEY);}catch(_){ } location.reload();});
}

window.addEventListener('error',function(e){if(isExternalBrowserNoise(e.error||e.message||e)){recordExternalBrowserNoise(e.error||e.message||e);e.preventDefault();return false;}const err=e.error||new Error(e.message);window.ValoraLogger?.critical({category:'system',action:'global_error',message:'Erro global capturado.',error:err,route:currentRoute,user:currentUser?.()});if(!currentUserSafe()||isPublicRoute(currentRoute,routeParamsFromLocation())){recordPublicBootError(err,'window.error');releasePublicUi('window.error');return;}handleError('a operação',err);});
window.addEventListener('unhandledrejection',function(e){const reason=e.reason||{};if(isExternalBrowserNoise(reason)){recordExternalBrowserNoise(reason);e.preventDefault();return false;}const err=e.reason||new Error('Falha desconhecida');window.ValoraLogger?.critical({category:'system',action:'unhandled_rejection',message:'Promise rejeitada sem tratamento.',error:err,route:currentRoute,user:currentUser?.()});if(!currentUserSafe()||isPublicRoute(currentRoute,routeParamsFromLocation())){recordPublicBootError(err,'window.unhandledrejection');releasePublicUi('window.unhandledrejection');return;}handleError('a operação assíncrona',err);});
document.addEventListener('DOMContentLoaded',bootstrapApp);

async function init(){
  if(!repository)throw new Error('Camada de repositório não carregada.');
  initializeState();
  if(repository.mode==='firebase'&&window.ValoraFirebaseAuth?.waitUntilReady){
    const routeNow=routeFromLocation(),paramsNow=routeParamsFromLocation(),publicNow=isPublicRoute(routeNow,paramsNow);
    const authReadyPromise=window.ValoraFirebaseAuth.waitUntilReady().then(user=>{state.authReady=true;state.user=currentUserSafe();return user;});
    const authTimeout=new Promise(resolve=>setTimeout(()=>{if(publicNow){updateRuntimeDiagnostic('lastPublicAuthTimeout',{route:routeNow,status:'visitor_released'});console.info('[Valora Pulse] Auth ainda carregando; seguindo em modo visitante para rota pública.');releasePublicUi('public_auth_timeout');resolve(null);}else{const app=$('#app');if(app)app.innerHTML='<section class="empty-state"><h3>Carregando sessão segura...</h3><p>Aguarde enquanto validamos seu acesso.</p><div class="confirm-actions"><button class="btn btn-secondary" data-action="reloadApp">Tentar novamente</button><button class="btn btn-soft" data-action="goLogin">Ir para login</button></div></section>';/* no visitor release for admin/private */}},publicNow?5000:15000));
    await (publicNow?Promise.race([authReadyPromise,authTimeout]):authReadyPromise);
    if(publicNow)authReadyPromise.then(()=>{state.user=currentUserSafe();state.isPublicMode=!state.user;}).catch(()=>{});
  }
  state.authReady=true;state.user=currentUserSafe();state.isPublicMode=!state.user;
  if(state.isPublicMode)releasePublicUi('init_public_no_auth');
  window.addEventListener('valora:auth-changed',()=>routeFromLocation());
  renderShell();
  routeFromLocation();
  window.addEventListener('hashchange',routeFromLocation);
  window.addEventListener('popstate',routeFromLocation);
}
function isPublicSurveyPage(){const url=new URL(location.href);return !!url.searchParams.get('survey')&&!!url.searchParams.get('token');}
function isPublicResultPage(){const url=new URL(location.href);return !!url.searchParams.get('result')&&!!url.searchParams.get('rt');}
function isPublicCertificateValidationPage(){const url=new URL(location.href);return !!url.searchParams.get('certificate');}
function isPublicJourneyPage(){return isPublicSurveyPage()||isPublicResultPage()||isPublicCertificateValidationPage();}

function routeFromLocation(){
  const u=new URL(location.href);const hash=(location.hash||'').slice(1);const sid=u.searchParams.get('survey'),token=u.searchParams.get('token'),result=u.searchParams.get('result'),resultToken=u.searchParams.get('rt'),certificate=u.searchParams.get('certificate');
  // Rotas internas sempre têm prioridade. Assim, Minha área, logo, LGPD e Planos
  // continuam funcionando mesmo depois de abrir um link seguro com query string.
  if(hash)return route(hash);
  if(sid){const contract=publicSurveyRouteContract({survey:sid,token,org:u.searchParams.get('org')});if(!contract.ok){return renderIncompletePublicSurveyLink(contract);} resolveProductionPublicSurveyLink({survey:sid,token,org:u.searchParams.get('org')}).then(r=>{ if(!r?.redirected&&!r?.blocked) renderTakeSurvey(sid,token,u.searchParams.get('org')); }).catch(()=>renderTakeSurvey(sid,token,u.searchParams.get('org'))); return; }
  if(result)return renderResult(result,false,resultToken);
  if(certificate)return renderCertificateValidation(certificate);
  route('home');
}

function renderCertificateValidation(validationCode=''){
  renderPublicSurveyShell();
  $('#app').innerHTML=`<section class="section"><div class="container"><div class="card"><span class="badge success">Validar certificado</span><h1>Validar certificado</h1><p>Informe o código público do certificado Valora para consultar a validade sem expor e-mail completo, token ou dados internos.</p><form class="form-grid" data-form="certificateValidation"><div class="field"><label>Código de validação</label><input name="certificate" value="${esc(validationCode)}" required></div><button class="btn btn-primary">Validar certificado</button></form><div class="result-notice" id="certificateValidationResult">Aguardando validação.</div></div></div></section>`;
  if(validationCode)validateCertificatePublic(validationCode);
}
async function validateCertificatePublic(code){
  const box=$('#certificateValidationResult');
  try{
    const base=(APP_CONFIG.API_BASE_URL||'').replace(/\/$/,'');
    if(!base){box.textContent='Validação pública disponível no Valora.Web ou na Valora.Api configurada.';return;}
    const data=await safeFetchJson(`${base}/certificates/validate/${encodeURIComponent(code)}`,{},'validação pública de certificado');
    box.innerHTML=data.valid?`Certificado válido para <b>${esc(data.participantName)}</b> (${esc(data.participantEmailMasked||'e-mail mascarado')}). Pesquisa: ${esc(data.surveyTitle)}. Nível: ${esc(data.maturityLevel)}.`:'Certificado não confirmado.';
  }catch(error){box.textContent='Falha controlada ao validar certificado. Tente novamente.';}
}

function route(path){
  currentRoute=path||'home';renderShell();
  const [viewRaw,tab]=currentRoute.split('/'); const alias={cadastro:'signup',register:'signup',suporte:'public-help',support:'public-help',privacidade:'lgpd',termos:'lgpd'}; const view=alias[viewRaw]||viewRaw;
  if(isPublicRoute(view,routeParamsFromLocation()))releasePublicUi(`route:${view}`);
  if(!isPublicRoute(view,routeParamsFromLocation())&&!currentUser())return renderLogin('Acesso seguro à plataforma Valora Pulse™.');
  if(isGlobalAdmin(currentUser())){}else{
    if(view==='admin'&&getRoleDefinition(currentUser()?.role).scope!=='valora')return renderNoAccess();
    if(view==='empresa'&&!['valora','empresa'].includes(getRoleDefinition(currentUser()?.role).scope))return renderNoAccess();
    if(view==='participante'&&!['participante','externo'].includes(getRoleDefinition(currentUser()?.role).scope))return renderNoAccess();
  }
  const views={home:renderHome,login:renderLogin,signup:renderSignup,lgpd:renderPublicLgpd,'public-help':renderPublicHelp,plans:renderPlans,admin:()=>renderPortal('admin',tab||'dashboard'),empresa:()=>renderPortal('empresa',tab||'dashboard'),participante:()=>renderPortal('participante',tab||'dashboard')};
  renderGuard(view,views[view]||renderHome);setTimeout(()=>{const app=$('#app');if(app){try{app.focus({preventScroll:true});}catch(_){app.focus();window.scrollTo({top:0,behavior:'auto'});}}},0);
}
function navigate(path){closeMobileMenu();const clean=location.href.split('?')[0].split('#')[0];history.pushState({},'',`${clean}#${path}`);route(path);window.scrollTo({top:0,behavior:'auto'});}
function goHome(){closeMobileMenu();
  const clean=location.href.split('?')[0].split('#')[0];history.replaceState({},'',`${clean}#home`);route('home');window.scrollTo({top:0,behavior:'smooth'});
}

