function publicJourneyContext(){const u=new URL(location.href),sid=u.searchParams.get('survey'),rid=u.searchParams.get('result'),orgSlug=u.searchParams.get('org');const s=sid?state.surveys.find(x=>x.id===sid):rid?state.surveys.find(x=>x.id===state.responses.find(r=>r.id===rid)?.surveyId):null;const company=findOrganizationBySlug(orgSlug)||companyById(s?.companyId)||null;return {survey:s,company,companyName:company?.publicName||company?.name||companyName(s?.companyId)||'Valora Group'};}
function isDemoCompany(company){const name=String(company?.name||company?.publicName||'').trim().toLowerCase();const slug=String(company?.slug||'').trim().toLowerCase();return company?.id==='org_demo'||slug==='empresa-exemplo'||name==='empresa exemplo'||name==='empresa demonstração'||name==='empresa demonstracao';}
function shouldShowPublicCompanyChip(company){return !!company&&!isDemoCompany(company);}
function publicCompanyDisplay(company,fallback='Valora Group'){return isDemoCompany(company)?'Pesquisa demonstrativa Valora':(company?.publicName||company?.name||fallback);}
function sanitizePublicUrlForLog(link){try{const u=new URL(link,location.href);u.searchParams.delete('token');return u.toString();}catch(_){return '';}}
function isPublicSurveyUrl(link){try{const u=new URL(link,location.href);return !!(u.searchParams.get('survey')&&u.searchParams.get('token'));}catch(_){return String(link||'').includes('?survey=')&&String(link||'').includes('token=');}}
function publicWhatsappUrl(ctx=publicJourneyContext()){const raw=onlyDigits(ctx.company?.settings?.whatsapp||ctx.company?.phone||state.settings.whatsappNumber);if(!raw)return '';const msg=`Olá! Preciso de ajuda para responder a pesquisa ${ctx.survey?.title||'Valora Pulse'} da ${publicCompanyDisplay(ctx.company,ctx.companyName)}.`;return `https://wa.me/${raw}?text=${encodeURIComponent(msg)}`;}
