function resolveHomeFeaturedSurvey(store=state){
  const st=store||{};
  const settings=st.settings||{};
  const surveys=Array.isArray(st.surveys)?st.surveys:[];
  const reasons=[];
  function isActiveSurvey(survey){
    if(!survey)return false;
    if(String(survey.id||'').toLowerCase()==='survey_demo'){reasons.push({id:survey.id,reason:'survey_demo bloqueado'});return false;}
    if(!['active','published','open'].includes(String(survey.status||'').toLowerCase())){reasons.push({id:survey.id,reason:`status inválido: ${survey.status||'vazio'}`});return false;}
    const visibility=String(survey.visibility||survey.publicVisibility||'public').toLowerCase();
    if(!['public',''].includes(visibility)){reasons.push({id:survey.id,reason:`visibility inválida: ${visibility}`});return false;}
    if(survey.revoked===true||survey.revokedAt){reasons.push({id:survey.id,reason:'pesquisa revogada'});return false;}
    if(survey.visibleOnHome===false){reasons.push({id:survey.id,reason:'visibleOnHome=false'});return false;}
    if(isSurveyExpired(survey)&&!isFreeOfficialSurvey(survey)){reasons.push({id:survey.id,reason:'pesquisa expirada'});return false;}
    return true;
  }
  function hasPublicAccess(survey){const token=survey?.publicToken||survey?.token||survey?.accessToken||'';return Boolean(token&&token!==String(survey?.tokenHash||'')&&survey?.formId&&survey?.companyId);}
  function isFreeHomeCandidate(s){return (s?.isFree===true||s?.planId==='free')&&isActiveSurvey(s)&&hasPublicAccess(s);}
  const sortRecent=(a,b)=>Date.parse(b.updatedAt||b.createdAt||0)-Date.parse(a.updatedAt||a.createdAt||0);
  const bySettings=surveys.find(s=>s.id===settings.featuredSurveyId&&isFreeHomeCandidate(s));
  if(bySettings)return{survey:bySettings,source:'settings.featuredSurveyId',reasons};
  const byFeatured=surveys.filter(s=>isFreeHomeCandidate(s)&&(s.isFeatured===true||s.featuredOnHome===true||s.homeFeatured===true)).sort(sortRecent)[0];
  if(byFeatured)return{survey:byFeatured,source:'survey.featuredOnHome/isFeatured',reasons};
  const byOfficial=surveys.find(s=>String(s.id||s.surveyId||'')===OFFICIAL_FREE_SURVEY_ID&&isFreeHomeCandidate(s));
  if(byOfficial)return{survey:byOfficial,source:'official_free_survey',reasons};
  const byFree=surveys.filter(s=>isFreeHomeCandidate(s)&&String(s.title||'').toLowerCase().includes('valora insight')).sort(sortRecent)[0];
  if(byFree){ensureSurveyPublicLink(byFree);return{survey:byFree,source:'survey.isFree/Valora Insight',reasons};}
  return{survey:null,source:'',reasons};
}
function buildHomeFeaturedSurveyUrl(survey){
  if(!survey||(isSurveyExpired(survey)&&!isFreeOfficialSurvey(survey)))return '';
  if(survey.publicUrl)return survey.publicUrl;
  if(survey.publicLink)return survey.publicLink;
  const token=survey.publicToken||survey.token||survey.accessToken||'';
  if(!token)return '';
  const company=companyById(survey.companyId)||companyById(survey.organizationId);
  const orgSlug=company?.slug||company?.publicSlug||'';
  const base=window.ValoraConfig?.APP_PUBLIC_URL||location.href.split('?')[0].split('#')[0];
  const url=new URL(base);
  url.searchParams.set('survey',survey.id);
  url.searchParams.set('token',token);
  if(orgSlug)url.searchParams.set('org',orgSlug);
  return url.toString();
}
function ensureSurveyPublicLink(survey){
  if(!survey)return survey;
  if(isSurveyExpired(survey)&&!isFreeOfficialSurvey(survey))return survey;
  if(!survey.publicToken&&!survey.token&&!survey.accessToken)survey.publicToken=secureToken();
  if(survey.tokenHash&&!survey.publicToken&&!survey.token&&!survey.accessToken)survey.publicToken=secureToken();
  if(!survey.publicToken&&survey.token)survey.publicToken=survey.token;
  survey.token=survey.publicToken||survey.token||survey.accessToken;
  const token=survey.publicToken||survey.token||survey.accessToken;
  if(token&&token!==String(survey.tokenHash||''))hashPublicValue(token).then(h=>{survey.tokenHash=h;}).catch(()=>{});
  const company=companyById(survey.companyId)||companyById(survey.organizationId);
  const base=window.ValoraConfig?.APP_PUBLIC_URL||location.href.split('?')[0].split('#')[0];
  const url=new URL(base);
  url.searchParams.set('survey',survey.id);
  url.searchParams.set('token',token);
  if(company?.slug)url.searchParams.set('org',company.slug);
  survey.publicUrl=url.toString();
  survey.publicLink=survey.publicUrl;
  return survey;
}

async function resolveFeaturedHomeSurvey(){
  const remoteResolver=window.ValoraRepository?.loadFeaturedHomeSurvey||window.ValoraRepository?.resolveFeaturedHomeSurvey;
  if(remoteResolver){try{const resolved=await remoteResolver.call(window.ValoraRepository);window.ValoraRuntimeDiagnostics=window.ValoraRuntimeDiagnostics||{};window.ValoraRuntimeDiagnostics.lastFeaturedHomeSurvey=resolved?.diagnostics||{};return resolved?.survey?resolved:{survey:resolved};}catch(error){const details=error?.details||error?.customData?._tokenResponse||{};window.ValoraRuntimeDiagnostics=window.ValoraRuntimeDiagnostics||{};window.ValoraRuntimeDiagnostics.lastFeaturedHomeSurvey=error?.details?.diagnostics||details?.diagnostics||{error:sanitizePublicError(error)};console.warn('[Valora Pulse] Destaque remoto indisponível.',sanitizePublicError(error),window.ValoraRuntimeDiagnostics.lastFeaturedHomeSurvey);}}
  const resolved=resolveHomeFeaturedSurvey(state);
  if(resolved?.survey)return ensureSurveyPublicLink(resolved.survey);
  const official=await loadOfficialFreeSurvey();
  return official?ensureOfficialFreeSurveyPublicLink(official):null;
}
async function getFeaturedHomeSurvey(){try{return await resolveFeaturedHomeSurvey();}catch(error){recordPublicBootError(error,'getFeaturedHomeSurvey');return {ok:false,url:'',errorCode:error?.code||'featured_unavailable',message:sanitizePublicError?.(error)||'Diagnóstico indisponível no momento.',diagnostics:window.ValoraRuntimeDiagnostics?.lastFeaturedHomeSurvey||{}};}}
async function getFeaturedHomeSurveyUrl(){const r=window.ValoraRuntimeCache; if(r.featuredHomeSurveyResult)return r.featuredHomeSurveyResult.url||''; if(!r.featuredHomeSurveyPromise){r.featuredHomeSurveyPromise=Promise.race([getFeaturedHomeSurvey(),new Promise(resolve=>setTimeout(()=>resolve({ok:false,url:'',errorCode:'timeout',message:'Tempo excedido'}),5000))]).then(res=>{const url=res?.url&&!/survey_demo|empresa-exemplo|tokenHash=/i.test(res.url)?res.url:'';r.featuredHomeSurveyResult={...(res||{}),url};return r.featuredHomeSurveyResult;}).catch(error=>{r.featuredHomeSurveyError=error;recordPublicBootError(error,'getFeaturedHomeSurveyUrl');return {ok:false,url:'',errorCode:error?.code||'featured_error',message:'Diagnóstico indisponível'};});} const resolved=await r.featuredHomeSurveyPromise; return resolved?.url||'';}
function resolveFeaturedFreeSurvey(store=state){return resolveHomeFeaturedSurvey(store).survey;}
function resolveFeaturedSurveyLink(survey){return buildHomeFeaturedSurveyUrl(survey);}
function getFeaturedFreeSurvey(){return resolveFeaturedFreeSurvey(state);}
function buildPublicSurveyUrl(survey){return buildHomeFeaturedSurveyUrl(survey)||'#plans';}

function isDemoPublicSurveyLink(params) {
  const surveyId = String(params?.survey || params?.surveyId || '').trim().toLowerCase();
  const org = String(params?.org || params?.organization || '').trim().toLowerCase();
  const token = String(params?.token || '').trim().toLowerCase();
  const legacyWords = ['demo', 'example', 'exemplo'];
  return surveyId === 'survey_demo' || legacyWords.some(w => surveyId === w || surveyId.includes(w)) ||
    org === 'empresa-exemplo' || legacyWords.some(w => org === w || org.includes(w)) || token.includes('demo');
}
function isOfficialFreeSurvey(survey) {
  if (!survey) return false;
  const id = String(survey.id || survey.surveyId || '').toLowerCase();
  if (id === 'survey_demo' || id.includes('demo') || id.includes('exemplo') || id.includes('example')) return false;
  const title = String(survey.title || survey.name || '').toLowerCase();
  const status = String(survey.status || '').toLowerCase();
  const visibility = String(survey.visibility || survey.publicVisibility || 'public').toLowerCase();
  const freeByTitle = title.includes('valora insight') || title.includes('diagnóstico gratuito') || title.includes('diagnostico gratuito') || title.includes('pesquisa gratuita');
  const hasRealPublicToken = !!(survey.publicToken || survey.token || survey.accessToken) && String(survey.publicToken || survey.token || survey.accessToken) !== String(survey.tokenHash || '');
  return hasRealPublicToken &&
    (id === 'official_free_survey' || survey.organizationId === 'valora-oficial' || survey.companyId === 'valora-oficial' || survey.official === true || survey.isOfficial === true || survey.isFree === true || survey.planId === 'free' || freeByTitle) &&
    ['active', 'published', 'open'].includes(status) &&
    !['private', 'restricted', 'internal'].includes(visibility) &&
    survey.revoked !== true && !survey.revokedAt;
}
function officialFreeSurveyDiagnostics(reason, candidates = []) {
  const first = candidates[0] || {};
  const hasToken = !!(first.publicToken || first.token || first.accessToken) && String(first.publicToken || first.token || first.accessToken) !== String(first.tokenHash || '');
  return { attemptedSources: ['state.homeFeatured', 'state.surveys', 'ValoraRepository.loadOfficialFreeSurvey', 'repairFreeSurveyPublicLink'], reason, foundCandidatesCount: candidates.length, hasPublicToken: hasToken, status: first.status || '', visibility: first.visibility || first.publicVisibility || '', isFree: first.isFree === true || first.planId === 'free' };
}
async function loadOfficialFreeSurvey() {
  const surveys = Array.isArray(state?.surveys) ? state.surveys : [];
  const candidates = [];
  const byOfficialId = surveys.find(s => String(s?.id || s?.surveyId || '') === OFFICIAL_FREE_SURVEY_ID);
  if (byOfficialId) candidates.push(byOfficialId);
  const byHome = resolveHomeFeaturedSurvey(state)?.survey;
  if (byHome && byHome !== byOfficialId) candidates.push(byHome);
  candidates.push(...surveys.filter(s => s && s !== byHome && s !== byOfficialId));
  const local = candidates.find(isOfficialFreeSurvey);
  if (local) { window.ValoraRuntimeDiagnostics = window.ValoraRuntimeDiagnostics || {}; window.ValoraRuntimeDiagnostics.lastOfficialFreeSurvey = officialFreeSurveyDiagnostics('local_candidate_found', [local]); return local; }
  if (window.ValoraRepository?.loadOfficialFreeSurvey) {
    const remote = await window.ValoraRepository.loadOfficialFreeSurvey();
    if (remote) { window.ValoraRuntimeDiagnostics = window.ValoraRuntimeDiagnostics || {}; window.ValoraRuntimeDiagnostics.lastOfficialFreeSurvey = officialFreeSurveyDiagnostics('remote_candidate_found', [remote]); return remote; }
  }
  window.ValoraRuntimeDiagnostics = window.ValoraRuntimeDiagnostics || {};
  window.ValoraRuntimeDiagnostics.lastOfficialFreeSurvey = officialFreeSurveyDiagnostics('no_valid_official_free_survey', candidates.filter(Boolean));
  return null;
}
async function ensureOfficialFreeSurveyPublicLink(survey) {
  if (!survey) return null;
  const currentToken = survey.publicToken || survey.token || survey.accessToken || '';
  if (!currentToken || currentToken === survey.tokenHash) {
    try {
      const repaired = await callFirebaseFunction('repairFreeSurveyPublicLink', { surveyId: survey.id });
      Object.assign(survey, repaired?.survey || repaired || {});
    } catch (error) {
      window.ValoraRuntimeDiagnostics = window.ValoraRuntimeDiagnostics || {};
      window.ValoraRuntimeDiagnostics.freeSurveyRepairRequired = { surveyId: survey.id, code: publicErrorCode(error) };
    }
  }
  if (!survey.publicToken && survey.tokenHash && !survey.token && !survey.accessToken) return null;
  if ((survey.publicToken || survey.token || survey.accessToken) === survey.tokenHash) return null;
  survey.isFree = true; survey.visibleOnHome = true; survey.featuredOnHome = true;
  return ensureSurveyPublicLink(survey);
}
function buildOfficialFreeSurveyUrl(survey) {
  if (!isOfficialFreeSurvey(survey)) return '';
  const token = survey.publicToken || survey.token || survey.accessToken || '';
  if (!token || token === String(survey.tokenHash || '')) return '';
  try {
    const company=companyById(survey.companyId)||companyById(survey.organizationId)||{};
    const base = window.ValoraConfig?.APP_PUBLIC_URL || location.href.split('?')[0].split('#')[0];
    const u = new URL(base);
    u.searchParams.set('survey', survey.id || survey.surveyId || OFFICIAL_FREE_SURVEY_ID);
    u.searchParams.set('token', token);
    u.searchParams.set('org', company.slug || company.publicSlug || (String(survey.id||survey.surveyId||'')===OFFICIAL_FREE_SURVEY_ID?OFFICIAL_FREE_ORG_SLUG:''));
    const url = u.toString();
    if (/survey_demo|empresa-exemplo|tokenHash=/i.test(url)) return '';
    return url;
  } catch (_) { return ''; }
}


async function getOfficialFreeSurveyUrl() {
  try {
    const featuredUrl = await getFeaturedHomeSurveyUrl();
    if (featuredUrl) return featuredUrl;
    const official = await loadOfficialFreeSurvey();
    const linked = await ensureOfficialFreeSurveyPublicLink(official);
    const token = linked?.publicToken || linked?.token || linked?.accessToken || '';
    const status = String(linked?.status || '').toLowerCase();
    const free = linked?.isFree === true || linked?.planId === 'free';
    if (!linked || !['active','published','open'].includes(status) || !free || !token || token === String(linked.tokenHash || '')) throw new Error('official_free_survey_unavailable');
    const company=companyById(linked.companyId)||companyById(linked.organizationId)||{};
    const base = window.ValoraConfig?.APP_PUBLIC_URL || location.href.split('?')[0].split('#')[0];
    const url = new URL(base);
    url.searchParams.set('survey', linked.id || linked.surveyId || OFFICIAL_FREE_SURVEY_ID);
    url.searchParams.set('token', token);
    url.searchParams.set('org', company.slug || company.publicSlug || (String(linked.id||linked.surveyId||'')===OFFICIAL_FREE_SURVEY_ID?OFFICIAL_FREE_ORG_SLUG:''));
    const text = url.toString();
    if (/survey_demo|empresa-exemplo|tokenHash=/i.test(text)) return '';
    return text;
  } catch (error) {
    window.ValoraRuntimeDiagnostics = window.ValoraRuntimeDiagnostics || {};
    window.ValoraRuntimeDiagnostics.lastHomeFreeSurvey = { provider: 'firestore-or-cache', status: 'error', reason: publicErrorCode(error), surveyId: OFFICIAL_FREE_SURVEY_ID, org: OFFICIAL_FREE_ORG_SLUG, error: sanitizePublicError(error) };
    return '';
  }
}


async function resolveFeaturedHomeSurveyPayload(payload = {}) {
  const resolved=await resolveFeaturedHomeSurvey();
  const linked=resolved?.survey;
  const token=linked?.publicToken||linked?.token||linked?.accessToken||'';
  if(!linked||!token||token===String(linked.tokenHash||'')){const e=new Error('Pesquisa gratuita oficial indisponível.');e.code='official_free_survey_unavailable';throw e;}
  let form=formById(linked.formId);
  let company=resolved.company||companyById(linked.companyId||linked.organizationId)||findOrganizationBySlug(OFFICIAL_FREE_ORG_SLUG);
  if((!form||!company)&&window.ValoraRepository?.validatePublicSurvey){
    try{const validated=await window.ValoraRepository.validatePublicSurvey({surveyId:linked.id,token,org:company?.slug||OFFICIAL_FREE_ORG_SLUG});form=form||validated.form;company=company||validated.company;}catch(_){}
  }
  if(!form){const e=new Error('Formulário da pesquisa gratuita indisponível.');e.code='official_free_survey_unavailable';throw e;}
  const org=company?.slug||company?.publicSlug||OFFICIAL_FREE_ORG_SLUG;
  publicSurveyCache.set(linked.id,{survey:linked,form,company,lgpd:{text:state.settings?.lgpdText||LGPD_TEXT}});
  return {...payload,surveyId:linked.id,token,org,survey:linked,form,company};
}

async function resolveOfficialFreeSurveyPayload(payload = {}) {
  const official = await loadOfficialFreeSurvey();
  const linked = await ensureOfficialFreeSurveyPublicLink(official);
  const token = linked?.publicToken || linked?.token || linked?.accessToken || '';
  if (!linked || String(linked.id || linked.surveyId || '') !== OFFICIAL_FREE_SURVEY_ID || !token || token === String(linked.tokenHash || '')) {
    const e = new Error('Pesquisa gratuita oficial indisponível.');
    e.code = 'official_free_survey_unavailable';
    throw e;
  }
  let form = formById(linked.formId);
  let company = companyById(linked.companyId || linked.organizationId) || findOrganizationBySlug(OFFICIAL_FREE_ORG_SLUG);
  if ((!form || !company) && window.ValoraRepository?.validatePublicSurvey) {
    try {
      const loaded = await window.ValoraRepository.validatePublicSurvey({ surveyId: OFFICIAL_FREE_SURVEY_ID, token, org: OFFICIAL_FREE_ORG_SLUG });
      form = form || loaded?.form;
      company = company || loaded?.company;
      Object.assign(linked, loaded?.survey || {});
    } catch (_) {}
  }
  if (!form && window.ValoraRepository?.loadOfficialFreeSurveyForm) {
    try { form = await window.ValoraRepository.loadOfficialFreeSurveyForm(); } catch (_) {}
  }
  if (!form) { const e = new Error('Formulário oficial indisponível.'); e.code = 'official_form_unavailable'; throw e; }
  const resolved = { ...payload, surveyId: OFFICIAL_FREE_SURVEY_ID, token, org: OFFICIAL_FREE_ORG_SLUG, survey: { ...linked, id: OFFICIAL_FREE_SURVEY_ID }, surveyData: { ...linked, id: OFFICIAL_FREE_SURVEY_ID }, form, company };
  publicSurveyCache.set(OFFICIAL_FREE_SURVEY_ID, { survey: resolved.survey, form, company, lgpd: { text: form.lgpdText || linked.lgpdText || state.settings?.lgpdText || LGPD_TEXT } });
  window.ValoraRuntimeDiagnostics = window.ValoraRuntimeDiagnostics || {};
  window.ValoraRuntimeDiagnostics.lastDemoLinkRedirect = { fromSurvey: payload.survey || payload.surveyId || '', fromOrg: payload.org || '', redirected: false, resolved: true, targetSurveyId: OFFICIAL_FREE_SURVEY_ID, targetOrg: OFFICIAL_FREE_ORG_SLUG };
  window.ValoraRuntimeDiagnostics.lastOfficialFreeSurvey = { provider: 'cache-or-firestore', status: 'resolved', reason: 'official_free_survey_payload_resolved', surveyId: OFFICIAL_FREE_SURVEY_ID, org: OFFICIAL_FREE_ORG_SLUG, redirectedFromDemo: isDemoPublicSurveyLink(payload), usedFallback: false, savedResponse: false };
  return resolved;
}

async function handleDemoPublicSurveyLink(params) {
  try {
    const resolved = await resolveOfficialFreeSurveyPayload(params);
    await renderTakeSurvey(resolved.surveyId, resolved.token, resolved.org, resolved);
  } catch (_) {
    renderPublicSurveyError({
      code: 'Diagnóstico gratuito',
      title: 'Diagnóstico gratuito indisponível',
      message: 'A pesquisa gratuita oficial ainda não está disponível. Tente novamente em instantes ou fale com a Valora Group.',
      showWhatsapp: true
    });
  }
  return true;
}

