function renderAdminUserCard(user){return `<div class="who"><b>${esc(user.name)}</b><span>${esc(ROLE_LABELS[user.role]||user.role)}</span><span>${esc(user.companyId?companyName(user.companyId):'Valora Group')}</span></div>`;}
function renderAdminMenuItem(item,currentRoute){const disabled=item.disabled?'disabled aria-disabled="true"':'';const badge=item.disabled?'<span class="badge">em implantação</span>':'';return `<button class="${item.id===currentRoute?'active':''}" data-action="portalTab" data-scope="admin" data-route="${esc(item.route||`admin/${item.id}`)}" data-tab="${esc(item.id)}" ${disabled}>${esc(item.label)}${badge}</button>`;}
function getAdminMenuItems(user){
  const items=[
    {id:'dashboard',label:'Dashboard',route:'admin/dashboard',permission:'canAccessPortal'},
    {id:'notifications',label:'Notificações',route:'admin/notifications',permission:'canAccessPortal'},
    {id:'clients',label:'Clientes',route:'admin/clients',permission:'canManageCompanies'},
    {id:'finance',label:'Financeiro',route:'admin/finance',permission:'canViewFinance',module:'financeiro'},
    {id:'plans',label:'Planos',route:'admin/plans',permission:'canManagePlans'},
    {id:'surveys',label:'Pesquisas',route:'admin/surveys',permission:'canCreateSurveys',module:'pesquisas'},
    {id:'forms',label:'Formulários',route:'admin/forms',permission:'canCreateForms',module:'formularios'},
    {id:'users',label:'Usuários',route:'admin/users',permission:'canManageCompanyUsers'},
    {id:'responses',label:'Respostas',route:'admin/responses',permission:'canViewResponses'},
    {id:'reports',label:'Relatórios',route:'admin/reports',permission:'canViewReports',module:'relatorios'},
    {id:'certificates',label:'Certificados',route:'admin/certificates',permission:'canViewReports',disabled:true},
    {id:'communications',label:'Comunicações',route:'admin/communications',permission:'canSendInvites'},
    {id:'logs',label:'Logs',route:'admin/logs',permission:'canViewLogs'},
    {id:'backup',label:'Backup',route:'admin/backup',permission:'canBackup'},
    {id:'support',label:'Atendimento',route:'admin/support',permission:'canHandleSupport'},
    {id:'settings',label:'Configurações',route:'admin/settings',permission:'canManageGlobalSettings'},
    {id:'environment',label:'Status do Ambiente',route:'admin/environment',permission:'canViewLogs'},
    {id:'diagnostics',label:'Diagnóstico do Ambiente',route:'admin/diagnostics',permission:'canViewLogs'},
    {id:'freeDiagnostics',label:'Diagnósticos gratuitos',route:'admin/free-diagnostics',permission:'canViewResponses'},
    {id:'operations',label:'Operação',route:'admin/operations',permission:'canViewLogs'}
  ];
  return items.filter(function(item){return isGlobalAdmin(user)||can(user,item.permission);}).map(item=>({...item,disabled:item.disabled||(item.module?!moduleEnabled(item.module):false)}));
}
function renderAdminSidebar(user,currentRoute){const items=getAdminMenuItems(user);return `<aside id="adminSidebar" class="sidebar admin-sidebar" aria-label="Menu administrativo" aria-hidden="true" data-admin-sidebar>${renderAdminUserCard(user)}<nav class="side-menu admin-nav" aria-label="Menu da área">${items.map(item=>renderAdminMenuItem(item,currentRoute)).join('')}</nav></aside>`;}
function renderPortal(scope,tab){
  const user=currentUser();if(!user)return renderLogin('Entre para acessar sua área.');
  const menu=scope==='admin'?getAdminMenuItems(user):menuFor(scope);const selected=menu.some(x=>x.id===tab&&!x.disabled)?tab:(menu.find(x=>!x.disabled)?.id||'dashboard');
  const sidebar=scope==='admin'?renderAdminSidebar(user,selected):`<aside class="sidebar admin-sidebar" id="adminSidebar" aria-label="Menu administrativo" aria-hidden="true" data-admin-sidebar><div class="who"><b>${esc(user.name)}</b><span>${esc(ROLE_LABELS[user.role]||user.role)}</span><span>${esc(user.companyId?companyName(user.companyId):'Valora Group')}</span></div><nav class="side-menu admin-nav" aria-label="Menu da área">${menu.map(x=>`<button class="${x.id===selected?'active':''}" data-action="portalTab" data-scope="${scope}" data-tab="${x.id}" ${x.disabled?'disabled':''}>${esc(x.label)}</button>`).join('')}</nav></aside>`;
  $('#app').innerHTML=`<div class="app-shell admin-shell"><button type="button" class="btn btn-primary admin-mobile-menu-toggle admin-mobile-toggle" data-action="toggleAdminMobileMenu" data-admin-mobile-toggle aria-label="Abrir menu administrativo" aria-controls="adminSidebar" aria-expanded="false"><span aria-hidden="true">☰</span><span>Menu</span></button>${sidebar}<section class="content" id="portalContent"></section></div>`;
  ensureAdminMobileOverlay();bindAdminMobileMenuEvents();renderPortalTab(scope,selected);
}
function menuFor(scope){
  const user=currentUser(),role=user?.role;
  if(scope==='participante')return role==='convidado_externo'?[]:[{id:'dashboard',label:'Minha área'},{id:'notifications',label:'Notificações'},{id:'available',label:'Pesquisas disponíveis'},{id:'responses',label:'Pesquisas respondidas'},{id:'certificates',label:'Certificados'},{id:'privacy',label:'Privacidade e LGPD'},{id:'support',label:'Atendimento'}];
  if(scope==='empresa'){
    if(role==='gestor_area')return [{id:'dashboard',label:'Visão geral da área'},{id:'notifications',label:'Notificações'},{id:'responses',label:'Respostas da área'},{id:'actionPlans',label:'Plano de ação',disabled:!moduleEnabled('actionPlans')},{id:'reports',label:'Relatórios da área',disabled:!moduleEnabled('relatorios')}];
    if(role==='analista_resultados')return [{id:'dashboard',label:'Visão geral'},{id:'notifications',label:'Notificações'},{id:'responses',label:'Respostas'},{id:'actionPlans',label:'Plano de ação',disabled:!moduleEnabled('actionPlans')},{id:'reports',label:'Relatórios',disabled:!moduleEnabled('relatorios')}];
    const items=[{id:'dashboard',label:'Visão geral'},{id:'notifications',label:'Notificações'},{id:'support',label:'Atendimento'}];
    if(can(user,'canCreateSurveys'))items.push({id:'surveys',label:'Pesquisas',disabled:!moduleEnabled('pesquisas')});
    if(can(user,'canCreateForms'))items.push({id:'forms',label:'Formulários',disabled:!moduleEnabled('formularios')});
    if(can(user,'canSendInvites'))items.push({id:'users',label:'Funcionários'});
    if(can(user,'canViewResponses'))items.push({id:'responses',label:'Respostas'});
    if(can(user,'canViewReports'))items.push({id:'actionPlans',label:'Plano de ação',disabled:!moduleEnabled('actionPlans')});
    if(can(user,'canViewReports'))items.push({id:'reports',label:'Relatórios',disabled:!moduleEnabled('relatorios')});
    if(['empresa_admin','gestor_pesquisa','analista_resultados'].includes(role))items.push({id:'integrations',label:'Integrações',disabled:!moduleEnabled('integrations')});
    if(can(user,'canViewPlan'))items.push({id:'plan',label:'Plano contratado'});
    if(can(user,'canEditOwnCompany'))items.push({id:'settings',label:'Dados e marca'});
    return items;
  }
  if(role==='consultor_valora')return [{id:'dashboard',label:'Dashboard'},{id:'notifications',label:'Notificações'},{id:'clients',label:'Clientes'},{id:'surveys',label:'Pesquisas'},{id:'forms',label:'Formulários'},{id:'responses',label:'Respostas'},{id:'reports',label:'Relatórios'},{id:'actionPlans',label:'Plano de ação'},{id:'support',label:'Atendimentos'}];
  return [{id:'dashboard',label:'Dashboard'},{id:'notifications',label:'Notificações'},{id:'clients',label:'Clientes'},{id:'finance',label:'Financeiro',disabled:!moduleEnabled('financeiro')},{id:'plans',label:'Planos'},{id:'surveys',label:'Pesquisas',disabled:!moduleEnabled('pesquisas')},{id:'forms',label:'Formulários',disabled:!moduleEnabled('formularios')},{id:'users',label:'Usuários'},{id:'responses',label:'Respostas'},{id:'reports',label:'Relatórios',disabled:!moduleEnabled('relatorios')},{id:'actionPlans',label:'Plano de ação',disabled:!moduleEnabled('actionPlans')},{id:'modules',label:'Módulos'},{id:'settings',label:'Configurações'},{id:'publish',label:'Publicador'},{id:'backup',label:'Backup'},{id:'integrations',label:'Integrações',disabled:!moduleEnabled('integrations')},{id:'logs',label:'Logs'},{id:'support',label:'Atendimentos'}];
}

