function notificationBell(){const u=currentUser();if(!u||u.role==='convidado_externo'||!window.ValoraNotifications)return '';const unread=window.ValoraNotifications.getUnreadNotifications(state,u).length;const latest=window.ValoraNotifications.listForUser(state,u).slice(0,5);return `<div class="notification-menu"><button class="btn btn-soft notification-bell" data-action="toggleNotifications" aria-label="Abrir notificações">🔔${unread?`<span>${unread}</span>`:''}</button><div class="notification-dropdown" id="notificationDropdown"><div class="notification-drop-head"><b>Notificações</b><button class="btn btn-mini btn-soft" data-action="markAllNotificationsRead">Marcar todas</button></div>${latest.map(notificationItem).join('')||'<div class="empty">Sem notificações.</div>'}<button class="btn btn-primary btn-block" data-action="openNotificationsCenter">Ver todas</button></div></div>`;}
function notificationItem(n){return `<div class="notification-item ${esc(n.severity)} ${n.read?'read':''}"><div><b>${esc(n.title)}</b><p>${esc(n.message)}</p><small>${esc(notificationTypeLabel(n.type))} • ${brDate(n.createdAt)}</small></div><div class="notification-actions"><button class="btn btn-soft btn-mini" data-action="markNotificationRead" data-id="${esc(n.id)}" ${n.read?'disabled':''}>Lida</button><button class="btn btn-soft btn-mini" data-action="dismissNotification" data-id="${esc(n.id)}">Dispensar</button>${n.actionRoute?`<button class="btn btn-secondary btn-mini" data-action="actNotification" data-route="${esc(n.actionRoute)}" data-id="${esc(n.id)}">${esc(n.actionLabel||'Abrir')}</button>`:''}</div></div>`;}
function notificationTypeLabel(type){return ({survey_expiring:'Pesquisa vencendo',survey_expired:'Pesquisa expirada',invitation_pending:'Convite pendente',invitation_failed:'Falha de convite',new_response:'Nova resposta',low_response_rate:'Baixa adesão',action_overdue:'Ação vencida',action_critical:'Ação crítica',plan_limit_warning:'Limite próximo',plan_limit_exceeded:'Limite excedido',onboarding_stalled:'Onboarding travado',report_ready:'Relatório disponível',trial_ending:'Trial vencendo',payment_overdue:'Pagamento em atraso',subscription_suspended:'Assinatura suspensa',upgrade_recommended:'Upgrade recomendado',white_label_incomplete:'White label incompleto',system_error:'Erro do sistema'})[type]||type;}
function notificationsSection(){const u=currentUser();const list=window.ValoraNotifications?.listForUser(state,u)||[];const types=[...new Set(list.map(n=>n.type))],sevs=[...new Set(list.map(n=>n.severity))];return `<div class="section-toolbar"><div><h3>Central de notificações</h3><p class="muted">Alertas inteligentes por perfil, empresa, área e permissão. Convidado externo não acessa esta central.</p></div><button class="btn btn-primary" data-action="markAllNotificationsRead">Marcar todas como lidas</button></div><details class="card filters notification-filters" open><summary>Filtros e agrupamentos</summary><div class="form-grid"><div class="field"><label>Tipo</label><select data-input="notificationFilter" id="notificationType"><option value="">Todos</option>${types.map(t=>`<option value="${esc(t)}">${esc(notificationTypeLabel(t))}</option>`).join('')}</select></div><div class="field"><label>Severidade</label><select data-input="notificationFilter" id="notificationSeverity"><option value="">Todas</option>${sevs.map(v=>`<option value="${esc(v)}">${esc(v)}</option>`).join('')}</select></div><label class="checkline"><input id="notificationUnread" data-input="notificationFilter" type="checkbox"><span>Apenas não lidas</span></label></div></details><div id="notificationList" class="notification-list">${renderNotificationList(list)}</div>`;}
function renderNotificationList(list){if(!list.length)return '<div class="empty">Nenhuma notificação para seu perfil.</div>';const grouped=list.reduce((a,n)=>{(a[n.severity]||(a[n.severity]=[])).push(n);return a;},{});return Object.entries(grouped).map(([sev,rows])=>`<section class="notification-group"><h3>${esc(sev)} <span class="badge">${rows.length}</span></h3>${rows.map(notificationItem).join('')}</section>`).join('');}
function filterNotifications(){const u=currentUser(),type=$('#notificationType')?.value,severity=$('#notificationSeverity')?.value,unread=$('#notificationUnread')?.checked;let rows=window.ValoraNotifications?.listForUser(state,u,{type,severity,unread})||[];const box=$('#notificationList');if(box)box.innerHTML=renderNotificationList(rows);}
function markNotification(id){if(window.ValoraNotifications?.markNotificationRead(state,id,currentUser())){audit('Notificação lida','notification',id,'Central de notificações');persist('Notificação marcada como lida.');rerenderPortal();}}
function dismissNotification(id){if(window.ValoraNotifications?.dismissNotification(state,id,currentUser())){audit('Notificação dispensada','notification',id,'Central de notificações');persist('Notificação dispensada.');rerenderPortal();}}
function markAllNotifications(){const count=window.ValoraNotifications?.markAllNotificationsRead(state,currentUser())||0;audit('Notificações marcadas como lidas','notification','all',`${count} item(ns)`);persist(`${count} notificação(ões) marcada(s).`);rerenderPortal();}
function actOnNotification(route,id){if(id)window.ValoraNotifications?.markNotificationRead(state,id,currentUser());save();navigate(route||'empresa/notifications');}

function kpi(label,value,detail='',tone=''){return `<div class="kpi ${tone}"><span>${esc(label)}</span><strong>${esc(value)}</strong><small>${esc(detail)}</small></div>`;}
function barList(items){return renderHorizontalBars(items);}
function renderHorizontalBars(items=[]){if(!items.length)return '<div class="empty">Sem dados para exibir.</div>';return `<div class="metric-list">${items.map(x=>`<div class="metric-row"><div><b>${esc(x.label)}</b><span>${esc(x.valueLabel||x.value||'0')}</span></div><div class="bar" aria-label="${esc(x.label)} ${esc(x.valueLabel||x.value||'0')}"><span style="width:${clamp(x.percent??x.percentage,0,100)}%"></span></div></div>`).join('')}</div>`;}
function renderBarChart(items=[]){if(!items.length)return '<div class="empty">Sem dados para exibir.</div>';const max=Math.max(1,...items.map(i=>Number(i.value||0)));return `<div class="chart-columns">${items.map(i=>`<div class="chart-col"><b>${esc(i.valueLabel||i.value||0)}</b><div class="col" style="height:${clamp(Number(i.value||0)/max*100,3,100)}%"></div><span>${esc(i.label)}</span></div>`).join('')}</div>`;}
function renderTrendLine(points=[]){if(!points.length)return '<div class="empty">Sem série histórica.</div>';const max=Math.max(1,...points.map(p=>Number(p.value||0)));return `<div class="trend-line">${points.map(p=>`<div class="trend-point"><span style="height:${clamp(Number(p.value||0)/max*100,4,100)}%"></span><b>${esc(p.value)}</b><small>${esc(p.label)}</small></div>`).join('')}</div>`;}
function renderDistribution(items=[]){return renderHorizontalBars(items.map(i=>({label:i.label,valueLabel:`${i.value||0} resposta(s)`,percent:items.reduce((s,x)=>s+Number(x.value||0),0)?Number(i.value||0)/items.reduce((s,x)=>s+Number(x.value||0),0)*100:0})));}
function renderRanking(items=[]){if(!items.length)return '<div class="empty">Sem dados para ranking.</div>';return `<div class="ranking-list">${items.map((i,idx)=>`<div><b>${idx+1}. ${esc(i.label)}</b><span>${esc(i.valueLabel||i.value||'')}</span></div>`).join('')}</div>`;}
function renderProgressRing(value){return `<div class="progress-ring"><strong>${clamp(value,0,100)}%</strong></div>`;}
function onboardingMetrics(companyId){
  const c=companyById(companyId), plan=planById(c?.planId), users=state.users.filter(u=>u.companyId===companyId), employees=users.filter(u=>COMPANY_ROLES.includes(u.role)&&u.role!=='empresa_admin'), admins=users.filter(u=>u.role==='empresa_admin'&&u.status!=='inactive'), forms=scopedForms(companyId), ownForms=forms.filter(f=>f.companyId===companyId||f.global), surveys=scopedSurveys(companyId), activeSurveys=surveys.filter(s=>surveyIsActive(s)), invitations=state.invitations.filter(i=>i.companyId===companyId), responses=scopedResponses(companyId), reports=responses.length;
  const basic=!!(c?.name&&(c.email||c.phone||c.document||c.address));
  const checks=[
    {id:'company',label:'Dados da empresa revisados',weight:10,done:basic,action:'portalTab',scope:'empresa',tab:'settings',button:'Revisar dados',text:'Confirme nome, contato, endereço, responsável e área principal.'},
    {id:'plan',label:'Plano contratado definido',weight:10,done:!!plan,action:'portalTab',scope:'empresa',tab:'plan',button:'Ver plano',text:'Confira limites, módulos e se o envio por e-mail está incluso.'},
    {id:'admin',label:'Administrador da empresa configurado',weight:10,done:admins.length>0,action:'newUser',button:'Configurar admin',text:'Mantenha ao menos um administrador ativo para operar o ambiente.'},
    {id:'employees',label:'Funcionários/respondentes cadastrados',weight:15,done:employees.length>0,action:'newUser',button:'Cadastrar funcionários',text:'Cadastre respondentes com e-mail, perfil, departamento e status.'},
    {id:'forms',label:'Questionário criado ou escolhido',weight:15,done:ownForms.length>0,action:'newForm',button:'Criar questionário',text:'Use um modelo global ou crie o Diagnóstico Essencial de Maturidade.'},
    {id:'surveys',label:'Pesquisa criada',weight:15,done:activeSurveys.length>0,action:'newSurvey',button:'Criar pesquisa',text:'Transforme um questionário em campanha com validade e LGPD.'},
    {id:'invites',label:'Convites enviados',weight:10,done:invitations.length>0,action:'bulkInvite',button:'Enviar convites',text:'Selecione uma pesquisa ativa e envie convites por e-mail.'},
    {id:'responses',label:'Primeira resposta recebida',weight:10,done:responses.length>0,action:'portalTab',scope:'empresa',tab:'responses',button:'Ver respostas',text:'Acompanhe a taxa de resposta e reenvie lembretes se necessário.'},
    {id:'reports',label:'Relatório inicial gerado',weight:5,done:reports>0,action:'portalTab',scope:'empresa',tab:'reports',button:'Gerar relatório',text:'Com ao menos uma resposta, gere o relatório inicial.'}
  ];
  let percent=checks.reduce((sum,x)=>sum+(x.done?x.weight:0),0);const next=checks.find(x=>!x.done)||checks[checks.length-1];const status=percent>=100?'implantado':responses.length?'com_respostas':invitations.length?'convites_enviados':activeSurveys.length?'pesquisa_criada':employees.length?'funcionarios_cadastrados':percent>=20?'configurando':'novo';
  const inactiveDays=Math.floor((Date.now()-new Date(c?.updatedAt||c?.createdAt||Date.now()))/86400000);return {company:c,plan,checks,percent,next,status:inactiveDays>14&&percent<80?'travado':status,employees,forms,surveys,activeSurveys,invitations,responses};
}
function onboardingCard(companyId){const m=onboardingMetrics(companyId), canCreate=can(currentUser(),'canCreateSurveys')||can(currentUser(),'canManageCompanyUsers');return `<div class="card onboarding-card"><div class="onboarding-head"><div><span class="badge">Primeiros passos da implantação</span><h3>Implantação ${m.percent}% concluída</h3><p>Etapa atual: <b>${esc(m.next.label)}</b>. Próximo passo: ${esc(m.next.text)}</p></div><div class="progress-ring"><strong>${m.percent}%</strong></div></div><div class="bar onboarding-progress"><span style="width:${m.percent}%"></span></div>${planWarnings(companyId)}<div class="quick-actions"><button class="btn btn-primary" data-action="openOnboardingWizard" ${canCreate?'':'disabled'}>Configurar minha primeira pesquisa</button><button class="btn btn-secondary" data-action="${m.next.action}" ${m.next.scope?`data-scope="${m.next.scope}" data-tab="${m.next.tab}"`:''}>${esc(m.next.button)}</button></div><div class="onboarding-list">${m.checks.map(x=>`<div class="onboarding-step ${x.done?'done':x.id===m.next.id?'current':''}"><span>${x.done?'✓':x.id===m.next.id?'…':'○'}</span><div><b>${esc(x.label)}</b><small>${esc(x.done?'Concluído':x.id===m.next.id?'Em andamento':'Pendente')} • ${esc(x.text)}</small></div><button class="btn btn-soft btn-mini" data-action="${x.action}" ${x.scope?`data-scope="${x.scope}" data-tab="${x.tab}"`:''}>${esc(x.button)}</button></div>`).join('')}</div></div>`;}
function planWarnings(companyId){const p=getCompanyPlan(companyId);const u=currentUser();let out='';if(p&&p.allowEmailSending===false)out+='<div class="notice warn">Seu plano atual não inclui envio por e-mail. Fale com a Valora para ativar.</div>';else if(p&&!hasEffectiveCapability(companyId,'emailSending'))out+='<div class="notice warn">Envio por e-mail incluído no plano, mas depende da ativação do canal de comunicação neste ambiente.</div>';if(u&&!can(u,'canCreateSurveys'))out+='<div class="notice warn">Seu perfil permite acompanhar resultados, mas não criar pesquisas.</div>';return out;}
function smartEmpty(kind){const map={employees:['Nenhum funcionário cadastrado ainda.','Cadastre os primeiros respondentes para enviar pesquisas e acompanhar resultados por área.','Cadastrar funcionário','newUser'],forms:['Nenhum questionário criado.','Crie um questionário próprio ou use um modelo global para iniciar seu diagnóstico.','Criar questionário','newForm'],surveys:['Nenhuma pesquisa ativa.','Crie uma pesquisa a partir de um questionário e envie convites aos funcionários.','Criar pesquisa','newSurvey'],invites:['Nenhum convite enviado.','Selecione uma pesquisa ativa e envie para os funcionários cadastrados.','Enviar convites','bulkInvite'],responses:['Ainda não há respostas.','Quando os participantes concluírem a pesquisa, os resultados aparecerão aqui.','Reenviar convites','bulkInvite'],reports:['Relatório ainda indisponível.','Você precisa ter pelo menos uma resposta concluída para gerar um relatório.','Ver pesquisas','portalTab']};const x=map[kind];return `<div class="card empty-smart"><h3>${x[0]}</h3><p>${x[1]}</p><button class="btn btn-primary" data-action="${x[3]}" ${kind==='reports'?'data-scope="empresa" data-tab="surveys"':''}>${x[2]}</button></div>`;}
