function publishSection(){
  if(currentUser()?.role!=='admin_valora')return `<div class="danger-box">Apenas admin_valora acessa o Publicador.</div>`;
  const iis='C:\\inetpub\\wwwroot\\valoragroup', url='https://valoragroup.mnsoft.com.br', project='gestordepesquisa';
  const dry=`node scripts/publish-iis-prd.js --iis-path ${iis} --mode firebase --dry-run --url ${url} --project ${project}`;
  const apply=`node scripts/publish-iis-prd.js --iis-path ${iis} --mode firebase --apply --url ${url} --project ${project}`;
  const data=`node scripts/publish-iis-prd.js --iis-path ${iis} --mode firebase --with-data --data-file .\\exports\\valora-prd-export.json --project ${project} --apply`;
  const health=`node scripts/healthcheck-prd.js --url ${url} --project ${project} --check-firebase`;
  const checklist=['config.js em modo firebase com FIREBASE_CONFIG preenchido','Rodar Simular publicação antes do Apply','Conferir backup automático em backups/iis/','Confirmar dist/index.html, assets/*.js, assets/*.css e web.config','Health check sem 500.19, 403.14, MIME text/html ou Firebase sem config','Rollback disponível com scripts/restore-iis-backup.js --latest'].join('\n');
  return `<div class="grid grid-2"><div class="card"><h3>Publicador para IIS</h3><p>Esta tela prepara arquivos e comandos, mas não copia para o IIS pelo navegador. A publicação real roda no Windows Server por PowerShell/BAT + Node.</p><div class="table-actions"><button class="btn btn-primary" data-action="exportLocalMigration">Exportar dados para PRD</button><button class="btn btn-secondary" data-action="downloadPublishConfig">Baixar publish.config.json exemplo</button><button class="btn btn-soft" data-action="downloadIisWebConfig">Baixar web.config IIS</button><button class="btn btn-soft" data-action="downloadPublishChecklist">Checklist</button></div></div><div class="card"><h3>Duplo clique no Windows</h3><p>Use <b>tools\\windows\\Publicar-Valora-PRD.bat</b> para abrir o menu com Simular, Publicar, Pacote, Dados, Health Check e Rollback.</p><p class="muted">Sem Electron nesta etapa; PowerShell + BAT mantém o publicador leve e auditável.</p></div><div class="card"><h3>Comandos de publicação</h3>${[['Dry Run',dry],['Publicar PRD',apply],['Publicar com Dados',data],['Health Check',health]].map(([label,cmd])=>`<p><b>${esc(label)}</b></p><pre>${esc(cmd)}</pre><button class="btn btn-soft btn-mini" data-action="copyLink" data-link="${esc(cmd)}">Copiar comando ${esc(label)}</button>`).join('')}</div><div class="card"><h3>Checklist PRD/IIS</h3><pre>${esc(checklist)}</pre><button class="btn btn-secondary" data-action="openExternal" data-url="PUBLICADOR_WINDOWS_PRD.md">Abrir documentação</button></div></div>`;
}
function iisWebConfigText(){return `<?xml version="1.0" encoding="UTF-8"?>\n<configuration>\n  <system.webServer>\n    <defaultDocument enabled="true"><files><clear /><add value="index.html" /></files></defaultDocument>\n    <directoryBrowse enabled="false" />\n    <staticContent><remove fileExtension=".js" /><mimeMap fileExtension=".js" mimeType="application/javascript" /><remove fileExtension=".css" /><mimeMap fileExtension=".css" mimeType="text/css" /></staticContent>\n  </system.webServer>\n</configuration>\n`;}
function downloadPublishConfig(){downloadText('publish.config.json',JSON.stringify({projectName:'Valora Pulse',mode:'firebase',firebaseProjectId:'gestordepesquisa',productionUrl:'https://valoragroup.mnsoft.com.br',iisPath:'C:\\inetpub\\wwwroot\\valoragroup',backupPath:'backups\\iis',reportsPath:'publish\\reports',packagePath:'publish\\packages',preserveFiles:['web.config'],withData:false,dataFile:'',runHealthCheck:true},null,2),'application/json');}
function downloadPublishChecklist(){downloadText('checklist-publicacao-iis-prd.txt','1. Exportar dados para PRD\n2. Copiar export para o servidor\n3. Rodar dry-run\n4. Conferir relatório em publish/reports\n5. Rodar --apply\n6. Validar index.html, assets e web.config no IIS\n7. Se necessário, restaurar último backup','text/plain');}
function downloadIisWebConfig(){downloadText('web.config',iisWebConfigText(),'application/xml');}

function backupSection(){
  if(currentUser()?.role!=='admin_valora')return `<div class="danger-box">Backup e migração são exclusivos do administrador geral.</div>`;
  const counts=firebaseSeedStatusCounts();
  const critical=[];if(!counts.plans)critical.push('planos');if(!counts.forms)critical.push('formulários');if(!counts.surveys)critical.push('pesquisas');if(!counts.companies)critical.push('empresas');
  return `<div class="grid grid-2"><div class="card"><h3>Exportar backup completo</h3><p>Gera um JSON com configurações, planos, empresas, usuários, formulários, pesquisas, respostas, financeiro e logs.</p><button class="btn btn-primary" data-action="exportBackup">Exportar JSON completo</button></div><div class="card"><h3>Importar backup</h3><p>A importação substitui a base local após confirmação. Um backup automático é baixado antes da operação.</p><button class="btn btn-danger" data-action="openImport">Selecionar arquivo JSON</button></div><div class="card"><h3>Exportar estado local para migração Firebase</h3><p>Baixa um pacote sanitizado para HML/PRD. Senhas, SMTP, Telegram, service account e segredos não são exportados.</p><label class="checkline"><input id="migrationIncludeResponses" type="checkbox"><span>Incluir respostas de teste</span></label><label class="checkline"><input id="migrationMaskDemo" type="checkbox" checked><span>Mascarar documentos de ambiente demo</span></label><button class="btn btn-primary" data-action="exportLocalMigration">Exportar dados para PRD Firebase</button><button class="btn btn-secondary" data-action="exportLocalMigrationStructure">Exportar somente estrutura para PRD</button></div><div class="card"><h3>Status do ambiente Firebase</h3><p class="muted">Em modo Firebase, estes números refletem o estado carregado do Firestore; em local/demo, servem para avaliar o que será exportado.</p>${critical.length?`<div class="danger-box">Ambiente Firebase ainda não possui ${esc(critical.join(', '))} importados.</div>`:''}<div class="kpi-grid">${kpi('Empresas',counts.companies)}${kpi('Usuários',counts.users)}${kpi('Planos',counts.plans)}${kpi('Módulos',counts.modules)}${kpi('Formulários',counts.forms,`${counts.questions} perguntas`)}${kpi('Pesquisas',counts.surveys)}${kpi('Respostas',counts.responses)}${kpi('Convites',counts.invitations)}</div><p><b>Último seed/migração:</b> ${esc(state.settings?.seed?.lastMigrationAt||state.settings?.lastMigrationAt||'não registrado no estado carregado')}</p></div></div>`;}
function logsSection(){
  if(currentUser()?.role!=='admin_valora')return `<div class="danger-box">Apenas o administrador geral pode visualizar logs globais.</div>`;
  const rows=(state.logs||[]),unanswered=(state.chatbotUnansweredQuestions||[]).slice().reverse(),since=Date.now()-24*60*60*1000,last24=rows.filter(l=>Date.parse(l.createdAt||0)>=since),errors=rows.filter(l=>['error','critical'].includes(l.level)),crit=rows.filter(l=>l.level==='critical'),sec=rows.filter(l=>l.level==='security'||l.category==='security'),tests=rows.filter(l=>l.isTest||l.category==='test'),tg=rows.filter(l=>l.telegramSent);
  const levels=[...new Set(rows.map(l=>l.level).filter(Boolean))],cats=[...new Set(rows.map(l=>l.category||l.entityType).filter(Boolean))];
  return `<div class="section-toolbar"><div><h3>Logs e Monitoramento</h3><p class="muted">Observabilidade operacional com auditoria, segurança, erros, testes, exportação e alertas Telegram filtrados.</p></div><div class="table-actions"><button class="btn btn-secondary" data-action="exportLogsCsv">Exportar CSV</button><button class="btn btn-soft" data-action="exportLogsJson">Exportar JSON</button><button class="btn btn-soft" data-action="exportLogsExcel">Exportar Excel compatível</button><button class="btn btn-danger" data-action="clearLogs">Limpar logs</button></div></div><div class="kpi-grid">${kpi('Logs 24h',last24.length)}${kpi('Erros',errors.length)}${kpi('Críticos',crit.length,'','danger')}${kpi('Segurança',sec.length)}${kpi('Testes',tests.length)}${kpi('Telegram',tg.length)}${kpi('Perguntas sem resposta',unanswered.length)}</div><div class="card table-wrap"><h3>Perguntas não respondidas pelo ValoraBot</h3><table class="table"><thead><tr><th>Pergunta</th><th>Perfil</th><th>Rota</th><th>Data</th><th>Status</th><th>Ação</th></tr></thead><tbody>${unanswered.slice(0,20).map(q=>`<tr><td>${esc(q.question)}</td><td>${esc(q.role)}</td><td>${esc(q.route)}</td><td>${brDate(q.createdAt)}</td><td>${esc(q.status)}</td><td><button class="btn btn-soft btn-mini" disabled>Adicionar à base de conhecimento</button></td></tr>`).join('')||'<tr><td colspan="6">Nenhuma pergunta sem resposta.</td></tr>'}</tbody></table><p class="muted">TODO: converter o botão em editor assistido da base de conhecimento quando houver governança editorial.</p></div><div class="card"><h3>Teste de logs</h3><div class="table-actions">${[['debug','Gerar log debug'],['info','Gerar log info'],['warn','Gerar log warning'],['error','Gerar log error'],['critical','Gerar log critical'],['audit','Gerar log audit'],['security','Gerar log security']].map(x=>`<button class="btn btn-soft btn-mini" data-action="generateTestLog" data-level="${x[0]}">${x[1]}</button>`).join('')}<button class="btn btn-secondary btn-mini" data-action="sendTelegramTest">Enviar teste Telegram</button><button class="btn btn-soft btn-mini" data-action="simulateFrontendError">Simular erro frontend</button><button class="btn btn-soft btn-mini" data-action="simulateAsyncError">Simular erro async</button><button class="btn btn-soft btn-mini" data-action="simulateAccessDenied">Simular acesso negado</button><button class="btn btn-soft btn-mini" data-action="simulateFirebaseFailure">Simular falha de Firebase</button><button class="btn btn-soft btn-mini" data-action="simulateEmailFailure">Simular falha de e-mail</button><button class="btn btn-soft btn-mini" data-action="simulateChatbotFailure">Simular falha de chatbot</button><button class="btn btn-soft btn-mini" data-action="simulateHumanSupport">Simular atendimento humano</button><button class="btn btn-soft btn-mini" data-action="simulateWebhookFailure">Simular falha de webhook</button></div></div><details class="card filters" open><summary>Filtros</summary><div class="form-grid"><div class="field"><label>Nível</label><select id="logLevelFilter" data-input="logFilter"><option value="">Todos</option>${levels.map(v=>`<option value="${esc(v)}">${esc(v)}</option>`).join('')}</select></div><div class="field"><label>Categoria</label><select id="logCategoryFilter" data-input="logFilter"><option value="">Todas</option>${cats.map(v=>`<option value="${esc(v)}">${esc(v)}</option>`).join('')}</select></div><label class="checkline"><input id="logTelegramFilter" data-input="logFilter" type="checkbox"><span>Enviado ao Telegram</span></label><label class="checkline"><input id="logTestFilter" data-input="logFilter" type="checkbox"><span>Apenas testes</span></label></div></details><div class="card table-wrap"><table class="table"><thead><tr><th>Data</th><th>Nível</th><th>Categoria</th><th>Ação</th><th>Empresa</th><th>Usuário</th><th>Mensagem</th><th>Telegram</th></tr></thead><tbody id="logsTableBody">${renderLogsRows(rows)}</tbody></table></div>`;}

function getFilteredLogs(){let rows=[...(state.logs||[])];const lvl=$('#logLevelFilter')?.value,cat=$('#logCategoryFilter')?.value;if(lvl)rows=rows.filter(l=>l.level===lvl);if(cat)rows=rows.filter(l=>(l.category||l.entityType)===cat);if($('#logTelegramFilter')?.checked)rows=rows.filter(l=>l.telegramSent);if($('#logTestFilter')?.checked)rows=rows.filter(l=>l.isTest||l.category==='test');return rows;}
function renderLogsRows(rows){return rows.slice().reverse().map(l=>`<tr class="log-row" data-level="${esc(l.level||'audit')}" data-category="${esc(l.category||l.entityType||'system')}" data-telegram="${l.telegramSent?'1':'0'}" data-test="${l.isTest||l.category==='test'?'1':'0'}"><td>${brDate(l.createdAt)}</td><td><span class="badge ${l.level==='critical'||l.level==='error'?'danger':l.level==='security'?'dark':l.level==='warn'?'warn':'success'}">${esc(l.level||'audit')}</span></td><td>${esc(l.category||l.entityType||'')}</td><td>${esc(l.action)}</td><td>${esc(l.companyName||companyName(l.companyId)||'')}</td><td>${esc(l.userEmailMasked||l.userName||'Sistema')}<br><span class="muted">${esc(l.userRole||'')}</span></td><td class="break">${esc(l.message||l.detail||'')}${l.errorMessage?`<br><span class="muted">${esc(l.errorMessage)}</span>`:''}</td><td>${l.telegramSent?'Sim':'Não'}</td></tr>`).join('')||'<tr><td colspan="8">Nenhum log.</td></tr>';}
function filterLogsTable(){const body=$('#logsTableBody');if(body)body.innerHTML=renderLogsRows(getFilteredLogs());}
function exportLogsJson(){const rows=getFilteredLogs().map(l=>window.ValoraLogs?.sanitizeLogMetadata(l)||l);downloadText(`logs-${new Date().toISOString().slice(0,10)}.json`,JSON.stringify({exportedAt:nowIso(),filters:{level:$('#logLevelFilter')?.value||'',category:$('#logCategoryFilter')?.value||''},rows},null,2),'application/json');audit('Exportação de logs JSON','log','global',`${rows.length} registros`);}
function exportLogsCsv(){const rows=getFilteredLogs().map(l=>({createdAt:l.createdAt,level:l.level,category:l.category,action:l.action,company:l.companyName,user:l.userEmailMasked,message:l.message,telegramSent:l.telegramSent}));downloadText(`logs-${new Date().toISOString().slice(0,10)}.csv`,toCsv(rows),'text/csv');audit('Exportação de logs CSV','log','global',`${rows.length} registros`);}
function exportLogsExcel(){const rows=getFilteredLogs().map(l=>({Data:l.createdAt,Nivel:l.level,Categoria:l.category,Acao:l.action,Empresa:l.companyName,Usuario:l.userEmailMasked,Mensagem:l.message,Telegram:l.telegramSent?'sim':'nao'}));downloadText(`logs-${new Date().toISOString().slice(0,10)}.xls`,toCsv(rows),'application/vnd.ms-excel');audit('Exportação de logs Excel compatível','log','global',`${rows.length} registros`);}
function generateTestLog(el){const level=el.dataset.level;window.ValoraLogs?.createSystemLog({level,category:'test',action:`test_${level}`,message:'Este é um log de teste gerado manualmente pelo administrador.',user:currentUser(),isTest:true});save();toast('Log de teste gerado.','success');rerenderPortal();}
function sendTelegramTest(){const l=window.ValoraLogs?.createSystemLog({level:'critical',category:'test',action:'telegram_test',message:'Este é um alerta Telegram de teste gerado manualmente pelo administrador.',user:currentUser(),isTest:true});save();toast('Teste Telegram solicitado via Cloud Function. Verifique os secrets e o chat configurado.', 'success');setTimeout(()=>{save();rerenderPortal();},1200);rerenderPortal();}
function simulateFrontendError(){handleError('simulação de erro frontend',new Error('Erro de frontend simulado pelo administrador.'));rerenderPortal();}
function simulateAccessDenied(){logSecurityEvent({action:'access_denied_test',message:'Simulação de acesso negado pelo administrador.',metadata:{isTest:true}});save();toast('Acesso negado simulado.','success');rerenderPortal();}
function simulateEmailFailure(){window.ValoraLogs?.logError({category:'notification',action:'email_failed_test',message:'Simulação de falha de e-mail.',user:currentUser(),isTest:true});save();toast('Falha de e-mail simulada.','success');rerenderPortal();}
function simulateWebhookFailure(){window.ValoraLogs?.logError({category:'integration',action:'webhook_failed_test',message:'Simulação de falha de webhook.',user:currentUser(),isTest:true});save();toast('Falha de webhook simulada.','success');rerenderPortal();}

function limitRows(companyId){return getLimitStatus(companyId).map(x=>`<div class="usage-row ${x.status}"><div><b>${esc(({maxActiveSurveys:'Pesquisas ativas',maxResponsesMonth:'Respostas/mês',maxManagers:'Gestores',maxEmployees:'Funcionários',maxEmailsMonth:'E-mails/mês'})[x.key]||x.key)}</b><span>${x.used} / ${x.limit<0?'Ilimitado':x.limit} • ${x.status}</span></div><div class="bar"><span style="width:${x.limit<0?0:clamp(x.percent,0,100)}%"></span></div></div>`).join('');}
function companySettingsSection(){const c=currentCompany(),b=getCompanyTheme(c),admin=currentUser()?.role==='admin_valora';return `<form class="card grid" data-form="companySettings"><h3>Dados da empresa e identidade visual</h3><div class="form-grid"><div class="field"><label>Nome público</label><input name="publicName" value="${esc(c?.publicName||c?.name||'')}" required></div><div class="field"><label>Slogan</label><input name="slogan" value="${esc(c?.slogan||'')}"></div><div class="field"><label>Slug público</label><input name="slug" value="${esc(c?.slug||'')}" ${admin?'':'readonly'}><span class="field-help">Usado em ?org=slug. Alteração restrita ao Admin Valora.</span></div><div class="field"><label>URL da logo</label><input name="logoUrl" type="url" value="${esc(b.logoUrl||'')}" placeholder="https://..."></div><div class="field"><label>E-mail de contato</label><input name="contactEmail" type="email" value="${esc(c?.settings?.contactEmail||c?.email||'')}"></div><div class="field"><label>WhatsApp</label><input name="whatsapp" value="${esc(c?.settings?.whatsapp||c?.phone||'')}"></div><div class="field"><label>Contato LGPD</label><input name="lgpdContact" value="${esc(c?.settings?.lgpdContact||c?.email||'')}"></div>${['primaryColor','secondaryColor','accentColor','backgroundColor','textColor'].map(k=>`<div class="field"><label>${esc(k)}</label><input name="${k}" type="color" value="${esc(b[k])}"></div>`).join('')}</div><div class="grid grid-2"><label class="checkline"><input name="useCompanyBrandOnPublicSurvey" type="checkbox" ${b.useCompanyBrandOnPublicSurvey?'checked':''}><span>Usar marca da empresa nas pesquisas públicas</span></label><label class="checkline"><input name="useCompanyBrandOnEmails" type="checkbox" ${b.useCompanyBrandOnEmails?'checked':''}><span>Usar marca da empresa nos e-mails</span></label><label class="checkline"><input name="showPoweredByValora" type="checkbox" ${b.showPoweredByValora?'checked':''}><span>Exibir Powered by Valora</span></label></div>${brandPreview(c)}<div class="confirm-actions"><button type="button" class="btn btn-soft" data-action="restoreBrandDefaults">Restaurar padrão Valora</button><button class="btn btn-primary">Salvar personalização</button></div></form>`;}

function participantAvailable(){return miniSurveysTable(activeSurveysForParticipant(),true);}
function participantResponses(){return miniResponsesTable(responsesForUser(currentUser()),true);}
function participantCertificates(){const rows=responsesForUser(currentUser());return `<div class="grid grid-2">${rows.map(r=>`<div class="card"><span class="badge success">Certificado disponível</span><h3>${esc(surveyTitle(r.surveyId))}</h3><p>${esc(companyName(r.companyId))} • ${brDay(r.createdAt)}</p><p><b>${Number(r.normalized5).toFixed(2)} / 5</b> — ${esc(r.level.label)}</p><div class="table-actions"><button class="btn btn-primary" data-action="certificatePdf" data-id="${r.id}">Baixar certificado</button><button class="btn btn-secondary" data-action="certificatePng" data-id="${r.id}">Baixar certificado em imagem</button><button class="btn btn-soft" data-action="viewResponse" data-id="${r.id}">Ver resultado</button></div></div>`).join('')||'<div class="empty">Nenhum certificado disponível.</div>'}</div>`;}
function participantPrivacy(){return `<div class="grid grid-2"><div class="card"><h3>Meus dados</h3><p>Exporte seu histórico pessoal ou registre uma solicitação de exclusão.</p><div class="table-actions"><button class="btn btn-secondary" data-action="exportMyData">Exportar meus dados</button><button class="btn btn-danger" data-action="requestDeletion">Solicitar exclusão</button></div></div><div class="card"><h3>Termo vigente</h3><div class="legal-preview">${nl2br((state.settings.lgpdText||LGPD_TEXT).slice(0,1200))}…</div><a class="btn btn-soft" href="#lgpd">Ler termo completo</a></div></div>`;}

function openModal(title,body,size='normal'){
  lastFocus=document.activeElement;const layer=$('#modalLayer');layer.innerHTML=`<div class="modal-box ${size}" role="dialog" aria-modal="true" aria-labelledby="modalTitle"><div class="modal-head"><h2 id="modalTitle">${esc(title)}</h2><button class="modal-close" data-action="closeModal" aria-label="Fechar">×</button></div><div class="modal-body">${body}</div></div>`;layer.classList.add('open');layer.setAttribute('aria-hidden','false');document.body.style.overflow='hidden';setTimeout(()=>layer.querySelector('input,select,textarea,button')?.focus(),20);
}
function closeModal(){const layer=$('#modalLayer');layer.classList.remove('open');layer.setAttribute('aria-hidden','true');layer.innerHTML='';document.body.style.overflow='';builderDraft=null;lastFocus?.focus?.();}
function confirmAction(title,message,callback,danger=true,cancelCallback=null){confirmCallback=callback;confirmCancelCallback=cancelCallback;const layer=$('#confirmLayer');layer.innerHTML=`<div class="modal-box small" role="alertdialog" aria-modal="true" aria-labelledby="confirmTitle"><div class="modal-head"><h2 id="confirmTitle">${esc(title)}</h2><button class="modal-close" data-action="closeConfirm" aria-label="Fechar">×</button></div><div class="modal-body"><p>${esc(message)}</p><div class="confirm-actions"><button class="btn btn-soft" data-action="closeConfirm">Cancelar</button><button class="btn ${danger?'btn-danger':'btn-primary'}" data-action="confirmOk">Confirmar</button></div></div></div>`;layer.classList.add('open');layer.setAttribute('aria-hidden','false');setTimeout(()=>layer.querySelector('[data-action="confirmOk"]')?.focus(),20);}
function closeConfirm(cancelled=true){const layer=$('#confirmLayer');const cancel=confirmCancelCallback;layer.classList.remove('open');layer.setAttribute('aria-hidden','true');layer.innerHTML='';confirmCallback=null;confirmCancelCallback=null;if(cancelled&&cancel)cancel();}
function toast(message,type='info'){const zone=$('#toastZone');if(!zone)return;zone.replaceChildren();const t=document.createElement('div');t.className=`toast ${type}`;t.textContent=message;zone.appendChild(t);setTimeout(()=>t.remove(),3400);}
function data(form){const out={};for(const [k,v] of new FormData(form).entries()){if(Object.prototype.hasOwnProperty.call(out,k))out[k]=Array.isArray(out[k])?[...out[k],v]:[out[k],v];else out[k]=v;}return out;}
function persist(message='Alterações salvas.'){save();toast(message,'success');}
function rerenderPortal(){const [scope,tab]=currentRoute.split('/');if(['admin','empresa','participante'].includes(scope))renderPortal(scope,tab||'dashboard');else route(currentRoute);}

function openUserEditor(id=''){
  const actor=currentUser();if(!actor||!can(actor,'canManageCompanyUsers'))return toast(PERMISSION_DENIED_MESSAGE,'error');
  const u=id?state.users.find(x=>x.id===id):null;if(id&&!u)return toast('Usuário não localizado.','error');
  if(actor.role==='empresa_admin'&&u&&u.companyId!==actor.companyId)return toast('Usuário fora do seu ambiente.','error');
  const roles=actor.role==='admin_valora'?Object.keys(ROLE_DEFINITIONS):availableRolesForCompanyUser(actor);
  const companies=actor.role==='admin_valora'?state.companies:state.companies.filter(c=>c.id===actor.companyId);
  const selectedRole=u?.role||(actor.role==='admin_valora'?'participante':'participante');
  openModal(u?'Editar usuário':'Cadastrar usuário',`<form class="grid" data-form="user"><input type="hidden" name="id" value="${esc(u?.id||'')}"><div class="page-help"><b>Dados pessoais.</b> Informe contato, cargo e empresa. No modo Firebase, a senha inicial deve virar convite seguro/Firebase Auth; no modo local/demo ela cria a credencial local.</div><div class="form-grid"><div class="field"><label>Nome</label><input name="name" value="${esc(u?.name||'')}" required spellcheck="true"></div><div class="field"><label>E-mail</label><input name="email" type="email" value="${esc(u?.email||'')}" required></div><div class="field"><label>Telefone</label><input name="phone" value="${esc(u?.phone||'')}"></div><div class="field"><label>Cargo ou função</label><input name="position" value="${esc(u?.position||u?.jobTitle||'')}"></div><div class="field"><label>Área/departamento</label><input name="department" value="${esc(u?.department||u?.area||'')}"></div><div class="field"><label>Perfil de acesso</label><select name="role" data-change="roleExplain">${roles.map(r=>`<option value="${r}" ${selectedRole===r?'selected':''}>${esc(ROLE_LABELS[r])}</option>`).join('')}</select></div><div class="field"><label>Empresa</label><select name="companyId" ${actor.role!=='admin_valora'?'disabled':''}><option value="">Valora Group / sem empresa</option>${companies.map(c=>`<option value="${c.id}" ${(u?.companyId||actor.companyId)===c.id?'selected':''}>${esc(c.name)}</option>`).join('')}</select></div><div class="field"><label>Status</label><select name="status"><option value="active" ${u?.status!=='inactive'?'selected':''}>Ativo</option><option value="inactive" ${u?.status==='inactive'?'selected':''}>Inativo</option></select></div><label class="checkline"><input name="receivesEmail" type="checkbox" ${u?.receivesEmail!==false?'checked':''}><span>Recebe e-mail de pesquisas</span></label><label class="checkline"><input name="portalAccess" type="checkbox" ${u?.portalAccess!==false?'checked':''}><span>Pode acessar portal</span></label><div class="field span-2"><label>${u?'Nova senha (deixe em branco para manter)':'Senha inicial (local/demo)'}</label><input name="password" type="password" ${u?'':'required minlength="6"'} autocomplete="new-password"></div><div class="field span-2"><label>Observações internas</label><textarea name="notes">${esc(u?.notes||'')}</textarea></div></div><div id="roleExplainBox">${roleHint(selectedRole)}</div><div class="confirm-actions"><button type="button" class="btn btn-soft" data-action="closeModal">Cancelar</button><button class="btn btn-primary">Salvar usuário</button></div></form>`,'large');
}

function sanitizeCreateErrorCode(err){return String(err?.code||err?.message||'unknown_error').toLowerCase().replace(/[^a-z0-9_-]+/g,'_').slice(0,80)||'unknown_error';}
function validateEmailValue(v){return !v||/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(String(v).trim());}
function validateDocumentValue(v){return !v||onlyDigits(v).length>=11;}
function buildClientPayload(fd,existing=null){const actor=currentUser();const baseSlug=normalizeSlug(fd.slug||fd.name||fd.legalName||'cliente');return {id:existing?.id||fd.id||'',type:fd.type||existing?.type||'juridica',name:String(fd.name||'').trim(),legalName:String(fd.legalName||fd.name||'').trim(),document:String(fd.document||'').trim(),email:String(fd.email||'').trim().toLowerCase(),phone:String(fd.phone||'').trim(),responsibleName:String(fd.responsibleName||fd.adminName||'').trim(),responsibleEmail:String(fd.responsibleEmail||fd.adminEmail||'').trim().toLowerCase(),planId:fd.planId||defaultPlan()?.id||'free',status:fd.status||'active',slug:baseSlug,cep:fd.cep||'',address:fd.address||'',companyId:existing?.companyId||existing?.id||'',organizationId:existing?.organizationId||existing?.id||'',subscription:{...(existing?.subscription||{}),planId:fd.planId||defaultPlan()?.id||'free',status:fd.status||'active',billingStatus:fd.status==='overdue'?'overdue':(existing?.subscription?.billingStatus||'open'),startedAt:existing?.subscription?.startedAt||nowIso()},updatedAt:nowIso(),updatedBy:actor?.id||actor?.uid||'',createdAt:existing?.createdAt||nowIso(),createdBy:existing?.createdBy||actor?.id||actor?.uid||'',source:'legacy_admin',isDeleted:false};}
function validateClientPayload(payload){if(!payload.name)return 'name_required';if(!validateEmailValue(payload.email)||!validateEmailValue(payload.responsibleEmail))return 'invalid_email';if(!validateDocumentValue(payload.document))return 'invalid_document';if(['survey_demo','empresa-exemplo','cliente-demo'].includes(payload.slug))return 'demo_client_blocked';return '';}
async function saveClientViaCloudFunction(payload){return repository.createClient(payload);}
async function saveClientViaFirebase(payload){return repository.createClient?repository.createClient(payload):repository.createOrganization(payload);}
async function saveClientViaApi(payload){if(!window.ValoraApiRepository?.createClient)throw Object.assign(new Error('api_unavailable'),{code:'api_unavailable'});return window.ValoraApiRepository.createClient(payload);}
async function saveClientAuto(payload){try{return await saveClientViaCloudFunction(payload);}catch(err){if(String(err?.code||err?.message).includes('permission'))throw err;try{return await saveClientViaFirebase(payload);}catch(err2){return saveClientViaApi(payload).catch(()=>{throw err2;});}}}
async function listClientsAuto(){return repository.listOrganizations?repository.listOrganizations():state.companies;}
function renderClientForm(client=null){openCompanyEditor(client?.id||'');}
function bindClientFormEvents(){return true;}
async function handleClientSubmit(form){return saveCompany(form);}
function renderClientsPage(){rerenderPortal();}
async function saveCompany(form){const fd=data(form),existing=fd.id?companyById(fd.id):null,actor=currentUser();if(actor?.role!=='admin_valora')return toast(PERMISSION_DENIED_MESSAGE,'error');const payload=buildClientPayload(fd,existing);const validation=validateClientPayload(payload);if(validation)return toast(`Não foi possível cadastrar o cliente. Código: ${validation}`,'error');const btn=form.querySelector('button[type="submit"],button.btn-primary');const old=btn?.textContent;if(btn){btn.disabled=true;btn.textContent='Salvando...';}try{let saved;if(existing){saved=await (repository.updateClient?repository.updateClient(existing.id,payload):repository.updateOrganization(existing.id,payload));Object.assign(existing,payload,saved||{});audit('Cliente editado','empresa',existing.id,existing.name);}else{saved=await saveClientAuto(payload);const id=saved?.id||payload.id||uid('org');const c=normalizeOrganization({...payload,id,companyId:id,organizationId:id});if(!state.companies.some(x=>x.id===id))state.companies.push(c);createInvoiceForCompany(c);audit('Cliente cadastrado','empresa',id,c.name);if(fd.createAdmin){await saveUserAuto({name:fd.adminName,email:fd.adminEmail,phone:fd.adminPhone||'',position:fd.adminPosition||'Administrador da Empresa',role:'empresa_admin',companyId:id,organizationId:id,status:'active',sendInvite:!!fd.sendInvite,createdBy:actor.id||actor.uid});}}
toast(existing?'Cliente salvo.':'Cliente cadastrado com sucesso.','success');closeModal();await repository.loadStoreFromFirestore?.().then(()=>Object.assign(state,window.ValoraFirebaseRepository?.loadStore({seedStore,normalizeState})||state)).catch(()=>{});rerenderPortal();}catch(err){const code=sanitizeCreateErrorCode(err);window.ValoraLogger?.warn?.({category:'company',action:'legacy_client_create_failed',message:'Falha sanitizada ao cadastrar cliente.',metadata:{code},user:actor});toast(`Não foi possível cadastrar o cliente. Código: ${code}`,'error');}finally{if(btn){btn.disabled=false;btn.textContent=old;}}}
function validateUserPayload(payload){if(!String(payload.name||'').trim())return 'name_required';if(!validateEmailValue(payload.email))return 'invalid_email';if(!payload.role)return 'role_required';if(!GLOBAL_ROLES.includes(payload.role)&&!(payload.companyId||payload.organizationId))return 'company_required';if(payload.temporaryPassword)return 'temporary_password_not_persisted';return '';}
async function saveUserViaCloudFunction(payload){return repository.createUser(payload);}
async function saveUserViaFirebase(payload){return repository.createUser?repository.createUser(payload):repository.createUserProfile(payload);}
async function saveUserViaApi(payload){if(!window.ValoraApiRepository?.createUser)throw Object.assign(new Error('api_unavailable'),{code:'api_unavailable'});return window.ValoraApiRepository.createUser(payload);}
async function saveUserAuto(payload){try{return await saveUserViaCloudFunction(payload);}catch(err){try{return await saveUserViaFirebase(payload);}catch(err2){return saveUserViaApi(payload).catch(()=>{throw err2;});}}}
async function listUsersAuto(){return repository.listUsers?repository.listUsers():state.users;}
function renderUserForm(user=null){openUserEditor(user?.id||'');}
function bindUserFormEvents(){return true;}
