function renderUsersPage(){rerenderPortal();}
async function saveUser(form){const actor=currentUser(),fd=data(form),existing=fd.id?state.users.find(u=>u.id===fd.id):null;if(!can(actor,'canManageCompanyUsers'))return toast(PERMISSION_DENIED_MESSAGE,'error');if(existing&&existing.id===actor.id&&existing.role!==fd.role)return toast('Usuário não pode alterar o próprio perfil.','error');if(!canCreateUserWithRole(actor,fd.role))return toast('Perfil não permitido para seu usuário.','error');if(actor.role==='empresa_admin'){fd.companyId=actor.companyId;if(existing&&existing.companyId!==actor.companyId)return toast('Usuário fora do seu ambiente.','error');}const payload={name:String(fd.name||'').trim(),email:String(fd.email||'').trim().toLowerCase(),phone:fd.phone||'',position:fd.position||'',department:fd.department||'',role:fd.role,companyId:fd.companyId||'',organizationId:fd.companyId||'',status:fd.status||'active',sendInvite:!!fd.sendInvite,receivesEmail:!!fd.receivesEmail,portalAccess:!!fd.portalAccess,notes:fd.notes||'',type:['participante','convidado_externo'].includes(fd.role)?'funcionario':'usuario',updatedAt:nowIso(),updatedBy:actor.id||actor.uid||'',createdAt:existing?.createdAt||nowIso(),createdBy:existing?.createdBy||actor.id||actor.uid||'',source:'legacy_admin'};const validation=validateUserPayload(payload);if(validation)return toast(`Não foi possível cadastrar o usuário. Código: ${validation}`,'error');if(state.users.some(u=>u.id!==fd.id&&u.email.toLowerCase()===payload.email))return toast('Já existe um usuário com este e-mail.','error');const btn=form.querySelector('button[type="submit"],button.btn-primary');const old=btn?.textContent;if(btn){btn.disabled=true;btn.textContent='Salvando...';}try{if(existing){const saved=await (repository.updateUserProfile?repository.updateUserProfile(existing.id,payload):Promise.resolve(payload));Object.assign(existing,payload,saved||{});audit('Usuário editado','usuário',existing.id,existing.email);}else{const saved=await saveUserAuto(payload);const id=saved?.uid||saved?.id||uid('u');const row={id,uid:saved?.uid||id,...payload,status:saved?.status||payload.status||'pending_invite',inviteStatus:saved?.inviteStatus||(saved?.uid?'sent':'pending_invite')};state.users.push(row);audit('Usuário criado','usuário',id,`${row.email} • ${row.role}`);}toast(existing?'Usuário salvo.':'Usuário cadastrado com sucesso.','success');closeModal();rerenderPortal();}catch(err){const code=sanitizeCreateErrorCode(err);window.ValoraLogger?.warn?.({category:'user',action:'legacy_user_create_failed',message:'Falha sanitizada ao cadastrar usuário.',metadata:{code},user:actor});toast(`Não foi possível cadastrar o usuário. Código: ${code}`,'error');}finally{if(btn){btn.disabled=false;btn.textContent=old;}}}
function deleteUser(id){
  const actor=currentUser(),u=state.users.find(x=>x.id===id);if(!u)return;if(!['admin_valora','empresa_admin'].includes(actor?.role))return toast(PERMISSION_DENIED_MESSAGE,'error');if(actor.role==='empresa_admin'&&u.companyId!==actor.companyId)return toast('Usuário fora do seu ambiente.','error');if(u.id===actor.id)return toast('Você não pode excluir o próprio usuário conectado.','error');
  confirmAction('Excluir usuário?',`O acesso de ${u.name} será removido.`,()=>{state.users=state.users.filter(x=>x.id!==id);audit('Usuário excluído','usuário',id,u.email);persist('Usuário excluído.');rerenderPortal();});
}

function openCompanyEditor(id=''){
  if(currentUser()?.role!=='admin_valora')return toast('Apenas o administrador geral pode cadastrar clientes.','error');const c=id?companyById(id):null;const hasAdmin=c?state.users.some(u=>u.companyId===c.id&&u.role==='empresa_admin'&&u.status==='active'):false;
  openModal(c?'Editar cliente':'Cadastrar cliente',`<form class="grid" data-form="company"><input type="hidden" name="id" value="${esc(c?.id||'')}">${c&&!hasAdmin?'<div class="danger-box"><b>Esta empresa ainda não possui administrador.</b><br>Cadastre um responsável para liberar o uso.</div>':''}<div class="form-grid"><div class="field"><label>Tipo</label><select name="type"><option value="juridica" ${c?.type!=='fisica'?'selected':''}>Empresa / CNPJ</option><option value="fisica" ${c?.type==='fisica'?'selected':''}>Pessoa física</option></select></div><div class="field"><label>CNPJ ou CPF</label><div class="inline-field"><input name="document" value="${esc(c?.document||'')}"><button type="button" class="btn btn-soft btn-mini" data-action="lookupCnpj">Buscar CNPJ</button></div></div><div class="field"><label>Nome / razão social</label><input name="name" value="${esc(c?.name||'')}" required spellcheck="true"></div><div class="field"><label>E-mail</label><input name="email" type="email" value="${esc(c?.email||'')}"></div><div class="field"><label>Telefone</label><input name="phone" value="${esc(c?.phone||'')}"></div><div class="field"><label>Plano</label><select name="planId" required>${publicPlans().map(p=>`<option value="${p.id}" ${(c?.planId||defaultPlan()?.id)===p.id?'selected':''}>${esc(p.name)} — ${p.price?money(p.price):'Grátis'}</option>`).join('')}</select></div><div class="field"><label>CEP</label><div class="inline-field"><input name="cep" value="${esc(c?.cep||'')}"><button type="button" class="btn btn-soft btn-mini" data-action="lookupCep">Buscar CEP</button></div></div><div class="field"><label>Status inicial da empresa</label><select name="status">${['trial','active','overdue','suspended','cancelled','inactive'].map(st=>`<option value="${st}" ${(c?.subscription?.status||c?.status||'active')===st?'selected':''}>${SUBSCRIPTION_STATUS_LABELS[st]||st}</option>`).join('')}</select></div><div class="field span-2"><label>Endereço</label><input name="address" value="${esc(c?.address||'')}"></div></div><div class="card"><h3>Administrador principal da empresa</h3><p class="muted">Perfil fixo: Administrador da Empresa. Em Firebase, preparar criação por Firebase Auth ou convite seguro; em local/demo, a senha inicial cria usuário local.</p><label class="checkline"><input name="createAdmin" type="checkbox" ${c?'':'checked'}><span>${c?'Criar novo administrador para esta empresa':'Criar administrador junto com o cliente'}</span></label><div class="form-grid"><div class="field"><label>Nome do administrador</label><input name="adminName"></div><div class="field"><label>E-mail</label><input name="adminEmail" type="email"></div><div class="field"><label>Telefone</label><input name="adminPhone"></div><div class="field"><label>Cargo</label><input name="adminPosition" value="Administrador da Empresa"></div><div class="field"><label>Senha inicial (local/demo)</label><input name="adminPassword" type="password" minlength="6"></div><label class="checkline"><input name="sendInvite" type="checkbox" checked><span>Enviar convite de acesso por e-mail</span></label></div></div><div class="confirm-actions"><button type="button" class="btn btn-soft" data-action="closeModal">Cancelar</button><button class="btn btn-primary">Salvar cliente</button></div></form>`,'large');
}

function deleteCompany(id){const c=companyById(id);if(!c||currentUser()?.role!=='admin_valora')return;confirmAction('Excluir cliente?',`Excluir ${c.name}, usuários, formulários e pesquisas do ambiente? As respostas também serão removidas.`,()=>{state.companies=state.companies.filter(x=>x.id!==id);state.users=state.users.filter(x=>x.companyId!==id);const surveyIds=state.surveys.filter(s=>s.companyId===id).map(s=>s.id);state.forms=state.forms.filter(f=>f.global||f.companyId!==id);state.surveys=state.surveys.filter(s=>s.companyId!==id);state.responses=state.responses.filter(r=>!surveyIds.includes(r.surveyId));state.invoices=state.invoices.filter(i=>i.companyId!==id);audit('Cliente excluído','empresa',id,c.name);persist('Cliente excluído.');rerenderPortal();});}
function impersonateCompany(id){const c=companyById(id),u=state.users.find(x=>x.companyId===id&&x.role==='empresa_admin');if(!c)return;if(!u)return toast('Cadastre um administrador para esta empresa.','warn');state.session={userId:u.id,impersonatedBy:currentUser()?.id,createdAt:nowIso()};audit('Ambiente aberto pelo administrador','empresa',id,c.name);save();navigate('empresa/dashboard');}

function openInvoiceEditor(id=''){if(currentUser()?.role!=='admin_valora')return toast(PERMISSION_DENIED_MESSAGE,'error');const i=id?normalizeInvoice(state.invoices.find(x=>x.id===id)||{}):null;openModal(i?'Editar fatura':'Nova fatura',`<form class="grid" data-form="invoice"><input type="hidden" name="id" value="${esc(i?.id||'')}"><div class="form-grid"><div class="field"><label>Cliente</label><select name="companyId">${state.companies.map(c=>`<option value="${c.id}" ${i?.companyId===c.id?'selected':''}>${esc(c.name)}</option>`).join('')}</select></div><div class="field"><label>Descrição</label><input name="description" value="${esc(i?.description||'Assinatura Valora Pulse')}"></div><div class="field"><label>Valor</label><input name="amount" type="number" min="0" step="0.01" value="${esc(i?.amount||0)}" required></div><div class="field"><label>Vencimento</label><input name="dueDate" type="date" value="${dateInput(i?.dueDate||i?.dueAt||datePlus(30))}" required></div><div class="field"><label>Status</label><select name="status">${['draft','open','pending','paid','overdue','cancelled','refunded','failed'].map(st=>`<option value="${st}" ${i?.status===st?'selected':''}>${subscriptionLabel(st)}</option>`).join('')}</select></div><div class="field"><label>Link externo de pagamento</label><input name="paymentUrl" type="url" value="${esc(i?.paymentUrl||'')}"></div><div class="field span-2"><label>Observações financeiras</label><textarea name="notes">${esc(i?.notes||'')}</textarea></div></div><div class="confirm-actions"><button type="button" class="btn btn-soft" data-action="closeModal">Cancelar</button><button class="btn btn-primary">Salvar fatura</button></div></form>`,'large');}
function saveInvoice(form){const fd=data(form),existing=fd.id?state.invoices.find(x=>x.id===fd.id):null,c=companyById(fd.companyId),plan=planById(c?.planId),due=new Date(`${fd.dueDate}T12:00:00`).toISOString();const payload=normalizeInvoice({...(existing||{}),companyId:fd.companyId,organizationId:fd.companyId,planId:c?.planId||'',subscriptionId:c?.id||'',description:fd.description,amount:Number(fd.amount),currency:'BRL',status:fd.status,dueDate:due,dueAt:due,paymentUrl:fd.paymentUrl||'',notes:fd.notes||'',customerName:c?.name||'',customerEmail:c?.email||'',customerDocument:c?.document||'',items:[{description:fd.description||`Plano ${plan?.name||''}`,quantity:1,unitPrice:Number(fd.amount),total:Number(fd.amount)}],updatedAt:nowIso(),updatedBy:currentUser()?.id||''});if(existing){Object.assign(existing,payload);audit('Fatura editada','fatura',existing.id,companyName(existing.companyId));}else{payload.id=uid('inv');payload.createdAt=nowIso();payload.createdBy=currentUser()?.id||'';state.invoices.push(payload);audit('Fatura criada','fatura',payload.id,companyName(payload.companyId));}persist('Fatura salva.');closeModal();rerenderPortal();}
function markInvoicePaid(id){const i=state.invoices.find(x=>x.id===id);if(!i||currentUser()?.role!=='admin_valora')return;Object.assign(i,{status:'paid',paidAt:nowIso(),updatedAt:nowIso(),updatedBy:currentUser()?.id});const c=companyById(i.companyId);if(c)c.subscription={...(c.subscription||{}),status:'active',billingStatus:'paid'};audit('Fatura paga','fatura',id,companyName(i.companyId));persist('Pagamento registrado.');rerenderPortal();}
function cancelInvoice(id){const i=state.invoices.find(x=>x.id===id);if(!i||currentUser()?.role!=='admin_valora')return;Object.assign(i,{status:'cancelled',cancelledAt:nowIso(),updatedAt:nowIso(),updatedBy:currentUser()?.id});audit('Fatura cancelada','fatura',id,companyName(i.companyId));persist('Fatura cancelada.');rerenderPortal();}
