function openKnowledgeArticleModal(id=''){const article=id?(state.knowledgeBase||[]).find(a=>a.id===id):normalizeKnowledgeArticle({category:'primeiros_passos',audience:'public',published:true});if(!article)return toast('Artigo não encontrado.','error');openModal(id?'Editar artigo da base':'Novo artigo da base',`<form class="grid" data-form="knowledgeArticle"><input type="hidden" name="id" value="${esc(article.id||'')}"><div class="form-grid"><div class="field"><label>Título</label><input name="title" value="${esc(article.title||'')}" required spellcheck="true"></div><div class="field"><label>Categoria</label><select name="category">${['primeiros_passos','planos_precos','diagnostico_valora_insight','resultado_devolutiva','certificado_relatorio','pesquisa_publica','portal_empresa','portal_participante','suporte','privacidade_lgpd'].map(c=>`<option value="${c}" ${article.category===c?'selected':''}>${c}</option>`).join('')}</select></div><div class="field"><label>Público</label><select name="audience"><option value="public" ${article.audience==='public'?'selected':''}>Público</option><option value="private" ${article.audience==='private'?'selected':''}>Interno/logado</option><option value="admin" ${article.audience==='admin'?'selected':''}>Admin Valora</option></select></div><label class="checkline"><input name="published" type="checkbox" ${article.published!==false?'checked':''}><span>Publicado</span></label><div class="field"><label>Palavras-chave</label><input name="tags" value="${esc((article.tags||[]).join(', '))}" placeholder="planos, certificado, LGPD"></div><div class="field"><label>Rotas relacionadas</label><input name="relatedRoutes" value="${esc((article.relatedRoutes||[]).join(', '))}" placeholder="plans, empresa/reports"></div></div><div class="field"><label>Resumo</label><textarea name="summary" spellcheck="true">${esc(article.summary||'')}</textarea></div><div class="field"><label>Conteúdo</label><textarea name="content" required spellcheck="true" style="min-height:180px">${esc(article.content||'')}</textarea></div><div class="confirm-actions"><button type="button" class="btn btn-soft" data-action="closeModal">Cancelar</button><button class="btn btn-primary">Salvar artigo</button></div></form>`,'large');}
function saveKnowledgeArticle(form){const fd=data(form);const tags=String(fd.tags||'').split(',').map(x=>x.trim()).filter(Boolean);const relatedRoutes=String(fd.relatedRoutes||'').split(',').map(x=>x.trim()).filter(Boolean);const payload=normalizeKnowledgeArticle({id:fd.id||uid('kb'),title:fd.title,category:fd.category,audience:fd.audience,summary:fd.summary,content:fd.content,tags,relatedRoutes,published:!!fd.published,updatedAt:nowIso()});const i=(state.knowledgeBase||[]).findIndex(a=>a.id===payload.id);if(i>=0)state.knowledgeBase[i]={...state.knowledgeBase[i],...payload};else state.knowledgeBase.push({...payload,createdAt:nowIso()});persist('Artigo da base de conhecimento salvo.');closeModal();rerenderPortal();}
function toggleKnowledgeArticle(el){const a=(state.knowledgeBase||[]).find(x=>x.id===el.dataset.id);if(!a)return;a.published=!a.published;a.updatedAt=nowIso();persist(a.published?'Artigo publicado.':'Artigo despublicado.');rerenderPortal();}
function deleteKnowledgeArticle(el){const id=el.dataset.id;state.knowledgeBase=(state.knowledgeBase||[]).filter(a=>a.id!==id);persist('Artigo removido.');rerenderPortal();}
function supportCategory(id){return (state.supportCategories||defaultSupportCategories()).find(c=>c.id===id)||defaultSupportCategories().find(c=>c.id==='outros');}
function supportSlaFor(priority){return (state.supportSlaPolicies||defaultSupportSlaPolicies()).find(p=>p.priority===priority&&p.active!==false)||defaultSupportSlaPolicies().find(p=>p.priority==='medium');}
function calculateSlaDueAt(priority,createdAt=nowIso()){const p=supportSlaFor(priority);return new Date(toDateValue(createdAt).getTime()+Number(p.resolutionHours||48)*3600000).toISOString();}
function slaStatus(c){if(['resolved','closed','cancelled'].includes(c.status))return 'dentro do prazo';const due=toDateValue(c.slaDueAt||c.createdAt);const mins=(due-Date.now())/60000;if(mins<0)return 'vencido';if(mins<120)return 'próximo do vencimento';return 'dentro do prazo';}
function routeSupportTicket(ticket){const cat=supportCategory(ticket.category);if(cat?.id==='erro_tecnico')ticket.priority='high';if(cat?.id==='financeiro'||cat?.id==='plano_assinatura')ticket.assignedToRole='admin_valora';if(ticket.companyId){const agent=(state.users||[]).find(u=>u.companyId===ticket.companyId&&u.status!=='inactive'&&can(u,'canHandleSupport'));if(agent){ticket.assignedToUserId=agent.id;ticket.assignedToName=agent.name;ticket.assignedToRole=agent.role;ticket.status='in_progress';}else ticket.status=ticket.priority==='critical'?'waiting_agent':'open';}else ticket.status='waiting_agent';return ticket;}
function normalizeSupportConversation(c={}){const category=c.category||'outros',cat=supportCategory(category),priority=c.priority==='normal'?'medium':(c.priority||cat?.defaultPriority||'medium'),created=c.createdAt||nowIso();return {id:c.id||uid('sup'),companyId:c.companyId||currentUser()?.companyId||'',companyName:c.companyName||companyName(c.companyId||currentUser()?.companyId)||'',requesterUserId:c.requesterUserId||currentUser()?.id||'',requesterName:c.requesterName||currentUser()?.name||'',requesterEmail:c.requesterEmail||currentUser()?.email||'',requesterRole:c.requesterRole||currentUser()?.role||'public',requesterType:c.requesterType||c.origin||'public',assignedToUserId:c.assignedToUserId||'',assignedToName:c.assignedToName||'',assignedToRole:c.assignedToRole||'',subject:c.subject||'Atendimento',description:c.description||'',category,priority,status:c.status||'open',origin:c.origin||'manual',channel:c.channel||'web',relatedEntity:c.relatedEntity||'',relatedEntityId:c.relatedEntityId||'',relatedSurveyId:c.relatedSurveyId||'',relatedResponseId:c.relatedResponseId||'',relatedRoute:c.relatedRoute||currentRoute,slaPolicyId:c.slaPolicyId||cat?.defaultSlaPolicyId||supportSlaFor(priority).id,slaDueAt:c.slaDueAt||calculateSlaDueAt(priority,created),firstResponseAt:c.firstResponseAt||'',resolvedAt:c.resolvedAt||'',closedAt:c.closedAt||'',lastMessageAt:c.lastMessageAt||created,unreadForRequester:c.unreadForRequester||0,unreadForAgent:c.unreadForAgent||0,rating:c.rating||0,ratingComment:c.ratingComment||'',ratedAt:c.ratedAt||'',createdAt:created,updatedAt:c.updatedAt||created,createdBy:c.createdBy||currentUser()?.id||'public',updatedBy:c.updatedBy||'',metadata:c.metadata||{route:currentRoute}};}
function canSeeSupport(c,u=currentUser()){if(!u)return !c.requesterUserId&&c.origin==='public';if(can(u,'canHandleGlobalSupport'))return true;if(can(u,'canHandleSupport')&&u.companyId===c.companyId)return true;if(u.role==='gestor_pesquisa'&&u.companyId===c.companyId&&c.relatedSurveyId)return true;return c.requesterUserId===u.id;}
function supportMessages(id,includeInternal=false){state.supportMessages=state.supportMessages||[];return state.supportMessages.filter(m=>m.conversationId===id||m.ticketId===id).filter(m=>includeInternal||!m.internal);}
function openSupportChat(){audit('Atendimento humano aberto','jornada_publica','','Solicitação de atendimento');const u=currentUser(),ctx=publicJourneyContext();const catOpts=(state.supportCategories||defaultSupportCategories()).map(c=>`<option value="${esc(c.id)}">${esc(c.label)}</option>`).join('');if(!u)return openModal('Falar com atendente',`<form data-form="publicSupport" class="grid"><div class="field"><label>Nome</label><input name="name" required></div><div class="field"><label>E-mail</label><input name="email" type="email" required></div><div class="field"><label>Categoria</label><select name="category">${catOpts}</select></div><div class="field"><label>Assunto</label><input name="subject" required></div><div class="field"><label>Mensagem</label><textarea name="message" required></textarea></div><button class="btn btn-primary">Abrir atendimento</button></form>`,'small');openModal('Novo atendimento',`<form data-form="loggedSupport" class="grid"><div class="page-help">Usaremos seu perfil (${esc(ROLE_LABELS[u.role]||u.role)}), e-mail e empresa automaticamente.</div><div class="field"><label>Categoria</label><select name="category">${catOpts}</select></div><div class="field"><label>Prioridade</label><select name="priority"><option value="low">Baixa</option><option value="medium" selected>Média</option><option value="high">Alta</option><option value="critical">Crítica</option></select></div><div class="field"><label>Assunto</label><input name="subject" required></div><div class="field"><label>Mensagem</label><textarea name="message" required></textarea></div><button class="btn btn-primary">Abrir atendimento</button></form>`,'small');}
function createSupportConversation(data0){state.supportTickets=state.supportTickets||state.supportConversations||[];state.supportMessages=state.supportMessages||[];const c=routeSupportTicket(normalizeSupportConversation(data0));state.supportTickets.push(c);state.supportConversations=state.supportTickets;window.ValoraLogger?.info({category:'support_chat',action:'ticket_created',message:'Ticket de suporte aberto.',companyId:c.companyId,metadata:{ticketId:c.id,origin:c.origin,category:c.category,priority:c.priority}});save();return c;}
function savePublicSupport(form){const fd=data(form),ctx=publicJourneyContext(),cat=supportCategory(fd.category);const c=createSupportConversation({requesterName:fd.name,requesterEmail:fd.email,requesterType:'public',origin:isPublicSurveyPage()?'public_survey':'portal',channel:'web',companyId:ctx.company?.id||'',companyName:ctx.companyName,category:fd.category,priority:cat?.defaultPriority||'medium',subject:fd.subject,description:fd.message,relatedEntity:isPublicSurveyPage()?'survey':'',relatedSurveyId:ctx.survey?.id||'',relatedRoute:location.hash||location.search});sendSupportMessage(c.id,fd.message,'requester');closeModal();renderSupportChat(c.id);toast('Atendimento aberto com sucesso. Um atendente responderá por aqui.','success');}
function saveLoggedSupport(form){const fd=data(form),u=currentUser(),cat=supportCategory(fd.category);const c=createSupportConversation({requesterName:u.name,requesterEmail:u.email,requesterUserId:u.id,requesterRole:u.role,requesterType:getRoleDefinition(u.role).scope==='participante'?'participant':(GLOBAL_ROLES.includes(u.role)?'valora_user':'company_user'),companyId:u.companyId,category:fd.category,priority:fd.priority||cat?.defaultPriority,origin:'portal',channel:'web',subject:fd.subject,description:fd.message,relatedRoute:currentRoute});sendSupportMessage(c.id,fd.message,'requester');closeModal();renderSupportChat(c.id);toast('Atendimento aberto com sucesso. Um atendente responderá por aqui.','success');}
function renderSupportChat(id){const c=(state.supportTickets||state.supportConversations||[]).find(x=>x.id===id);if(!c||!canSeeSupport(c))return toast('Você não tem acesso a esta conversa.','error');const agent=can(currentUser(),'canHandleSupport')||can(currentUser(),'canHandleGlobalSupport'),msgs=supportMessages(id,agent);openModal('Atendimento',`<div class="page-help"><b>Ticket:</b> ${esc(c.id)} • <b>Status:</b> ${esc(SUPPORT_STATUS_LABELS[c.status]||c.status)} • <b>SLA:</b> ${esc(slaStatus(c))} (${brDate(c.slaDueAt)})<br><b>Categoria:</b> ${esc(supportCategory(c.category)?.label||c.category)} • <b>Prioridade:</b> ${esc(SUPPORT_PRIORITY_LABELS[c.priority]||c.priority)} • ${c.assignedToName?`Atendente: ${esc(c.assignedToName)}`:'Fila aguardando responsável.'}</div><div class="support-thread">${msgs.map(m=>`<div class="bot-msg ${m.senderType==='agent'?'me':''} ${m.internal?'internal-note':''}"><b>${esc(m.senderName||m.senderType)}${m.internal?' • nota interna':''}</b><br>${nl2br(m.message)}<small>${brDate(m.createdAt)}</small></div>`).join('')||'<div class="empty">Nenhuma mensagem ainda.</div>'}</div><form data-form="supportMessage" class="bot-input"><input type="hidden" name="conversationId" value="${esc(id)}"><input name="message" required placeholder="Digite sua mensagem"><button class="btn btn-primary btn-mini">Enviar</button></form>${agent?`<form data-form="supportInternalNote" class="bot-input"><input type="hidden" name="conversationId" value="${esc(id)}"><input name="message" required placeholder="Nota interna (não visível ao solicitante)"><button class="btn btn-soft btn-mini">Nota</button></form>`:''}<div class="confirm-actions">${agent?`<button class="btn btn-soft" data-action="assignSupportConversation" data-id="${esc(id)}">Assumir</button><button class="btn btn-secondary" data-action="resolveSupportConversation" data-id="${esc(id)}">Resolver</button>`:''}<button class="btn btn-soft" data-action="closeModal">Fechar</button><button class="btn btn-secondary" data-action="closeSupportConversation" data-id="${esc(id)}">Encerrar</button>${c.status==='closed'&&!agent&&!c.rating?`<button class="btn btn-primary" data-action="rateSupportConversation" data-id="${esc(id)}">Avaliar</button>`:''}</div>`,'large');}
function sendSupportMessage(id,message,senderType='requester',internal=false){const c=(state.supportTickets||state.supportConversations||[]).find(x=>x.id===id);if(!c||!canSeeSupport(c))return toast('Conversa não disponível.','error');const u=currentUser?.(),isAgent=senderType==='agent'||can(u,'canHandleSupport')||can(u,'canHandleGlobalSupport'),m={id:uid('msg'),ticketId:id,conversationId:id,companyId:c.companyId,senderType:internal?'agent':(isAgent?'agent':'requester'),senderUserId:u?.id||'',senderName:u?.name||c.requesterName||'Visitante',senderRole:u?.role||'public',message:String(message||'').slice(0,2000),attachments:[],internal:!!internal,createdAt:nowIso(),readAt:''};state.supportMessages.push(m);if(isAgent&&!c.firstResponseAt)c.firstResponseAt=nowIso();Object.assign(c,{updatedAt:nowIso(),lastMessageAt:nowIso(),status:internal?c.status:(isAgent?'waiting_user':'waiting_agent'),unreadForRequester:isAgent?1:c.unreadForRequester,unreadForAgent:isAgent?c.unreadForAgent:1});window.ValoraLogger?.info({category:'support_chat',action:internal?'internal_note_added':'message_sent',message:'Mensagem de atendimento registrada.',companyId:c.companyId,metadata:{ticketId:id,senderType:m.senderType,internal:!!internal}});save();return m;}
function saveSupportMessage(form){const fd=data(form);sendSupportMessage(fd.conversationId,fd.message);renderSupportChat(fd.conversationId);}function saveSupportInternalNote(form){const fd=data(form);sendSupportMessage(fd.conversationId,fd.message,'agent',true);renderSupportChat(fd.conversationId);}
function supportSection(){const u=currentUser();let rows=(state.supportTickets||state.supportConversations||[]).filter(c=>canSeeSupport(c,u));const k={open:rows.filter(c=>c.status==='open').length,waiting:rows.filter(c=>c.status==='waiting_agent').length,progress:rows.filter(c=>c.status==='in_progress').length,overdue:rows.filter(c=>slaStatus(c)==='vencido').length,critical:rows.filter(c=>c.priority==='critical').length,resolvedToday:rows.filter(c=>c.resolvedAt&&String(c.resolvedAt).slice(0,10)===nowIso().slice(0,10)).length,sat:avg(rows.filter(c=>c.rating).map(c=>c.rating)).toFixed(1)};return `<div class="section-toolbar"><div><h3>Atendimentos</h3><p class="muted">Fila, tickets, SLA, base de conhecimento e conversa humana com segregação por empresa/perfil.</p></div><button class="btn btn-primary" data-action="openSupportChat">Novo atendimento</button></div><div class="kpi-grid">${kpi('Abertos',k.open)}${kpi('Aguardando atendente',k.waiting)}${kpi('Em andamento',k.progress)}${kpi('SLA vencido',k.overdue,'','danger')}${kpi('Críticos',k.critical)}${kpi('Resolvidos hoje',k.resolvedToday)}${kpi('Satisfação média',k.sat||'—')}</div><details class="card filters" open><summary>Filtros</summary><div class="form-grid"><div class="field"><label>Status</label><select data-input="supportFilter" id="supportStatus"><option value="">Todos</option>${Object.entries(SUPPORT_STATUS_LABELS).map(([v,l])=>`<option value="${v}">${l}</option>`).join('')}</select></div><div class="field"><label>Prioridade</label><select data-input="supportFilter" id="supportPriority"><option value="">Todas</option>${Object.entries(SUPPORT_PRIORITY_LABELS).filter(([v])=>v!=='normal').map(([v,l])=>`<option value="${v}">${l}</option>`).join('')}</select></div><label class="checkline"><input id="supportOverdue" data-input="supportFilter" type="checkbox"><span>SLA vencido</span></label></div></details><div id="supportList">${renderSupportList(rows)}</div><div class="card"><div class="section-toolbar"><div><h3>Base de Conhecimento</h3><p class="muted">Artigos publicados alimentam o ValoraBot.</p></div>${['admin_valora','consultor_valora'].includes(u?.role)?'<button class="btn btn-primary btn-mini" data-action="openKnowledgeArticleModal">Novo artigo</button>':''}</div>${(state.knowledgeBase||[]).filter(a=>a.published||['admin_valora','consultor_valora'].includes(u?.role)).slice(0,20).map(a=>`<details><summary>${esc(a.title)} <span class="badge ${a.published?'success':'warn'}">${a.published?'publicado':'rascunho'}</span></summary><p>${esc(a.summary)}</p><div class="legal-text">${nl2br(a.content)}</div>${['admin_valora','consultor_valora'].includes(u?.role)?`<div class="table-actions"><button class="btn btn-soft btn-mini" data-action="openKnowledgeArticleModal" data-id="${esc(a.id)}">Editar</button><button class="btn btn-soft btn-mini" data-action="toggleKnowledgeArticle" data-id="${esc(a.id)}">${a.published?'Despublicar':'Publicar'}</button><button class="btn btn-danger btn-mini" data-action="deleteKnowledgeArticle" data-id="${esc(a.id)}">Excluir</button></div>`:''}</details>`).join('')}</div>`;}
function renderSupportList(rows){return `<div class="card table-wrap"><table class="table"><thead><tr><th>Ticket</th><th>Status</th><th>SLA</th><th>Prioridade</th><th>Categoria</th><th>Empresa</th><th>Solicitante</th><th>Assunto</th><th>Ações</th></tr></thead><tbody>${rows.slice().reverse().map(c=>`<tr><td>${esc(c.id)}</td><td>${esc(SUPPORT_STATUS_LABELS[c.status]||c.status)}</td><td>${esc(slaStatus(c))}</td><td>${esc(SUPPORT_PRIORITY_LABELS[c.priority]||c.priority)}</td><td>${esc(supportCategory(c.category)?.label||c.category)}</td><td>${esc(companyName(c.companyId)||'Valora')}</td><td>${esc(c.requesterName)}</td><td>${esc(c.subject)}</td><td><button class="btn btn-secondary btn-mini" data-action="openSupportConversation" data-id="${esc(c.id)}">Abrir</button></td></tr>`).join('')||'<tr><td colspan="9">Nenhum atendimento.</td></tr>'}</tbody></table></div>`;}
function filterSupport(){const st=$('#supportStatus')?.value,pr=$('#supportPriority')?.value,over=$('#supportOverdue')?.checked,u=currentUser();let rows=(state.supportTickets||state.supportConversations||[]).filter(c=>canSeeSupport(c,u));if(st)rows=rows.filter(c=>c.status===st);if(pr)rows=rows.filter(c=>c.priority===pr);if(over)rows=rows.filter(c=>slaStatus(c)==='vencido');const box=$('#supportList');if(box)box.innerHTML=renderSupportList(rows);enhanceResponsiveTables(box||document);}
function openSupportConversation(el){renderSupportChat(el.dataset.id);}function assignSupportConversation(el){const c=(state.supportTickets||state.supportConversations||[]).find(x=>x.id===el.dataset.id),u=currentUser();if(!c||!canSeeSupport(c,u)||!(can(u,'canHandleSupport')||can(u,'canHandleGlobalSupport')))return toast(PERMISSION_DENIED_MESSAGE,'error');Object.assign(c,{assignedToUserId:u.id,assignedToName:u.name,assignedToRole:u.role,status:'in_progress',updatedAt:nowIso(),updatedBy:u.id});window.ValoraLogger?.audit({category:'support_chat',action:'ticket_assigned',message:'Ticket assumido.',companyId:c.companyId,metadata:{ticketId:c.id}});persist('Atendimento assumido.');rerenderPortal();}
function resolveSupportConversation(el){const c=(state.supportTickets||state.supportConversations||[]).find(x=>x.id===el.dataset.id);if(!c||!canSeeSupport(c)||!(can(currentUser(),'canHandleSupport')||can(currentUser(),'canHandleGlobalSupport')))return;Object.assign(c,{status:'resolved',resolvedAt:nowIso(),updatedAt:nowIso()});persist('Atendimento resolvido.');closeModal();rerenderPortal();}
function closeSupportConversation(el){const c=(state.supportTickets||state.supportConversations||[]).find(x=>x.id===el.dataset.id);if(!c||!canSeeSupport(c))return;Object.assign(c,{status:'closed',closedAt:nowIso(),updatedAt:nowIso()});window.ValoraLogger?.audit({category:'support_chat',action:'ticket_closed',message:'Ticket encerrado.',companyId:c.companyId,metadata:{ticketId:c.id}});persist('Atendimento encerrado.');closeModal();rerenderPortal();}
function rateSupportConversation(el){const id=el.dataset.id;openModal('Avaliar atendimento',`<form class="grid" data-form="supportRating"><input type="hidden" name="id" value="${esc(id)}"><div class="field"><label>Como foi o atendimento?</label><select name="rating"><option value="5">★★★★★ Excelente</option><option value="4">★★★★ Bom</option><option value="3">★★★ Regular</option><option value="2">★★ Ruim</option><option value="1">★ Péssimo</option></select></div><div class="field"><label>Comentário opcional</label><textarea name="ratingComment"></textarea></div><button class="btn btn-primary">Enviar avaliação</button></form>`,'small');}
function openOnboardingWizard(){
  const user=currentUser?.();
  const target=user?.role==='admin_valora'?'admin/clients':user?.role==='empresa_admin'?'empresa/settings':'signup';
  toast('Vamos começar pela configuração inicial do ambiente.','info');
  if(typeof navigate==='function')return navigate(target);
  location.hash=`#${target}`;
}
function saveSupportRating(form){const fd=data(form),c=(state.supportTickets||state.supportConversations||[]).find(x=>x.id===fd.id);if(!c||!canSeeSupport(c))return;Object.assign(c,{rating:Number(fd.rating||0),ratingComment:fd.ratingComment||'',ratedAt:nowIso(),updatedAt:nowIso()});persist('Obrigado pela avaliação.');closeModal();rerenderPortal();}
function toggleMenu(force){
  const nav=document.getElementById('navActions');
  const button=document.querySelector('.mobile-menu');
  if(!nav||!button)return false;
  const shouldOpen=typeof force==='boolean'?force:!nav.classList.contains('open');
  nav.classList.toggle('open',shouldOpen);
  document.body.classList.toggle('menu-open',shouldOpen);
  button.setAttribute('aria-expanded',shouldOpen?'true':'false');
  return true;
}
function closeMobileMenu(){toggleMenu(false);}
function isMobileAdminViewport(){return window.matchMedia?window.matchMedia('(max-width: 991.98px)').matches:window.innerWidth<=991;}
function ensureAdminMobileOverlay(){let overlay=document.querySelector('.admin-mobile-overlay');if(!overlay){overlay=document.createElement('div');overlay.className='admin-mobile-overlay';overlay.dataset.action='closeAdminMobileMenu';overlay.tabIndex=-1;document.body.appendChild(overlay);}return overlay;}
function adminMobileMenuParts(){const sidebar=document.getElementById('adminSidebar')||document.querySelector('.admin-sidebar');return {sidebar,overlay:ensureAdminMobileOverlay(),button:document.querySelector('[data-action="toggleAdminMobileMenu"]')};}
function openAdminMobileMenu(){const {sidebar,overlay,button}=adminMobileMenuParts();if(!sidebar||!button||!isMobileAdminViewport())return false;sidebar.classList.add('open');overlay?.classList.add('active');document.body.classList.add('mobile-menu-open');button.setAttribute('aria-expanded','true');return true;}
function closeAdminMobileMenu(){const {sidebar,overlay,button}=adminMobileMenuParts();sidebar?.classList.remove('open');overlay?.classList.remove('active');document.body.classList.remove('mobile-menu-open');button?.setAttribute('aria-expanded','false');return true;}
function toggleAdminMobileMenu(force){const {sidebar}=adminMobileMenuParts();const shouldOpen=typeof force==='boolean'?force:!sidebar?.classList.contains('open');return shouldOpen?openAdminMobileMenu():closeAdminMobileMenu();}
function adminSidebarEl(){return document.querySelector('#adminSidebar, .admin-sidebar');}
function adminMobileToggleEl(){return document.querySelector('[data-action="toggleAdminMobileMenu"]');}
function bindAdminMobileMenuEvents(){if(window.__valoraAdminMobileMenuBound)return;window.__valoraAdminMobileMenuBound=true;document.addEventListener('click',function(event){const action=event.target.closest('[data-action]');if(action&&action.dataset.action==='toggleAdminMobileMenu'){event.preventDefault();toggleAdminMobileMenu();return;}if(event.target.closest('.admin-mobile-overlay')){closeAdminMobileMenu();return;}if(event.target.closest('.admin-sidebar a, .admin-sidebar button[data-route], .admin-nav a, .admin-nav button')){if(isMobileAdminViewport())closeAdminMobileMenu();}});document.addEventListener('keydown',event=>{if(event.key==='Escape')closeAdminMobileMenu();});window.addEventListener('resize',()=>{if(!isMobileAdminViewport())closeAdminMobileMenu();});}
