async function confirmDialog(options={}){return new Promise(resolve=>confirmAction(options.title||'Confirmar ação',options.message||'',()=>resolve(true),options.tone==='danger',()=>resolve(false)));}
async function deleteResponse(responseId){const response=findResponseById(responseId);if(!response){toast('Resposta não encontrada.','warn');return false;}if(!canDeleteResponse(response)){toast('Você não tem permissão para excluir esta resposta.','warn');return false;}const confirmed=await confirmDialog({title:'Excluir resposta?',message:'A resposta será removida da visualização principal e mantida em auditoria.'});if(!confirmed)return false;const actor=getCurrentUserSafe();const patch={status:'deleted',deleted:true,deletedAt:nowIso(),deletedBy:actor?.id||actor?.uid||''};if(repository.updateResponse)await repository.updateResponse(responseId,patch);else{Object.assign(response,patch);save();}audit('Resposta excluída logicamente','response',responseId,`deletedBy=${patch.deletedBy}`);toast('Resposta excluída com segurança.','success');if(typeof rerenderPortal==='function')rerenderPortal();else if(typeof route==='function')route();return true;}
async function anonymizeResponse(responseId){const response=findResponseById(responseId);if(!response){toast('Resposta não encontrada.','warn');return false;}if(!canAnonymizeResponse(response)){toast('Você não tem permissão para anonimizar esta resposta.','warn');return false;}const confirmed=await confirmDialog({title:'Anonimizar resposta?',message:'Dados pessoais serão removidos, mantendo estatísticas agregadas e auditoria.'});if(!confirmed)return false;const actor=getCurrentUserSafe();const patch={anonymous:true,anonymized:true,anonymizedAt:nowIso(),anonymizedBy:actor?.id||actor?.uid||'',participant:{name:'Participante não identificado',email:''},participantName:'',participantEmail:'',email:'',name:''};if(repository.updateResponse)await repository.updateResponse(responseId,patch);else{Object.assign(response,patch);save();}audit('Resposta anonimizada','response',responseId,`anonymizedBy=${patch.anonymizedBy}`);toast('Resposta anonimizada com segurança.','success');if(typeof rerenderPortal==='function')rerenderPortal();return true;}

