async function login(form){const fd=data(form);const btn=$('[data-login-button]',form)||$('button',form);if(btn){btn.disabled=true;btn.textContent='Entrando…';}try{const u=await loginUser(fd.email,fd.password);if(!u)return toast('Credenciais inválidas ou usuário inativo.','error');audit('Login realizado','usuário',u.id||u.uid,u.email);toast(`Bem-vindo(a), ${u.name}.`,'success');actions.goMyArea();}catch(err){toast(err?.message||'Não foi possível entrar agora. Tente novamente.','error');}finally{if(btn){btn.disabled=false;btn.textContent='Entrar';form.password.value='';}}}
async function registerCompanyAccount(form){const fd=data(form);if(fd.password!==fd.password2)return toast('As senhas não conferem.','error');if(!fd.lgpd)return toast('Aceite o termo LGPD para criar o ambiente.','error');if(isFirebaseMode()&&(repository.registerCompany||repository.registerCompanyAccount)){try{const registerFn=repository.registerCompanyAccount||repository.registerCompany;const profile=await registerFn.call(repository,{...fd,name:fd.companyName||fd.name,legalName:fd.companyName,companyName:fd.companyName,responsibleName:fd.name,responsibleEmail:fd.email,slug:normalizeSlug(fd.companyName),planId:fd.planId||defaultPlan().id});toast('Ambiente criado com sucesso.','success');audit('Ambiente criado','empresa',profile.companyId,fd.companyName);return navigate('empresa/dashboard');}catch(err){return toast(err?.message||'Não foi possível criar o ambiente. Tente novamente ou solicite suporte.','error');}}if(state.users.some(u=>u.email.toLowerCase()===fd.email.toLowerCase()))return toast('Já existe usuário com este e-mail.','error');const company=normalizeOrganization({id:uid('org'),type:fd.type,name:fd.companyName,publicName:fd.companyName,slug:normalizeSlug(fd.companyName),document:fd.document||'',email:fd.email,phone:fd.phone||'',cep:fd.cep||'',address:fd.address||'',planId:fd.planId||defaultPlan().id,status:'active',subscription:{planId:fd.planId||defaultPlan().id,status:'active',billingStatus:'free',startedAt:nowIso()},createdAt:nowIso(),updatedAt:nowIso()});const user={id:uid('u'),name:fd.name,email:fd.email,password:fd.password,role:'empresa_admin',companyId:company.id,phone:fd.phone||'',status:'active',createdAt:nowIso()};state.companies.push(company);state.users.push(user);createInvoiceForCompany(company);state.session={userId:user.id,createdAt:nowIso()};audit('Ambiente criado','empresa',company.id,company.name);persist('Ambiente criado com sucesso.');navigate('empresa/dashboard');}
function signup(form){return registerCompanyAccount(form);}
function saveCompanySettings(form){const c=currentCompany();if(!c)return;const fd=data(form);const logo=(fd.logoUrl||'').trim();if(logo){try{new URL(logo);}catch(_){return toast('URL da logo inválida.','error');}}for(const k of ['primaryColor','secondaryColor','accentColor','backgroundColor','textColor'])if(!validHex(fd[k]))return toast('Cor inválida: '+k,'error');if(currentUser()?.role==='admin_valora'){const nextSlug=normalizeSlug(fd.slug||c.slug);const err=validateOrganizationSlug(nextSlug,c.id);if(err)return toast(err,'error');c.slug=nextSlug;}Object.assign(c,{publicName:fd.publicName,name:c.name||fd.publicName,slogan:fd.slogan||'',brand:{...getCompanyTheme(c),logoUrl:logo,primaryColor:fd.primaryColor,secondaryColor:fd.secondaryColor,accentColor:fd.accentColor,backgroundColor:fd.backgroundColor,textColor:fd.textColor,useCompanyBrandOnPublicSurvey:!!fd.useCompanyBrandOnPublicSurvey,useCompanyBrandOnEmails:!!fd.useCompanyBrandOnEmails,showPoweredByValora:!!fd.showPoweredByValora},settings:{...(c.settings||{}),contactEmail:fd.contactEmail||'',whatsapp:fd.whatsapp||'',lgpdContact:fd.lgpdContact||''},updatedAt:nowIso()});applyCompanyTheme(c);audit('Identidade visual atualizada','empresa',c.id,c.publicName||c.name);persist('Personalização salva.');rerenderPortal();}
function toggleBot(force){const p=$('#botPanel');if(!p)return;const open=typeof force==='boolean'?force:!p.classList.contains('open');p.classList.toggle('open',open);p.setAttribute('aria-hidden',open?'false':'true');}
function appendBot(text,who,actions=[]){const box=$('#botMessages');if(!box)return;const d=document.createElement('div');d.className=`bot-msg ${who==='me'?'me':''}`;d.innerHTML=`${who==='me'?'': '<b>ValoraBot</b><br>'}${nl2br(text)}<small>${new Date().toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'})}</small>${actions?.length?`<div class="bot-actions">${actions.map(a=>`<button class="btn btn-soft btn-mini" data-action="botAction" data-type="${esc(a.type||a.action||'')}" data-value="${esc(a.value||a.route||'')}">${esc(a.label)}</button>`).join('')}</div>`:''}`;box.appendChild(d);box.scrollTop=box.scrollHeight;}
function handleBotMessage(text){appendBot(text,'me');const box=$('#botMessages'),typing=document.createElement('div');typing.className='bot-msg typing';typing.textContent='ValoraBot está digitando...';box?.appendChild(typing);if(box)box.scrollTop=box.scrollHeight;setTimeout(()=>{typing.remove();const r=window.ValoraChatbot?.sendMessage?.(text)||window.ValoraChatbot?.buildAnswer?.(text)||{text:botReply(text),actions:[]};appendBot(r.text||r.answer,'bot',r.actions||[]);if((r.intent==='suporte_humano'||r.escalate)&&String(text).toLowerCase().includes('atendente'))openSupportChat();},220);}
function handleBotAction(el){const type=el.dataset.type,value=el.dataset.value;window.ValoraLogger?.info({category:'chatbot',action:'suggested_action_clicked',message:'Ação sugerida clicada.',metadata:{type,value},user:currentUser?.()});if(type==='route')navigate(value);else if(type==='manual')openManual();else if(type==='support'||type===''){window.ValoraLogger?.info({category:'chatbot',action:'chatbot_human_support_requested',message:'Suporte humano solicitado pelo ValoraBot.',metadata:{value},user:currentUser?.()});if(currentUser?.()){window.ValoraChatbot?.createSupportTicketFromBot?.({subject:'Atendimento pelo ValoraBot'});openSupportChat();}else{window.ValoraChatbot?.openWhatsappSupport?.(value||'atendimento humano');}}}
function botReply(text){const t=String(text).toLowerCase(),u=currentUser(),ctx=currentRoute;if(isPublicJourneyPage()){if(['preciso de ajuda','falar com atendente','não consigo responder','nao consigo responder','link expirou','erro'].some(x=>t.includes(x)))return 'Posso abrir um atendimento para você. Informe seu nome e e-mail para que um atendente possa responder. Se houver WhatsApp disponível nesta pesquisa, você também pode usar o botão de suporte.';if(t.includes('lgpd')||t.includes('dados')||t.includes('seguro'))return 'Seus dados são tratados conforme o termo LGPD exibido antes do envio. O link seguro usa token e validade, e a empresa responsável recebe apenas o necessário para a pesquisa e resultado.';if(t.includes('como')||t.includes('respon'))return 'Para responder, preencha a identificação, leia e aceite a LGPD quando solicitada, responda todas as perguntas obrigatórias e clique em Enviar respostas e ver resultado.';if(t.includes('resultado'))return 'Ao concluir, o resultado individual aparece na tela. Quando habilitado, você pode receber por e-mail e acessar seu histórico pela área do participante.';}const profile=u?`Seu perfil atual é ${ROLE_LABELS[u.role]||u.role} e você está em ${ctx||'home'}. `:'';const m=u?.companyId?onboardingMetrics(u.companyId):null;if(t.includes('alerta')||t.includes('notifica')||t.includes('convites pendentes')||t.includes('pesquisa vencendo')||t.includes('limite do plano')||t.includes('implantação está travada')||t.includes('implantacao esta travada')||t.includes('marcar notificações')||t.includes('marcar notificacoes'))return profile+'A Central de Notificações prioriza alertas por severidade e perfil. Convites pendentes pedem reenvio permitido ou atualização da lista; pesquisa vencendo pede renovar prazo ou concluir coleta; ação vencida pede revisar responsável/prazo; limite do plano pede reduzir uso ou ajustar plano; implantação travada indica etapa pendente do onboarding. Use o sino ou a aba Notificações para marcar como lida, dispensar ou abrir a ação relacionada.';if(t.includes('como começo')||t.includes('primeira pesquisa')||t.includes('próximo passo')||t.includes('proximo passo')||t.includes('dashboard está vazio')||t.includes('dashboard esta vazio')||t.includes('falta para concluir')||t.includes('cadastro funcionários')||t.includes('cadastro funcionarios')){if(!m)return profile+'Entre no portal da empresa para ver o checklist Primeiros passos da implantação.';return profile+(m.next.id==='employees'?'O próximo passo é cadastrar funcionários. Acesse Funcionários e clique em Cadastrar funcionário.':m.next.id==='surveys'?'Você já tem funcionários. Agora crie uma pesquisa usando um questionário.':m.next.id==='invites'?'Sua pesquisa está criada. Agora envie convites aos funcionários.':m.next.id==='responses'?'Os convites foram enviados. Você pode reenviar lembretes ou aguardar as respostas.':`O próximo passo é: ${m.next.label}. ${m.next.text}`);}if(t.includes('perfil')||t.includes('empresa admin')||t.includes('gestor de pesquisa')||t.includes('quem pode enviar')||t.includes('quem pode ver respostas')||t.includes('funcionário precisa')||t.includes('funcionario precisa')||t.includes('convidado externo'))return profile+'Perfis: Administrador da Empresa gerencia usuários, pesquisas, envios e relatórios da própria empresa; Gestor de Pesquisa cria questionários e envia pesquisas; Analista de Resultados visualiza respostas, gráficos e relatórios; Gestor de Área vê resultados da própria área; Participante apenas responde e consulta histórico permitido; Convidado Externo responde por link sem portal administrativo. Para apenas responder, use Participante; para criar e enviar, use Gestor de Pesquisa; para analisar, use Analista de Resultados; para responsável geral, use Administrador da Empresa.';if(t.includes('tipo')||t.includes('pergunta'))return profile+'Cada pergunta pode usar escala 1–5, escolha única (radio), múltipla escolha (checkbox), resposta curta (text box), resposta longa (text area) ou uma resposta correta. Você também define peso, nota máxima e pontuação das alternativas.';if(t.includes('compart')||t.includes('link'))return profile+'Abra Formulários, clique em “Criar pesquisa e compartilhar”, escolha a validade e depois copie o link seguro ou envie por WhatsApp/e-mail.';if(t.includes('lgpd')||t.includes('privacidade'))return profile+'A jornada registra finalidade, aceite, canais de contato e preferência de envio. O link usa token e expiração, e os dados são separados por empresa e perfil.';if(t.includes('plano de ação')||t.includes('plano de acao')||t.includes('ação vencida')||t.includes('acoes vencidas')||t.includes('ações vencidas')||t.includes('dimensão crítica')||t.includes('dimensao critica')||t.includes('gero ações')||t.includes('gerar ações')||t.includes('responsável por uma ação')||t.includes('responsavel por uma acao')){const rows=u?.companyId?actionPlansForUser(u.companyId):[];const overdue=rows.filter(actionIsOverdue).length;const critical=rows.filter(a=>a.priority==='critical'||a.priority==='high').length;return profile+(overdue?`Existem ${overdue} ação(ões) vencida(s). Recomendo revisar responsáveis e prazos. `:'')+(critical?'Identifiquei ações ou dimensões críticas. Você pode gerar ações sugeridas automaticamente a partir do resultado. ':'')+'Para criar, acesse Plano de ação, clique em Nova ação, informe título, prioridade, status, responsável, departamento, prazo e evidências. Para gerar automaticamente, use Gerar ações sugeridas após ter respostas da pesquisa. Os relatórios executivos incluem a seção Plano de Ação Recomendado.';}if(/valora insight|125|cinco dimens|5 dimens|cr[ií]tico|estrutura[cç][aã]o|estruturada|alta maturidade|radar|verdade estrat[eé]gica|baixar relat[oó]rio|certificado|depois do diagn[oó]stico|resultado/.test(t)){const ctx=window.ValoraChatbot?.getChatContext?.()||{};const current=ctx.currentResult;const contextLine=current?` Resultado atual: ${current.totalScore||current.rawScore||'—'}/125, nível ${current.maturityLabel||current.level?.label||'—'}, bloqueador ${current.weakestDimension?.name||current.valoraInsight?.weakestDimension?.name||'—'}.`:'';return profile+'O Valora Insight™ é a devolutiva estratégica da Valora Group: 25 perguntas, 5 dimensões oficiais e máximo de 125 pontos. As dimensões são Cultura e Propósito, Gestão e Governança, Liderança, Pessoas e Talentos, e Resultados e Crescimento; ESG fica fora do diagnóstico principal. Níveis: Crítico (25–55) indica base instável; Em estruturação (56–85) indica organização parcial; Estruturada (86–110) indica operação funcional com pontos a consolidar; Alta maturidade (111–125) indica sistema mais previsível. O radar textual mostra cada dimensão em 10 blocos e revela desequilíbrios. A verdade estratégica traduz o principal bloqueio: decisão, dependência de pessoas-chave, sustentação ou crescimento. Depois do diagnóstico, baixe o relatório estratégico/certificado na tela de resultado ou em Pesquisas respondidas e converse com a Valora Group pelo +55 91 99254-5353.'+contextLine;}if(t.includes('pdf')||t.includes('relat'))return profile+'Na tela de resultado e em Pesquisas respondidas, use “Baixar relatório estratégico” para gerar o PDF com Resultado Geral, Nível de Maturidade, Radar Organizacional, Verdade Estratégica, Risco se Nada Mudar, Próximo Nível e contato Valora Group. O certificado também possui versões PDF e PNG.';if(t.includes('logo')||t.includes('cores')||t.includes('white label')||t.includes('personalizo'))return profile+'Acesse Empresa › Dados e marca para alterar nome público, slogan, URL da logo e cores. Empresa Admin não altera plano, cobrança ou limites; esses campos são exclusivos do Admin Valora.';if(t.includes('upgrade')||t.includes('limite')||t.includes('assinatura suspensa')||t.includes('suspensa')||t.includes('não consigo enviar')||t.includes('nao consigo enviar'))return profile+'Abra Empresa › Plano contratado para ver uso, status da assinatura, módulos e limites. Se a assinatura estiver suspensa ou o limite mensal for excedido, novas pesquisas/convites podem ser bloqueados até regularização ou upgrade.';if(t.includes('plano'))return profile+'A vitrine tem Grátis, Essencial, Profissional, Corporativo e Enterprise. O Grátis permite 1 pesquisa e até 10 respostas; os planos pagos ampliam volume, gestão e relatórios.';if(t.includes('funcion')||t.includes('respondente'))return profile+'Na tela Empresa › Usuários, cadastre funcionário com nome, e-mail, telefone, cargo, departamento e status. Depois selecione os funcionários e clique em “Enviar pesquisa aos selecionados”. O sistema impede dados fora da empresa atual e duplicidade de e-mail.';if(t.includes('cálculo')||t.includes('calculo')||t.includes('peso')||t.includes('pontuação')||t.includes('pontuacao')||t.includes('dimensão')||t.includes('dimensao'))return profile+'O cálculo é centralizado em calculateSurveyResult: escala vira nota/5 × pontuação máxima × peso; escolha única usa a opção; múltipla soma sem ultrapassar o máximo; texto só pontua se scoreWhenFilled estiver configurado; dimensões consolidam apenas suas perguntas.';if(t.includes('resposta')||t.includes('gráfico')||t.includes('grafico')||t.includes('dashboard'))return profile+'Respostas concluídas alimentam área de respostas, dashboards e relatórios com a mesma função de cálculo. Se uma resposta não aparece, confira pesquisa, empresa, status do convite, permissão do perfil e se o envio foi concluído.';if(t.includes('reenviar')||t.includes('email')||t.includes('e-mail')||t.includes('convite'))return profile+'Use Compartilhar pesquisa › Enviar para funcionários ou Empresa › Usuários › Enviar pesquisa aos selecionados. Em local/demo o convite vira .eml em data/outbox; em Firebase a integração deve ser Cloud Functions, sem SMTP no frontend.';return profile+'Posso ajudar com criação de formulário, pontuação, pesquisa instantânea, compartilhamento, relatórios, planos ou LGPD. Escreva o tema da sua dúvida.';}
function openSurveyInNewTab(el){const link=el?.dataset?.link||lastShareLink;if(!link||link==='#signup')return navigate('signup');window.open(link,'_blank','noopener,noreferrer');window.ValoraLogger?.info({category:'survey',action:'open_public_survey_new_tab',message:'Pesquisa pública aberta em nova aba.',metadata:{link:sanitizePublicUrlForLog(link)}});}
function goHomeFromPublicSurvey(){const clean=location.href.split('?')[0].split('#')[0];history.replaceState({},'',`${clean}#home`);audit('Voltar Home público','jornada_publica','home','Retorno sem query string');route('home');window.scrollTo({top:0,behavior:'smooth'});}
function openExternal(target){const url=target?.dataset?.url||target;try{const w=window.open(url,'_blank','noopener,noreferrer');if(!w)location.href=url;}catch(_){location.href=url;}}
async function copyText(text){try{await navigator.clipboard.writeText(text);toast('Link copiado.','success');}catch(_){openModal('Copiar link',`<div class="field"><label>Selecione e copie</label><textarea style="min-height:120px">${esc(text)}</textarea></div>`,'small');}}

async function lookupCep(button){const root=button.closest('form')||button.closest('.modal-body')||document;const input=$('input[name="cep"]',root);if(!input)return;const cep=onlyDigits(input.value);if(cep.length!==8)return toast('Informe um CEP com 8 dígitos.','error');button.disabled=true;button.textContent='Buscando…';try{let data;if(isFirebaseMode()){if(!cloudFunctionsAvailable())throw new Error('Busca de CEP indisponível no plano Spark.');data=(await firebaseCallable('lookupCep')({cep})).data;}else{const r=await fetch(`/api/cep/${cep}`);if(!r.ok)throw new Error('CEP não encontrado.');data=await r.json();}if(data.erro)throw new Error('CEP não encontrado.');const address=data.address||[data.logradouro,data.bairro,data.localidade,data.uf].filter(Boolean).join(', ');const field=$('input[name="address"]',root);if(field)field.value=address;toast('Endereço preenchido.','success');}catch(err){toast(`Falha na busca de CEP: ${err.message}`,'error');}finally{button.disabled=false;button.textContent='Buscar CEP';}}
async function lookupCnpj(button){const root=button.closest('form')||button.closest('.modal-body')||document;const input=$('input[name="document"]',root);if(!input)return;const cnpj=onlyDigits(input.value);if(cnpj.length!==14)return toast('Informe um CNPJ com 14 dígitos.','error');button.disabled=true;button.textContent='Buscando…';try{let d;if(isFirebaseMode()){if(!cloudFunctionsAvailable())throw new Error('Busca de CNPJ indisponível no plano Spark.');d=(await firebaseCallable('lookupCnpj')({cnpj})).data;}else{const r=await fetch(`/api/cnpj/${cnpj}`);if(!r.ok)throw new Error('CNPJ não encontrado.');d=await r.json();}const name=$('input[name="companyName"]',root)||$('input[name="name"]',root);if(name)name.value=d.razao_social||d.nome_fantasia||d.nome||'';const cep=$('input[name="cep"]',root);if(cep)cep.value=d.cep||'';const address=$('input[name="address"]',root);if(address)address.value=d.endereco?[d.endereco,d.municipio,d.uf].filter(Boolean).join(', '):[d.descricao_tipo_de_logradouro,d.logradouro,d.numero,d.bairro,d.municipio,d.uf].filter(Boolean).join(', ');toast('Dados do CNPJ preenchidos.','success');}catch(err){const code=publicErrorCode(err);window.ValoraRuntimeDiagnostics=window.ValoraRuntimeDiagnostics||{};window.ValoraRuntimeDiagnostics.lastLookupCnpj={code,message:sanitizePublicError(err),nonBlocking:true};toast(code==='unauthenticated'||code==='permission-denied'?'Não foi possível consultar o CNPJ automaticamente. Continue o cadastro preenchendo manualmente.':`Consulta de CNPJ indisponível agora. Você pode continuar manualmente.`,'warn');}finally{button.disabled=false;button.textContent='Buscar CNPJ';}}


function migrationFileStamp(){const d=new Date(),p=n=>String(n).padStart(2,'0');return `${d.getFullYear()}${p(d.getMonth()+1)}${p(d.getDate())}-${p(d.getHours())}${p(d.getMinutes())}`;}
function sanitizeMigrationValue(value,key='',options={}){const secret=/password|senha|secret|token|apikey|apiKey|privateKey|serviceAccount|smtpPassword|telegram|botToken|authorization|credential/i;if(Array.isArray(value))return value.map(v=>sanitizeMigrationValue(v,key,options));if(value&&typeof value==='object'){const out={};Object.entries(value).forEach(([k,v])=>{if(k==='password'||(secret.test(k)&&!['senderEmail','contactEmail','email','supportEmail','tokenHash','secretHash','keyHash','resultToken'].includes(k)))return;if(k==='document'&&options.maskDemoDocuments&&/exemplo|demo|teste/i.test(String(value.name||value.publicName||value.email||'')))out[k]=maskDocument(v);else out[k]=sanitizeMigrationValue(v,k,options);});return out;}return value;}
function maskDocument(v){const d=onlyDigits(v);return d.length>4?`${d.slice(0,3)}***${d.slice(-2)}`:(v||'');}
function sanitizeMigrationUser(u={}){return sanitizeMigrationValue({id:u.id,uid:u.uid,name:u.name,email:u.email,role:u.role,companyId:u.companyId,phone:u.phone,status:u.status,department:u.department,position:u.position,permissions:u.permissions,receivesEmail:u.receivesEmail,portalAccess:u.portalAccess,createdAt:u.createdAt,updatedAt:u.updatedAt});}
function sanitizeExportForProduction(localState,options={}){const fullKeys=['settings','modules','plans','companies','users','forms','surveys','responses','invitations','invoices','actionPlans','knowledgeBase','supportCategories','supportSlaPolicies','supportTickets','supportMessages','integrations','webhooks'];const structureKeys=['settings','modules','plans','companies','users','forms','surveys','knowledgeBase','supportCategories','supportSlaPolicies'];const keys=options.structureOnly?structureKeys:fullKeys;const data={settings:{},modules:[],plans:[],companies:[],users:[],forms:[],surveys:[],responses:[],invitations:[],invoices:[],actionPlans:[],knowledgeBase:[],supportCategories:[],supportSlaPolicies:[],supportTickets:[],supportMessages:[],integrations:[],webhooks:[]};keys.forEach(k=>{if(k==='users')data[k]=(localState.users||[]).map(sanitizeMigrationUser);else if(k==='responses')data[k]=options.includeResponses?sanitizeMigrationValue(localState.responses||[],k,options).map(r=>({...r,isDemo:r.isDemo||/demo|teste|exemplo/i.test(String(r.companyName||r.source||''))})):[];else if(k==='companies')data[k]=sanitizeMigrationValue(localState.companies||[],k,options).map(c=>/empresa exemplo|exemplo|demo|teste/i.test(String(c.name||c.publicName||''))?{...c,isDemo:true}:c);else data[k]=sanitizeMigrationValue(localState[k]||(k==='settings'?{}:[]),k,options);});return data;}
function buildLocalMigrationExport(options={}){return {version:VERSION,exportedAt:nowIso(),source:'localStorage',storeKey:STORE_KEY,target:'firebase-prd',data:sanitizeExportForProduction(state,options)};}
function exportLocalMigration(){if(currentUser()?.role!=='admin_valora')return toast(PERMISSION_DENIED_MESSAGE,'error');const includeResponses=!!$('#migrationIncludeResponses')?.checked,maskDemoDocuments=$('#migrationMaskDemo')?.checked!==false;const payload=buildLocalMigrationExport({includeResponses,maskDemoDocuments});downloadText(`valora-prd-export-${migrationFileStamp()}.json`,JSON.stringify(payload,null,2),'application/json');audit('Exportação local para PRD Firebase','backup','migration',`responses=${includeResponses}`);toast('Exportação PRD sanitizada gerada. Confira o JSON antes de importar no Firebase.','success');}
function exportLocalMigrationStructure(){if(currentUser()?.role!=='admin_valora')return toast(PERMISSION_DENIED_MESSAGE,'error');const payload=buildLocalMigrationExport({structureOnly:true,includeResponses:false,maskDemoDocuments:true});downloadText(`valora-prd-structure-export-${migrationFileStamp()}.json`,JSON.stringify(payload,null,2),'application/json');audit('Exportação estrutural para PRD Firebase','backup','migration','sem responses/logs/sensíveis');toast('Exportação somente estrutura gerada.','success');}
function firebaseSeedStatusCounts(){return {companies:(state.companies||[]).length,users:(state.users||[]).length,plans:(state.plans||[]).length,modules:(state.modules||[]).length,forms:(state.forms||[]).length,questions:(state.forms||[]).reduce((n,f)=>n+(f.questions||[]).length,0),surveys:(state.surveys||[]).length,responses:(state.responses||[]).length,invitations:(state.invitations||[]).length,invoices:(state.invoices||[]).length,knowledgeBase:(state.knowledgeBase||[]).length};}

function exportBackup(){if(!can(currentUser(),'canBackup'))return toast(PERMISSION_DENIED_MESSAGE,'error');downloadText(`valora-pulse-backup-${new Date().toISOString().slice(0,10)}.json`,JSON.stringify(state,null,2),'application/json');audit('Backup exportado','backup','global','Base completa');}
function openImport(){if(currentUser()?.role!=='admin_valora')return toast(PERMISSION_DENIED_MESSAGE,'error');openModal('Importar backup',`<form class="grid" data-form="importBackup"><div class="danger-box"><b>Atenção:</b> a importação substitui toda a base local.</div><div class="field"><label>Arquivo JSON</label><input name="file" type="file" accept="application/json,.json" required></div><div class="confirm-actions"><button type="button" class="btn btn-soft" data-action="closeModal">Cancelar</button><button class="btn btn-danger">Validar e importar</button></div></form>`,'small');}
function importBackup(form){const file=$('input[type="file"]',form)?.files?.[0];if(!file)return;const reader=new FileReader();reader.onload=()=>{try{const obj=JSON.parse(reader.result);if(!obj||!Array.isArray(obj.users)||!Array.isArray(obj.forms)||!Array.isArray(obj.surveys))throw new Error('Estrutura inválida.');confirmAction('Substituir a base?',`Importar ${obj.users.length} usuários, ${obj.forms.length} formulários e ${obj.surveys.length} pesquisas?`,()=>{downloadText('backup-antes-da-importacao.json',JSON.stringify(state,null,2),'application/json');obj.version=VERSION;state=obj;normalizeState(state);save();closeModal();audit('Backup importado','backup','global',file.name);toast('Backup importado.','success');goHome();});}catch(err){toast(`Arquivo inválido: ${err.message}`,'error');}};reader.readAsText(file);}
function clearLogs(){if(!can(currentUser(),'canViewLogs'))return toast(PERMISSION_DENIED_MESSAGE,'error');confirmAction('Limpar logs?', 'Esta ação apaga o histórico de auditoria local.',()=>{state.logs=[];audit('Logs limpos','log','global','Reinício da auditoria');persist('Logs limpos.');rerenderPortal();});}
function exportMyData(){const u=currentUser();if(!u)return;const payload={user:{...u,password:undefined},responses:responsesForUser(u)};downloadText(`meus-dados-${slug(u.name)}.json`,JSON.stringify(payload,null,2),'application/json');audit('Dados pessoais exportados','usuário',u.id,u.email);}
function requestDeletion(){const u=currentUser();if(!u)return;confirmAction('Registrar solicitação?', 'A solicitação será registrada no log para análise do controlador dos dados.',()=>{audit('Solicitação LGPD de exclusão','usuário',u.id,u.email);persist('Solicitação registrada. A organização responsável deverá analisá-la.');});}



// Integrações corporativas, API pública, webhooks, importação/exportação e LGPD.
const INTEGRATION_SCOPES=['employees:read','employees:write','surveys:read','responses:read','reports:read','webhooks:manage'];
const WEBHOOK_EVENTS=['employee.created','employee.updated','survey.created','survey.sent','invitation.sent','invitation.failed','response.submitted','report.generated','action_plan.created','action_plan.completed','invoice.paid','subscription.updated'];
function normalizeIntegration(x={}){return {id:x.id||uid('int'),companyId:x.companyId||'',name:x.name||'Integração',type:x.type||'manual',status:x.status||'active',provider:x.provider||'custom',description:x.description||'',enabled:x.enabled!==false,allowedEvents:x.allowedEvents||[],allowedScopes:x.allowedScopes||[],createdAt:x.createdAt||nowIso(),updatedAt:x.updatedAt||nowIso(),createdBy:x.createdBy||'',updatedBy:x.updatedBy||''};}
function normalizeApiKey(x={}){return {id:x.id||uid('key'),companyId:x.companyId||'',name:x.name||'API Key',keyHash:x.keyHash||'',keyPrefix:x.keyPrefix||'',scopes:x.scopes||['employees:read'],status:x.status||'active',lastUsedAt:x.lastUsedAt||'',expiresAt:x.expiresAt||'',createdAt:x.createdAt||nowIso(),revokedAt:x.revokedAt||'',createdBy:x.createdBy||'',revokedBy:x.revokedBy||''};}
function normalizeWebhook(x={}){return {id:x.id||uid('wh'),companyId:x.companyId||'',name:x.name||'Webhook',url:x.url||'',secretHash:x.secretHash||'',events:x.events||['response.submitted'],status:x.status||'active',lastDeliveryAt:x.lastDeliveryAt||'',lastDeliveryStatus:x.lastDeliveryStatus||'',failureCount:Number(x.failureCount||0),createdAt:x.createdAt||nowIso(),updatedAt:x.updatedAt||nowIso()};}
function integrationsAllowed(company=currentCompany()){const p=planById(company?.planId);return currentUser()?.role==='admin_valora'||!!(p?.allowIntegrations||p?.id==='enterprise'||(p?.enabledModules||[]).includes('integrations'));}
function integrationScopeCompany(){const u=currentUser();return u?.role==='admin_valora'?($('#integrationCompanyFilter')?.value||state.companies[0]?.id||''):u?.companyId;}
function integrationRows(companyId){return (state.integrations||[]).filter(x=>!companyId||x.companyId===companyId);}
function apiKeyRows(companyId){return (state.apiKeys||[]).filter(x=>!companyId||x.companyId===companyId).map(k=>({...k,keyHash:k.keyHash?'•••• hash protegido':''}));}
function webhookRows(companyId){return (state.webhooks||[]).filter(x=>!companyId||x.companyId===companyId).map(w=>({...w,secretHash:w.secretHash?'•••• segredo protegido':''}));}
function logIntegration(action,status='success',detail='',companyId=integrationScopeCompany(),integrationId='') { (state.integrationLogs||(state.integrationLogs=[])).push({id:uid('ilog'),companyId,integrationId,type:'integration',action,status,requestSummary:detail,responseSummary:'',error:status==='error'?detail:'',createdAt:nowIso()});audit(action,'integration',integrationId,detail); }
function fakeHash(v){return 'sha256:'+btoa(unescape(encodeURIComponent(String(v)))).replace(/=+$/,'').slice(0,44);}
function makeApiSecret(){return 'vp_live_'+Array.from(crypto.getRandomValues(new Uint8Array(24))).map(b=>b.toString(16).padStart(2,'0')).join('');}
function integrationsSection(scope){const c=scope==='admin'?state.companies[0]:currentCompany();if(scope!=='admin'&&!integrationsAllowed(c))return '<div class="danger-box"><b>Módulo não contratado.</b><br>Integrações, API keys e webhooks exigem plano com módulo Integrações. Exportação manual limitada pode continuar em Relatórios.</div>';const companyId=scope==='admin'?(state.companies[0]?.id||''):currentUser().companyId, ints=integrationRows(companyId), keys=apiKeyRows(companyId), whs=webhookRows(companyId), logs=(state.integrationLogs||[]).filter(l=>!companyId||l.companyId===companyId).slice(-20).reverse();return `<div class="section-toolbar"><div><h3>Integrações externas</h3><p class="muted">Base para RH, ERP, CRM, BI, planilhas, automações e sistemas internos. Segredos não são exibidos no frontend.</p></div><div class="table-actions"><button class="btn btn-primary" data-action="openApiKeyModal">Criar chave</button><button class="btn btn-secondary" data-action="openWebhookModal">Criar webhook</button><button class="btn btn-soft" data-action="openEmployeeImport">Importar funcionários</button><button class="btn btn-soft" data-action="openDataExport">Exportar dados</button></div></div>${scope==='admin'?`<div class="card field"><label>Empresa</label><select id="integrationCompanyFilter" data-change="integrationCompanyFilter">${state.companies.map(x=>`<option value="${esc(x.id)}">${esc(x.name)}</option>`).join('')}</select></div>`:''}<div class="kpi-grid">${kpi('Integrações',ints.length,'ativas/configuradas')}${kpi('API keys',keys.filter(k=>k.status==='active').length,'hash protegido')}${kpi('Webhooks',whs.length,'HMAC + retry simples')}${kpi('Logs',logs.length,'últimos eventos')}</div><div class="grid grid-2"><div class="card"><h3>Integrações</h3>${ints.map(i=>`<div class="feature"><b>${esc(i.name)}</b><br><span class="muted">${esc(i.type)} • ${esc(i.status)} • escopos: ${(i.allowedScopes||[]).join(', ')||'—'}</span></div>`).join('')||'<div class="empty">Nenhuma integração.</div>'}</div><div class="card table-wrap"><h3>API keys</h3><table class="table"><thead><tr><th>Nome</th><th>Prefixo</th><th>Escopos</th><th>Status</th><th>Ações</th></tr></thead><tbody>${keys.map(k=>`<tr><td>${esc(k.name)}</td><td>${esc(k.keyPrefix)}</td><td>${esc(k.scopes.join(', '))}</td><td>${esc(k.status)}</td><td><button class="btn btn-danger btn-mini" data-action="revokeApiKey" data-id="${esc(k.id)}">Revogar</button></td></tr>`).join('')||'<tr><td colspan="5">Sem chaves.</td></tr>'}</tbody></table></div><div class="card table-wrap"><h3>Webhooks</h3><table class="table"><thead><tr><th>Nome</th><th>URL</th><th>Eventos</th><th>Status</th><th>Ações</th></tr></thead><tbody>${whs.map(w=>`<tr><td>${esc(w.name)}</td><td>${esc(w.url)}</td><td>${esc(w.events.join(', '))}</td><td>${esc(w.status)} / ${esc(w.lastDeliveryStatus||'—')}</td><td><button class="btn btn-secondary btn-mini" data-action="testWebhook" data-id="${esc(w.id)}">Testar</button></td></tr>`).join('')||'<tr><td colspan="5">Sem webhooks.</td></tr>'}</tbody></table></div><div class="card table-wrap"><h3>Logs de integração</h3><table class="table"><thead><tr><th>Data</th><th>Ação</th><th>Status</th><th>Resumo</th></tr></thead><tbody>${logs.map(l=>`<tr><td>${brDate(l.createdAt)}</td><td>${esc(l.action)}</td><td>${esc(l.status)}</td><td>${esc(l.requestSummary||l.error||'')}</td></tr>`).join('')||'<tr><td colspan="4">Sem logs.</td></tr>'}</tbody></table></div></div><div class="page-help"><b>API pública preparada:</b> GET/POST/PUT /api/v1/employees, GET /api/v1/surveys, /responses, /reports e POST /api/v1/webhooks/test via Cloud Function publicApi, sempre validando hash da API key, companyId, escopo, rate limit e auditoria.</div>`;}
function openApiKeyModal(){const companyId=integrationScopeCompany();openModal('Criar API key',`<form class="grid" data-form="apiKey"><div class="field"><label>Nome</label><input name="name" required value="Integração RH"></div><div class="field"><label>Expira em</label><input name="expiresAt" type="date"></div><div class="field span-2"><label>Escopos</label>${INTEGRATION_SCOPES.map(s=>`<label class="checkline"><input type="checkbox" name="scopes" value="${s}" ${s==='employees:read'?'checked':''}><span>${s}</span></label>`).join('')}</div><input type="hidden" name="companyId" value="${esc(companyId)}"><button class="btn btn-primary">Criar e mostrar chave uma vez</button></form>`,'small');}
function saveApiKey(form){const fd=data(form), secret=makeApiSecret(), companyId=fd.companyId||currentUser().companyId, item=normalizeApiKey({companyId,name:fd.name,keyHash:fakeHash(secret),keyPrefix:secret.slice(0,12),scopes:Array.isArray(fd.scopes)?fd.scopes:[fd.scopes].filter(Boolean),expiresAt:fd.expiresAt?new Date(fd.expiresAt+'T23:59:59').toISOString():'',createdBy:currentUser().id});state.apiKeys.push(item);logIntegration('api_key.created','success',`Chave ${item.keyPrefix} criada`,companyId,item.id);persist('API key criada. Copie a chave agora.');openModal('Copie sua API key agora',`<div class="danger-box"><b>Esta chave será exibida somente uma vez.</b><br>Salve em um cofre seguro. O Firestore guarda apenas hash.</div><textarea readonly style="min-height:90px">${esc(secret)}</textarea><button class="btn btn-primary" data-action="copyApiSecret" data-secret="${esc(secret)}">Copiar chave</button>`,'small');}
function revokeApiKey(id){const k=(state.apiKeys||[]).find(x=>x.id===id);if(!k)return;confirmAction('Revogar API key?','Chamadas com esta chave serão bloqueadas.',()=>{Object.assign(k,{status:'revoked',revokedAt:nowIso(),revokedBy:currentUser().id});logIntegration('api_key.revoked','success',k.keyPrefix,k.companyId,k.id);persist('API key revogada.');rerenderPortal();});}
function openWebhookModal(){const companyId=integrationScopeCompany();openModal('Criar webhook',`<form class="grid" data-form="webhook"><div class="field"><label>Nome</label><input name="name" required value="Webhook BI"></div><div class="field"><label>URL HTTPS</label><input name="url" type="url" required placeholder="https://cliente.com/webhook"></div><div class="field span-2"><label>Eventos</label>${WEBHOOK_EVENTS.map(e=>`<label class="checkline"><input type="checkbox" name="events" value="${e}" ${e==='response.submitted'?'checked':''}><span>${e}</span></label>`).join('')}</div><input type="hidden" name="companyId" value="${esc(companyId)}"><button class="btn btn-primary">Criar webhook</button></form>`,'small');}
function saveWebhook(form){const fd=data(form), secret=makeApiSecret(), companyId=fd.companyId||currentUser().companyId;try{const u=new URL(fd.url);if(u.protocol!=='https:')return toast('Webhook deve usar HTTPS.','error');}catch(_){return toast('URL inválida.','error');}const item=normalizeWebhook({companyId,name:fd.name,url:fd.url,events:Array.isArray(fd.events)?fd.events:[fd.events].filter(Boolean),secretHash:fakeHash(secret)});state.webhooks.push(item);logIntegration('webhook.created','success',item.url,companyId,item.id);persist('Webhook criado. Copie o segredo agora.');openModal('Segredo do webhook',`<div class="danger-box"><b>O segredo será exibido somente uma vez.</b> Use para validar X-Valora-Signature.</div><textarea readonly>${esc(secret)}</textarea>`,'small');}
function testWebhook(id){const w=(state.webhooks||[]).find(x=>x.id===id);if(!w)return;w.lastDeliveryAt=nowIso();w.lastDeliveryStatus=w.url.includes('fail')?'failed':'success';w.failureCount+=w.lastDeliveryStatus==='failed'?1:0;logIntegration(w.lastDeliveryStatus==='failed'?'webhook.failed':'webhook.sent',w.lastDeliveryStatus,w.url,w.companyId,w.id);persist('Teste de webhook registrado. Em produção a Cloud Function assina HMAC e faz POST HTTPS.');rerenderPortal();}
function openEmployeeImport(){openModal('Importar funcionários',`<form class="grid" data-form="employeeImport"><div class="page-help">CSV/Excel compatível: name,email,phone,position,department,role,status,receivesEmail,portalAccess. Use vírgula ou ponto e vírgula.</div><textarea name="rows" placeholder="name,email,department,role\nAna,ana@empresa.com,RH,participante" style="min-height:180px"></textarea><div class="confirm-actions"><button type="button" class="btn btn-soft" data-action="downloadEmployeeTemplate">Baixar modelo CSV</button><button class="btn btn-primary">Validar e importar</button></div></form>`,'large');}
function saveEmployeeImport(form){const companyId=currentUser().role==='admin_valora'?integrationScopeCompany():currentUser().companyId, lines=String(data(form).rows||'').trim().split(/\n+/);const head=lines.shift()?.split(/[;,]/).map(x=>x.trim())||[], errors=[];let created=0,updated=0,ignored=0;lines.forEach((line,i)=>{const vals=line.split(/[;,]/), row=Object.fromEntries(head.map((h,j)=>[h,vals[j]?.trim()||'']));if(!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(row.email||'')){errors.push(`Linha ${i+2}: e-mail inválido`);return;}if(['admin_valora','consultor_valora'].includes(row.role)){errors.push(`Linha ${i+2}: perfil global proibido`);return;}const existing=state.users.find(u=>u.companyId===companyId&&u.email.toLowerCase()===row.email.toLowerCase());if(existing){Object.assign(existing,{name:row.name||existing.name,phone:row.phone||existing.phone,position:row.position||existing.position,department:row.department||existing.department,role:COMPANY_ROLES.includes(row.role)?row.role:existing.role,status:row.status||existing.status,receivesEmail:row.receivesEmail!=='false',portalAccess:row.portalAccess!=='false',updatedAt:nowIso()});updated++;}else{state.users.push({id:uid('u'),companyId,name:row.name,email:row.email,phone:row.phone||'',position:row.position||'',department:row.department||'',role:COMPANY_ROLES.includes(row.role)?row.role:'participante',status:row.status||'active',receivesEmail:row.receivesEmail!=='false',portalAccess:row.portalAccess!=='false',inviteStatus:'pending_invite',createdAt:nowIso()});created++;}});logIntegration('employees.imported',errors.length?'warning':'success',`linhas=${lines.length}; criados=${created}; atualizados=${updated}; erros=${errors.length}`,companyId);persist(`Importação concluída: ${created} criados, ${updated} atualizados, ${ignored} ignorados, ${errors.length} erros.`);openModal('Resumo da importação',`<div class="kpi-grid">${kpi('Total',lines.length)}${kpi('Criados',created)}${kpi('Atualizados',updated)}${kpi('Com erro',errors.length)}</div>${errors.map(e=>`<div class="danger-box">${esc(e)}</div>`).join('')||'<div class="notice">Sem erros.</div>'}`,'large');}
function openDataExport(){openModal('Exportar dados',`<form class="grid" data-form="dataExport"><div class="form-grid"><div class="field"><label>Tipo</label><select name="type"><option>employees</option><option>surveys</option><option>responses_flat</option><option>dimensions_summary</option><option>survey_summary</option><option>company_usage</option></select></div><div class="field"><label>Formato</label><select name="format"><option>json</option><option>csv</option></select></div><div class="field"><label>Departamento</label><input name="department"></div><div class="field"><label>Status</label><input name="status"></div></div><button class="btn btn-primary">Exportar</button></form>`,'small');}
function exportData(form){const fd=data(form), companyId=currentUser().role==='admin_valora'?integrationScopeCompany():currentUser().companyId;let rows=[];if(fd.type==='employees')rows=state.users.filter(u=>u.companyId===companyId&&!['admin_valora','consultor_valora'].includes(u.role)).map(({password,...u})=>u);else if(fd.type==='surveys')rows=scopedSurveys(companyId);else if(fd.type==='responses_flat')rows=scopedResponses(companyId).flatMap(r=>Object.entries(r.byDimension||{Geral:{}}).map(([dimensionName,d])=>({companyId,companyName:companyName(companyId),surveyId:r.surveyId,surveyTitle:surveyTitle(r.surveyId),responseId:r.id,participantEmail:r.anonymous?'anonimizado':r.participant?.email,department:r.department||r.participant?.department||'',createdAt:r.createdAt,normalized5:d.normalized5||r.normalized5,percentage:d.percentage||r.percentage,level:r.level?.label||'',dimensionName,questionText:'',answer:'',score:d.rawScore||r.rawScore})));else rows=scopedResponses(companyId).map(r=>({id:r.id,surveyId:r.surveyId,normalized5:r.normalized5,percentage:r.percentage,createdAt:r.createdAt}));if(fd.department)rows=rows.filter(r=>String(r.department||'')===fd.department);if(fd.status)rows=rows.filter(r=>String(r.status||'')===fd.status);logIntegration('data.exported','success',`${fd.type}.${fd.format} ${rows.length} linhas`,companyId);const name=`${fd.type}-${new Date().toISOString().slice(0,10)}.${fd.format}`;downloadText(name,fd.format==='csv'?toCsv(rows):JSON.stringify(rows,null,2),fd.format==='csv'?'text/csv':'application/json');closeModal();}
function toCsv(rows){const keys=[...new Set(rows.flatMap(r=>Object.keys(r)))];return [keys.join(','),...rows.map(r=>keys.map(k=>`"${String(r[k]??'').replace(/"/g,'""')}"`).join(','))].join('\n');}

function currentUser(){return repository.currentUser({state});}
function currentCompany(){const u=currentUser();return u?.companyId?companyById(u.companyId):null;}
function companyById(id){return loadCompanies().find(c=>c.id===id)||null;}
function companyName(id){return companyById(id)?.name||'Valora Group';}
function planByIdFrom(plans,id){return (plans||[]).find(p=>p.id===id)||null;}
function defaultPlanFrom(plans){return (plans||[]).find(p=>p.default)||(plans||[])[0]||null;}
function planById(id){return planByIdFrom(state?.plans,id);}
function defaultPlan(){return defaultPlanFrom(state?.plans);}
function formById(id){return loadForms().find(f=>f.id===id)||null;}
function surveyTitle(id){return loadSurveys().find(s=>s.id===id)?.title||'Pesquisa removida';}
function canManageCompany(id){const u=currentUser();return !!u&&(isGlobalAdmin(u)||isValoraConsultant(u)||u.companyId===id);}
function scopedSurveys(companyId){const rows=loadSurveys();if(isGlobalAdmin(currentUser()))return rows.sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt));return rows.filter(s=>s.companyId===companyId).sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt));}
function scopedResponses(companyId){const rows=loadResponses();if(isGlobalAdmin(currentUser()))return rows.sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt));return rows.filter(r=>r.companyId===companyId).sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt));}
function scopedForms(companyId){return loadForms().filter(f=>f.global||f.companyId===companyId).sort((a,b)=>Number(b.global)-Number(a.global)||a.name.localeCompare(b.name));}
function responsesForUser(u){if(!u)return[];return loadResponses().filter(r=>responseParticipantEmail(r).toLowerCase()===u.email.toLowerCase()).sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt));}
function activeSurveysForParticipant(){const u=currentUser();return loadSurveys().filter(s=>surveyIsActive(s)&&(!u?.companyId||s.companyId===u.companyId)).sort((a,b)=>new Date(a.expiresAt)-new Date(b.expiresAt));}
function moduleEnabled(id){const c=currentCompany();window.ValoraState=state;return window.ValoraModules?.canUseModule(currentUser(),c,id)??state.modules.find(m=>m.id===id)?.enabled!==false;}
function isExpired(s){return !s?.expiresAt||new Date(s.expiresAt)<new Date();}
function normalizeDateLike(value){
  if(!value)return null;
  if(value instanceof Date)return value;
  if(typeof value==='string'){const d=new Date(value);return Number.isNaN(d.getTime())?null:d;}
  if(typeof value.toDate==='function')return value.toDate();
  if(value.seconds)return new Date(value.seconds*1000);
  return null;
}
function isFreeOfficialSurvey(survey){return survey?.isFree===true||survey?.planId==='free'||/valora insight|diagn[oó]stico gratuito|pesquisa gratuita/i.test(String(survey?.title||''));}
function isSurveyExpired(survey,options={}){
  const isFreeOfficial=isFreeOfficialSurvey(survey);
  const expiresAt=normalizeDateLike(survey?.expiresAt||survey?.endAt||survey?.validUntil);
  if(isFreeOfficial&&!expiresAt)return false;
  if(isFreeOfficial&&expiresAt&&expiresAt.getTime()<Date.now())return options.strict===true;
  return !!(expiresAt&&expiresAt.getTime()<Date.now());
}
function surveyIsActive(s){const startsAt=normalizeDateLike(s?.startsAt);return ['active','published','open'].includes(String(s?.status||'').toLowerCase())&&!isSurveyExpired(s)&&(!startsAt||startsAt<=new Date());}
function daysUntil(v){const d=Math.ceil((new Date(v)-new Date())/86400000);return d<0?`${Math.abs(d)} dia(s) expirada`:d===0?'Expira hoje':`${d} dia(s) restantes`;}
function featuredSurvey(){const configured=loadSurveys().find(s=>s.id===state.settings.featuredSurveyId&&surveyIsActive(s));return configured||loadSurveys().find(s=>surveyIsActive(s))||null;}
function responsesThisMonth(companyId=''){const now=new Date();return loadResponses().filter(r=>(!companyId||r.companyId===companyId)&&new Date(r.createdAt).getMonth()===now.getMonth()&&new Date(r.createdAt).getFullYear()===now.getFullYear()).length;}
function aggregateDimensions(responses){const bag={};responses.forEach(r=>Object.entries(r.byDimension||{}).forEach(([name,v])=>{(bag[name]||(bag[name]=[])).push(Number(v.normalized5||0));}));return Object.fromEntries(Object.entries(bag).map(([k,v])=>[k,avg(v)]));}
function recentLogs(limit=6){return `<div class="activity-list">${state.logs.slice(-limit).reverse().map(l=>`<div class="activity-item"><b>${esc(l.action)}</b><span>${esc(l.detail||l.entityType||'')}</span><small>${brDate(l.createdAt)}</small></div>`).join('')||'<div class="empty">Sem atividade recente.</div>'}</div>`;}
function usageBars(companyId){const c=companyById(companyId),p=planById(c?.planId);if(!p)return '<div class="empty">Plano não localizado.</div>';const active=scopedSurveys(companyId).filter(s=>surveyIsActive(s)).length,month=responsesThisMonth(companyId),managers=state.users.filter(u=>u.companyId===companyId&&['empresa_admin','gestor_pesquisa'].includes(u.role)&&u.status==='active').length;const row=(label,used,max)=>`<div class="usage-row"><div><b>${esc(label)}</b><span>${used} / ${max<0?'Ilimitado':max}</span></div><div class="bar"><span style="width:${max<0?Math.min(100,used*8):clamp(used/Math.max(1,max)*100,0,100)}%"></span></div></div>`;return row('Pesquisas ativas',active,p.maxActiveSurveys)+row('Respostas no mês',month,p.maxResponsesMonth)+row('Gestores',managers,p.maxManagers);}
function scoringLabel(m){return m==='sum'?'Soma das notas':m==='average'?'Média simples':'Média ponderada';}
function formDimensionName(f,id){return f.dimensions.find(d=>d.id===id)?.name||'Geral';}
function statusLabel(v){return STATUS_LABELS[v]||v||'—';}
function fillTemplate(text,vars){return String(text||'').replace(/{{\s*([^}]+)\s*}}/g,(_,k)=>vars[String(k).trim()]??'');}
function parseFaq(text){return DataNorm.parseFaq?DataNorm.parseFaq(text):[];}
function defaultFaq(){return DataNorm.defaultFaq?DataNorm.defaultFaq():[{id:'faq_1',question:'O que é o Valora Insight™?',answer:'É um diagnóstico de maturidade organizacional.'}];}
function defaultBands(){return [{id:'attention',label:'Atenção',from:0,to:2.2,color:'#b5262b',description:'Fragilidades críticas que exigem prioridade.',recommendation:'Estabilidade operacional e governança básica.'},{id:'evolution',label:'Evolução',from:2.21,to:3.4,color:'#c47b00',description:'Fundamentos presentes com oportunidades de fortalecimento.',recommendation:'Consistência de processos e desenvolvimento de liderança.'},{id:'consistency',label:'Consistência',from:3.41,to:4.4,color:'#08764e',description:'Sistemas estruturados, operação segura e boa previsibilidade.',recommendation:'Inovação, benchmark e diferenciação competitiva.'},{id:'excellence',label:'Excelência',from:4.41,to:5,color:'#0f5265',description:'Maturidade elevada e geração sustentável de valor.',recommendation:'Manutenção, compartilhamento de práticas e liderança de mercado.'}];}
function createInvoiceForCompany(c){const p=planById(c.planId);if(p&&p.price>0)state.invoices.push({id:uid('inv'),companyId:c.id,amount:p.price,dueAt:datePlus(30),status:'open',createdAt:nowIso()});}
function audit(action,entityType='',entityId='',detail=''){if(isSavingAudit)return;isSavingAudit=true;setTimeout(()=>{isSavingAudit=false;},0);const u=currentUser();if(window.ValoraLogs)window.ValoraLogs.logAudit({category:mapLogCategory(entityType),action,message:detail||action,user:u,entity:entityType,entityId,metadata:{detail}});else state.logs.push({id:uid('log'),createdAt:nowIso(),userName:u?.name||'Sistema',userRole:u?.role||'',action,entityType,entityId,detail});if(state.logs.length>3000)state.logs=state.logs.slice(-3000);try{if(u)window.ValoraRepository?.saveAuditLog?.({action,entityType,entityId,detail});}catch(_){}finally{isSavingAudit=false;} }
function mapLogCategory(v){const x=String(v||'system').toLowerCase();return ({'usuário':'user','usuario':'user','empresa':'company','pesquisa':'survey','formulário':'form','formulario':'form','resposta':'response','relatório':'report','relatorio':'report','plano de ação':'action_plan','notificação':'notification','cobrança':'billing','e-mail':'notification','backup':'system','sistema':'system','log':'system'})[x]||x.replace(/[^a-z_]/g,'_')||'system';}
function logSecurityEvent(event){return window.ValoraLogs?.logSecurity({...event,user:currentUser?.(),route:event.route||currentRoute});}
function save(){try{saveChanges();}catch(err){if(isHandlingError)return;isHandlingError=true;console.error(err);toast('O navegador não conseguiu salvar os dados.','error');setTimeout(()=>{isHandlingError=false;},1000);}}
function loadStore(){return repository.loadStore({storeKey:STORE_KEY,seedStore,normalizeState});}
function initializeState(){if(state)return state;state=loadStore();if(!state||typeof state!=='object')throw new Error('Estado inicial inválido.');window.ValoraState=state;return state;}

// Fachada de acesso a dados. Hoje o modo local mantém o comportamento do MVP;
// em produção, estes pontos passam a delegar para Firebase Auth/Firestore/Functions.
async function loginUser(email,password){try{return await repository.login({state,email,password,nowIso});}catch(err){throw Object.assign(new Error('E-mail ou senha inválidos. Verifique seus dados ou redefina sua senha.'),{code:err?.code});}}
async function logoutUser(){closeMobileMenu();const u=currentUser();audit('Logout realizado','usuário',u?.id||u?.uid||'',u?.email||'');await repository.logout({state});state.session=null;if(repository.mode!=='firebase')save();toast('Sessão encerrada.','success');goHome();}
function loadCompanies(){const rows=repository.loadCompanies({state});return (window.ValoraDataNormalization?.isProductionEnvironment?.()?rows.filter(c=>!isBlockedInProduction(c)&&!window.ValoraDataNormalization?.isDeletedRecord?.(c)):rows);}
function loadUsers(){return repository.loadUsers({state});}
function loadForms(){const rows=repository.loadForms({state});return (window.ValoraDataNormalization?.isProductionEnvironment?.()?rows.filter(f=>!isBlockedInProduction(f)&&!window.ValoraDataNormalization?.isDeletedRecord?.(f)):rows);}
function loadSurveys(){const rows=repository.loadSurveys({state});if(!window.ValoraDataNormalization?.isProductionEnvironment?.())return rows;return rows.filter(s=>{const form=(state.forms||[]).find(f=>String(f.id)===String(s.formId));const company=(state.companies||[]).find(c=>String(c.id)===String(s.companyId||s.organizationId));return !isBlockedInProduction(s)&&!isBlockedInProduction(form)&&!isBlockedInProduction(company)&&!window.ValoraDataNormalization?.isDeletedRecord?.(s)&&s.revoked!==true&&s.removed!==true;});}
function loadResponses(){return repository.loadResponses({state});}
function saveChanges(){if(window.ValoraNotifications)window.ValoraNotifications.generateNotifications(state);return repository.saveChanges({storeKey:STORE_KEY,state});}

