// White label, assinatura e controles comerciais — evolução SaaS multiempresa.
function normalizeSlug(value){return String(value||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().replace(/[^a-z0-9-]+/g,'-').replace(/^-+|-+$/g,'').replace(/-{2,}/g,'-').slice(0,60);}
function validateOrganizationSlug(value,currentId=''){const v=normalizeSlug(value);if(!v)return {ok:false,message:'Slug obrigatório para white label público.'};if(RESERVED_ORG_SLUG_SET.has(v))return {ok:false,message:'Slug reservado.'};const used=state.companies.find(c=>c.id!==currentId&&c.slug===v);return used?{ok:false,message:'Slug já está em uso.'}:{ok:true,value:v};}
function findOrganizationBySlug(slug){return state.companies.find(c=>c.slug===normalizeSlug(slug))||null;}
function getCompanyTheme(company){const b=company?.brand||{};return {...VALORA_THEME,...b,logoUrl:b.logoUrl||LOGO_FULL};}
function applyCompanyTheme(company){if(!company||getRoleDefinition(currentUser()?.role).scope==='valora')return resetCompanyTheme();const t=getCompanyTheme(company);document.documentElement.style.setProperty('--brand-primary',t.primaryColor);document.documentElement.style.setProperty('--brand-secondary',t.secondaryColor);document.documentElement.style.setProperty('--brand-accent',t.accentColor);document.documentElement.style.setProperty('--brand-bg',t.backgroundColor);document.documentElement.style.setProperty('--brand-text',t.textColor);}
function resetCompanyTheme(){['--brand-primary','--brand-secondary','--brand-accent','--brand-bg','--brand-text'].forEach(k=>document.documentElement.style.removeProperty(k));}
function activeBrandLogo(){const c=currentCompany();return c?.brand?.logoUrl&&getRoleDefinition(currentUser()?.role).scope==='empresa'?c.brand.logoUrl:LOGO_SYMBOL;}
function activeBrandName(){const c=currentCompany();return c&&getRoleDefinition(currentUser()?.role).scope==='empresa'?(c.publicName||c.name):'Valora Group™';}
function subscriptionLabel(v){return ({trial:'Trial',active:'Ativa',past_due:'Pagamento pendente',overdue:'Pagamento vencido',suspended:'Suspensa',cancelled:'Cancelada',inactive:'Inativa',monthly:'Mensal',quarterly:'Trimestral',semiannual:'Semestral',annual:'Anual',manual:'Manual',draft:'Rascunho',open:'Em aberto',pending:'Pendente',paid:'Pago',refunded:'Estornada',failed:'Falhou'})[v]||v||'—';}
function getTrialDaysLeft(company){const end=company?.subscription?.trialEndsAt;if(!end)return 0;return Math.max(0,Math.ceil((toDateValue(end)-Date.now())/86400000));}
function isTrialExpired(company){return (company?.subscription?.status||company?.status)==='trial'&&!!company?.subscription?.trialEndsAt&&toDateValue(company.subscription.trialEndsAt)<new Date();}
function getTrialStatus(company){const days=getTrialDaysLeft(company);return {expired:isTrialExpired(company),daysLeft:days,message:isTrialExpired(company)?'Seu período de teste expirou. Fale com a Valora para ativar seu plano.':`Seu período de teste termina em ${days} dia(s).`};}
function getSubscriptionStatus(company){const s=company?.subscription||{}, status=isTrialExpired(company)?'overdue':(s.status||company?.status||'active');let tone=status==='active'?'success':['suspended','cancelled','inactive'].includes(status)?'danger':'warn',detail='Uso normal';if(status==='trial'&&s.trialEndsAt)detail=getTrialStatus(company).message;if(['past_due','overdue'].includes(status))detail='Leitura permitida; novas ações podem ser bloqueadas.';if(['suspended','cancelled','inactive'].includes(status))detail='Uso operacional bloqueado.';return {status,billingStatus:s.billingStatus||'open',tone,detail};}
function canUseCommercialFeature(company,feature){const st=getSubscriptionStatus(company).status;if(st==='active')return true;if(st==='trial')return !isTrialExpired(company);if(['past_due','overdue'].includes(st))return ['portal','view','billing'].includes(feature);return ['billing','contact'].includes(feature)&&['suspended'].includes(st);}
function canCreateSurveyByBilling(company){return canUseCommercialFeature(company,'survey')&&!getLimitStatus(company.id).items.find(i=>i.key==='maxActiveSurveys'&&i.status==='excedido');}
function canSendInvitesByBilling(company){return canUseCommercialFeature(company,'invite')&&!getLimitStatus(company.id).items.find(i=>i.key==='maxEmailsMonth'&&i.status==='excedido');}
function canGenerateReportsByBilling(company){return canUseCommercialFeature(company,'report');}
function canAccessPortalByBilling(company){return canUseCommercialFeature(company,'portal')||['active','trial','past_due','overdue','suspended'].includes(getSubscriptionStatus(company).status);}
function getEffectiveCompanyLimits(company,plan=planById(company?.planId)){const o=company?.limitsOverride||{};return ['maxActiveSurveys','maxResponsesMonth','maxManagers','maxEmployees','maxEmailsMonth'].reduce((a,k)=>{a[k]=Number(o[k]??plan?.[k]??(k==='maxEmailsMonth'?plan?.maxResponsesMonth:0));return a;},{});}
function getCompanyUsage(companyId){return {maxActiveSurveys:scopedSurveys(companyId).filter(s=>surveyIsActive(s)).length,maxResponsesMonth:responsesThisMonth(companyId),maxManagers:state.users.filter(u=>u.companyId===companyId&&['empresa_admin','gestor_pesquisa'].includes(u.role)&&u.status==='active').length,maxEmployees:state.users.filter(u=>u.companyId===companyId&&COMPANY_ROLES.includes(u.role)&&u.status==='active').length,maxEmailsMonth:state.invitations.filter(i=>i.companyId===companyId&&new Date(i.createdAt||i.sentAt||0).getMonth()===new Date().getMonth()).length};}
function getLimitStatus(companyId){const c=companyById(companyId),limits=getEffectiveCompanyLimits(c),usage=getCompanyUsage(companyId),labels={maxActiveSurveys:'Pesquisas ativas',maxResponsesMonth:'Respostas/mês',maxManagers:'Gestores',maxEmployees:'Funcionários',maxEmailsMonth:'E-mails/mês'};const items=Object.keys(limits).map(k=>{const limit=limits[k],used=usage[k]||0,pct=limit<0?0:used/Math.max(1,limit)*100,status=limit>=0&&used>=limit?'excedido':pct>=80?'atenção':'ok';return {key:k,label:labels[k],used,limit,percentage:clamp(pct,0,100),status};});return {items,warning:items.some(i=>i.status==='atenção'),exceeded:items.some(i=>i.status==='excedido')};}
function renderLimitStatus(limits){return `<div class="metric-list">${limits.items.map(i=>`<div class="metric-row ${i.status}"><div><b>${esc(i.label)}</b><span>${i.used} / ${i.limit<0?'Ilimitado':i.limit} • ${i.status}</span></div><div class="bar"><span style="width:${i.limit<0?10:i.percentage}%"></span></div></div>`).join('')}</div>`;}
function planHasModule(plan,moduleId){const mods=plan?.enabledModules;return !Array.isArray(mods)||!mods.length||mods.includes(moduleId);}
function limitAvailable(companyId,key){const item=getLimitStatus(companyId).items.find(i=>i.key===key);return !item||item.limit<0||item.used<item.limit;}
function canCreateSurvey(companyId){const c=companyById(companyId);return canCreateSurveyByBilling(c)&&limitAvailable(companyId,'maxActiveSurveys')&&planHasModule(planById(c?.planId),'pesquisas');}
function canCollectResponse(companyId){const c=companyById(companyId);return canUseCommercialFeature(c,'survey')&&limitAvailable(companyId,'maxResponsesMonth')&&planHasModule(planById(c?.planId),'respostas');}
function canAddManager(companyId){const c=companyById(companyId);return canUseCommercialFeature(c,'portal')&&limitAvailable(companyId,'maxManagers');}
function canUseReports(companyId){const c=companyById(companyId),p=planById(c?.planId);return canGenerateReportsByBilling(c)&&p?.allowReports!==false&&planHasModule(p,'relatorios');}
function canUseStrategicReport(companyId){const p=planById(companyById(companyId)?.planId);return canUseReports(companyId)&&!!p?.allowStrategicReport;}
function canUseActionPlans(companyId){const p=planById(companyById(companyId)?.planId);return canUseReports(companyId)&&!!p?.allowActionPlans&&planHasModule(p,'actionPlans');}
function canUseWhiteLabelFeature(companyId){const p=planById(companyById(companyId)?.planId);return !!p?.allowWhiteLabel&&planHasModule(p,'whiteLabel');}
function canUseValoraBot(companyId){const p=planById(companyById(companyId)?.planId);return p?.allowValoraBot!==false&&planHasModule(p,'valorabot');}
function canCreateSurveyBySubscription(company){return canCreateSurveyByBilling(company);}
function canSendInvitesBySubscription(company){return canSendInvitesByBilling(company);}
function canUseReportsBySubscription(company){return canGenerateReportsByBilling(company);}
function canUseWhiteLabel(company){return !!company&&['trial','active'].includes(getSubscriptionStatus(company).status);}
function publicSurveyBrand(s){const c=companyById(s.companyId);if(!c?.brand?.useCompanyBrandOnPublicSurvey)return '';const t=getCompanyTheme(c);return `<div class="brand-preview public-brand" style="--brand-primary:${esc(t.primaryColor)};--brand-secondary:${esc(t.secondaryColor)};--brand-bg:${esc(t.backgroundColor)};--brand-text:${esc(t.textColor)}"><div><img src="${esc(t.logoUrl)}" alt="${esc(c.publicName||c.name)}"><b>${esc(c.publicName||c.name)}</b><span>${esc(c.slogan||'Pesquisa organizacional')}</span></div>${c.brand.showPoweredByValora!==false?'<small>Powered by Valora Group</small>':''}</div>`;}
function clientsSection(){return `<div class="section-toolbar"><div><h3>Clientes e ambientes</h3><p class="muted">Plano, assinatura, white label, uso, CNPJ/CPF e dados de contato.</p></div><button class="btn btn-primary" data-action="newCompany">Cadastrar cliente</button></div><div class="card table-wrap"><table class="table"><thead><tr><th>Cliente</th><th>Slug</th><th>Plano/assinatura</th><th>Uso</th><th>Status</th><th>Ações</th></tr></thead><tbody>${state.companies.map(c=>{const p=planById(c.planId),sub=getSubscriptionStatus(c),limits=getLimitStatus(c.id);return `<tr><td><b>${esc(c.publicName||c.name)}</b><br><span class="muted">${esc(c.email||'')} • ${esc(c.legalName||c.name||'')}</span></td><td>${esc(c.slug||'—')}<br><span class="muted">${c.brand?.logoUrl?'Logo configurada':'Sem logo'}</span></td><td>${esc(p?.name||'—')}<br><span class="badge ${sub.tone}">${esc(subscriptionLabel(sub.status))}</span> <span class="muted">${money(p?.price||0)}/mês</span></td><td>${limits.items.slice(0,3).map(i=>`${esc(i.label)}: ${i.used}/${i.limit<0?'∞':i.limit}`).join('<br>')}</td><td><span class="badge ${c.status==='active'?'success':'danger'}">${esc(STATUS_LABELS[c.status]||c.status)}</span></td><td><div class="table-actions"><button class="btn btn-soft btn-mini" data-action="editCompany" data-id="${c.id}">Editar</button><button class="btn btn-secondary btn-mini" data-action="impersonateCompany" data-id="${c.id}">Abrir ambiente</button><button class="btn btn-danger btn-mini" data-action="deleteCompany" data-id="${c.id}">Excluir</button></div></td></tr>`}).join('')}</tbody></table></div>`;}
function companyPlanSection(){const c=currentCompany(),p=planById(c?.planId),sub=getSubscriptionStatus(c),limits=getLimitStatus(c?.id),mods=state.modules||[],invs=invoicesForCompany(c?.id);const price=p?.price?`${money(p.price)}/${p.priceComplement&&/mês|mes/.test(p.priceComplement)?'mês':'mês'}`:(p?.priceLabel||'Sob consulta');const nextLimit=(limits.items||[]).filter(i=>i.limit>=0).sort((a,b)=>(b.used/Math.max(1,b.limit))-(a.used/Math.max(1,a.limit)))[0];return `<div class="kpi-grid">${kpi('Plano atual',p?.name||'—',price)}${kpi('Valor mensal',p?.price?money(p.price)+'/mês':(p?.priceLabel||'Sob consulta'),p?.setupFeeLabel||p?.annualPriceLabel||'Condição comercial')}${kpi('Assinatura',subscriptionLabel(sub.status),sub.detail,sub.tone)}${kpi('Próximo limite',nextLimit?`${nextLimit.label}: ${nextLimit.used}/${nextLimit.limit}`:'Sem limite próximo','Acompanhe para evitar bloqueios')}</div><div class="grid grid-2"><div class="card plan-card"><span class="badge">Plano contratado</span><h3>${esc(p?.name||'—')}</h3><div class="price">${esc(p?.priceLabel||money(p?.price||0))} ${p?.priceComplement?`<small>${esc(p.priceComplement)}</small>`:''}</div><p>${esc(p?.publicSubtitle||p?.description||'')}</p><div class="plan-limits"><span>Pesquisas ativas: <b>${planLimit(p?.maxActiveSurveys)}</b></span><span>Respostas/mês: <b>${planLimit(p?.maxResponsesMonth)}</b></span><span>Gestores: <b>${planLimit(p?.maxManagers)}</b></span><span>Empresas/unidades: <b>${planLimit(p?.maxCompanies)}</b></span><span>Áreas/departamentos: <b>${planLimit(p?.maxDepartments)}</b></span></div>${(p?.features||[]).map(f=>`<div class="feature">${esc(f)}</div>`).join('')}<div class="table-actions"><button class="btn btn-primary" data-action="requestUpgrade">Solicitar upgrade</button><button class="btn btn-secondary" data-action="talkValora">Falar com Valora</button><button class="btn btn-soft" data-action="downloadPlanSummary">Baixar resumo do plano</button></div></div><div class="card"><h3>Uso atual</h3>${renderLimitStatus(limits)}</div><div class="card"><h3>Recursos disponíveis</h3>${mods.map(m=>{const ok=(p?.enabledModules||[]).includes(m.id)&&m.enabled!==false;return `<div class="feature ${ok?'':'muted'}">${ok?'✓':'×'} ${esc(m.name)}</div>`}).join('')}</div><div class="card"><h3>CTA para upgrade</h3><p>${limits.exceeded?'Há limites excedidos. Solicite upgrade ou ajuste comercial.':limits.warning?'Uso acima de 80% em pelo menos um limite. Planeje upgrade.':'Uso dentro dos limites atuais.'}</p><button class="btn btn-primary" data-action="requestUpgrade">Ver upgrade</button></div><div class="card table-wrap span-2"><h3>Faturas</h3><table class="table"><thead><tr><th>Número</th><th>Valor</th><th>Vencimento</th><th>Status</th><th>Ações</th></tr></thead><tbody>${invs.map(i=>`<tr><td>${esc(i.number)}</td><td>${money(i.amount)}</td><td>${brDay(i.dueDate||i.dueAt)}</td><td>${invoiceStatusBadge(i.status)}</td><td><div class="table-actions">${i.paymentUrl?`<button class="btn btn-primary btn-mini" data-action="openLink" data-link="${esc(i.paymentUrl)}">Abrir link de pagamento</button>`:''}<button class="btn btn-soft btn-mini" data-action="downloadPlanSummary">Baixar fatura</button><button class="btn btn-secondary btn-mini" data-action="requestUpgrade">Solicitar segunda via</button></div></td></tr>`).join('')||'<tr><td colspan="5">Nenhuma fatura disponível.</td></tr>'}</tbody></table></div></div>`;}
function companySettingsSection(){const c=currentCompany(),t=getCompanyTheme(c);return `<form class="card grid white-label-form" data-form="companySettings"><h3>Dados da empresa e identidade visual</h3><div class="brand-preview" style="--brand-primary:${esc(t.primaryColor)};--brand-secondary:${esc(t.secondaryColor)};--brand-bg:${esc(t.backgroundColor)};--brand-text:${esc(t.textColor)}"><div><img src="${esc(t.logoUrl)}" alt="Preview"><b>${esc(c?.publicName||c?.name||'Empresa')}</b><span>${esc(c?.slogan||'Sua pesquisa com identidade personalizada')}</span></div><button type="button" class="btn btn-soft btn-mini" data-action="restoreValoraTheme">Restaurar padrão Valora</button></div><div class="form-grid"><div class="field"><label>Nome público</label><input name="publicName" value="${esc(c?.publicName||c?.name||'')}" required></div><div class="field"><label>Slogan</label><input name="slogan" value="${esc(c?.slogan||'')}"></div><div class="field"><label>Slug público</label><input name="slug" value="${esc(c?.slug||'')}"></div><div class="field"><label>URL da logo</label><input name="logoUrl" type="url" value="${esc(c?.brand?.logoUrl||'')}"></div>${['primaryColor','secondaryColor','accentColor','backgroundColor','textColor'].map(k=>`<div class="field"><label>${esc(k)}</label><input name="${k}" type="color" value="${esc(t[k])}"></div>`).join('')}<div class="field"><label>E-mail de contato</label><input name="contactEmail" type="email" value="${esc(c?.settings?.contactEmail||c?.email||'')}"></div><div class="field"><label>WhatsApp</label><input name="whatsapp" value="${esc(c?.settings?.whatsapp||c?.phone||'')}"></div><div class="field"><label>Contato LGPD</label><input name="lgpdContact" value="${esc(c?.settings?.lgpdContact||'')}"></div></div><div class="grid grid-2"><label class="checkline"><input name="useCompanyBrandOnPublicSurvey" type="checkbox" ${c?.brand?.useCompanyBrandOnPublicSurvey!==false?'checked':''}><span>Usar marca da empresa em pesquisas públicas</span></label><label class="checkline"><input name="useCompanyBrandOnEmails" type="checkbox" ${c?.brand?.useCompanyBrandOnEmails?'checked':''}><span>Usar marca da empresa em e-mails</span></label><label class="checkline"><input name="showPoweredByValora" type="checkbox" ${c?.brand?.showPoweredByValora!==false?'checked':''}><span>Exibir Powered by Valora</span></label></div><div class="page-help"><b>Proteção comercial:</b> plano, limites, cobrança e status de assinatura são bloqueados para Empresa Admin.</div><button class="btn btn-primary">Salvar personalização</button></form>`;}
function saveCompanySettings(form){const c=currentCompany();if(!c)return;const fd=data(form),slugCheck=validateOrganizationSlug(fd.slug||c.slug||c.name,c.id);if(!slugCheck.ok)return toast(slugCheck.message,'error');if(fd.logoUrl){try{new URL(fd.logoUrl);}catch(_){return toast('URL da logo inválida.','error');}}const colors=['primaryColor','secondaryColor','accentColor','backgroundColor','textColor'];if(colors.some(k=>!/^#[0-9a-f]{6}$/i.test(fd[k]||'')))return toast('Informe cores hexadecimais válidas.','error');c.publicName=fd.publicName;c.slogan=fd.slogan;c.slug=slugCheck.value;c.brand={...(c.brand||{}),logoUrl:fd.logoUrl||'',primaryColor:fd.primaryColor,secondaryColor:fd.secondaryColor,accentColor:fd.accentColor,backgroundColor:fd.backgroundColor,textColor:fd.textColor,useCompanyBrandOnPublicSurvey:!!fd.useCompanyBrandOnPublicSurvey,useCompanyBrandOnEmails:!!fd.useCompanyBrandOnEmails,showPoweredByValora:!!fd.showPoweredByValora};c.settings={...(c.settings||{}),contactEmail:fd.contactEmail,whatsapp:fd.whatsapp,lgpdContact:fd.lgpdContact};c.updatedAt=nowIso();audit('Identidade visual atualizada','empresa',c.id,c.publicName);persist('Personalização salva.');applyCompanyTheme(c);rerenderPortal();}

